/**
 * setBudgetLimit - Callable Cloud Function (RBAC Protected)
 * 
 * Allows FINANCE_HEAD or SUPER_ADMIN users to create or update
 * MONTHLY budget limits for Business Unit + COA combinations.
 * 
 * Features:
 * - Monthly budget limits (not annual)
 * - Weekly spending breakdown tracking
 * 
 * Security: Checks user role from Firestore (not custom claims)
 * to match the existing auth pattern in the application.
 * 
 * @throws HttpsError('permission-denied') if user is not authorized
 */

import { onCall, HttpsError, CallableRequest } from 'firebase-functions/v2/https';
import { getFirestore, FieldValue } from 'firebase-admin/firestore';
import { getApp } from 'firebase-admin/app';

const db = getFirestore(getApp(), 'tng-systems');

interface SetBudgetLimitInput {
    businessUnitId: string;
    coaId: string;
    limitAmount: number;
    fiscalYear: number;
    month: number;  // 1-12
    currency?: string;
}

interface WeeklySpent {
    week1: number;
    week2: number;
    week3: number;
    week4: number;
    week5: number;
}

interface FirestoreUser {
    role: string;
    name: string;
    email: string;
}

/**
 * Roles authorized to manage budgets
 */
const AUTHORIZED_ROLES = ['FINANCE_HEAD', 'SUPER_ADMIN'];

/**
 * Create empty weekly spent object
 */
function createEmptyWeeklySpent(): WeeklySpent {
    return {
        week1: 0,
        week2: 0,
        week3: 0,
        week4: 0,
        week5: 0,
    };
}

export const setBudgetLimit = onCall(async (request: CallableRequest<SetBudgetLimitInput>) => {
    console.log('[setBudgetLimit] Called with data:', JSON.stringify(request.data));

    // 1. Validate authentication
    if (!request.auth) {
        throw new HttpsError('unauthenticated', 'User must be authenticated');
    }

    const uid = request.auth.uid;

    // 2. Fetch user role from Firestore (matches existing app pattern)
    const userDoc = await db.collection('users').doc(uid).get();

    if (!userDoc.exists) {
        throw new HttpsError('not-found', 'User profile not found');
    }

    const userData = userDoc.data() as FirestoreUser;
    const userRole = userData.role;

    // 3. RBAC Check - Only FINANCE_HEAD or SUPER_ADMIN can set budget limits
    if (!AUTHORIZED_ROLES.includes(userRole)) {
        throw new HttpsError(
            'permission-denied',
            `Only ${AUTHORIZED_ROLES.join(' or ')} can set budget limits. Your role: ${userRole}`
        );
    }

    // 4. Validate input
    const data = request.data as SetBudgetLimitInput;
    const { businessUnitId, coaId, limitAmount, fiscalYear, month, currency } = data;

    if (!businessUnitId || typeof businessUnitId !== 'string') {
        throw new HttpsError('invalid-argument', 'businessUnitId is required');
    }
    if (!coaId || typeof coaId !== 'string') {
        throw new HttpsError('invalid-argument', 'coaId is required');
    }
    if (limitAmount === undefined || typeof limitAmount !== 'number') {
        throw new HttpsError('invalid-argument', 'limitAmount is required and must be a number');
    }
    if (limitAmount < 0) {
        throw new HttpsError('invalid-argument', 'limitAmount must be zero or positive');
    }
    if (!fiscalYear || typeof fiscalYear !== 'number' || fiscalYear < 2000 || fiscalYear > 2100) {
        throw new HttpsError('invalid-argument', 'fiscalYear must be a valid year (2000-2100)');
    }
    if (!month || typeof month !== 'number' || month < 1 || month > 12) {
        throw new HttpsError('invalid-argument', 'month must be between 1 and 12');
    }

    // 5. Build composite document ID (includes month)
    const monthStr = month.toString().padStart(2, '0');
    const budgetId = `${businessUnitId}_${coaId}_${fiscalYear}_${monthStr}`;
    const budgetRef = db.collection('budgets').doc(budgetId);

    try {
        // 6. Check if budget already exists
        const existingDoc = await budgetRef.get();
        const isUpdate = existingDoc.exists;

        if (isUpdate) {
            // Update existing budget - preserve currentSpent and weeklySpent
            const existingData = existingDoc.data()!;

            // Validate: new limit should not be less than current spent
            if (limitAmount < existingData.currentSpent) {
                throw new HttpsError(
                    'failed-precondition',
                    `Cannot set limit (${limitAmount}) below current spent amount (${existingData.currentSpent})`
                );
            }

            await budgetRef.update({
                totalLimit: limitAmount,
                currency: currency || existingData.currency || 'PHP',
                updatedAt: FieldValue.serverTimestamp(),
                updatedBy: uid,
            });
            console.log(`[setBudgetLimit] Updated budget at path: ${budgetRef.path}`);
        } else {
            // Create new monthly budget with weekly breakdown
            await budgetRef.set({
                businessUnitId,
                coaId,
                fiscalYear,
                month,
                totalLimit: limitAmount,
                currentSpent: 0,
                weeklySpent: createEmptyWeeklySpent(),
                currency: currency || 'PHP',
                createdAt: FieldValue.serverTimestamp(),
                createdBy: uid,
                updatedAt: FieldValue.serverTimestamp(),
                updatedBy: uid,
            });
            console.log(`[setBudgetLimit] Created budget at path: ${budgetRef.path}`);
        }

        console.log(`[setBudgetLimit] Success. BudgetID: ${budgetId}`);

        return {
            success: true,
            budgetId,
            action: isUpdate ? 'updated' : 'created',
            message: `Monthly budget ${isUpdate ? 'updated' : 'created'} successfully for ${monthStr}/${fiscalYear}`,
            // @ts-ignore
            path: budgetRef.path,
            // @ts-ignore
            writeTime: new Date().toISOString()
        };

    } catch (error) {
        // Re-throw HttpsError as-is
        if (error instanceof HttpsError) {
            throw error;
        }
        // Wrap other errors
        console.error('setBudgetLimit error:', error);
        throw new HttpsError('internal', 'Failed to set budget limit');
    }
});

import { initializeApp } from 'firebase/app';
import { getFirestore, doc, getDoc } from 'firebase/firestore';

// Firebase configuration (you'll need to add your config)
const firebaseConfig = {
    // Add your config from src/config/firebase.ts
};

const app = initializeApp(firebaseConfig);
const db = getFirestore(app);

async function checkPermissions() {
    try {
        console.log('Fetching permissions from Firebase...\n');

        const docRef = doc(db, 'config', 'permissions');
        const docSnap = await getDoc(docRef);

        if (docSnap.exists()) {
            const data = docSnap.data();

            console.log('✅ Permissions document found!\n');
            console.log('='.repeat(80));
            console.log('ROLES TO PERMISSIONS MAPPING');
            console.log('='.repeat(80));

            if (data.permissions) {
                Object.entries(data.permissions).forEach(([role, perms]) => {
                    console.log(`\n${role}:`);
                    console.log(`  Total permissions: ${(perms as any[]).length}`);
                    console.log(`  Permissions:`);
                    (perms as any[]).forEach(p => {
                        console.log(`    - ${p}`);
                    });
                });
            } else {
                console.log('❌ No permissions field found in document');
            }

            console.log('\n' + '='.repeat(80));
            console.log('ROLES');
            console.log('='.repeat(80));

            if (data.roles && Array.isArray(data.roles)) {
                console.log(`\nTotal roles: ${data.roles.length}`);
                data.roles.forEach((role: string) => {
                    console.log(`  - ${role}`);
                });
            } else {
                console.log('❌ No roles field found in document');
            }

        } else {
            console.log('❌ No permissions document found in Firebase');
            console.log('The system will use default permissions from config/permissions.ts');
        }
    } catch (error) {
        console.error('Error checking permissions:', error);
    }
}

checkPermissions();

/**
 * Detect Duplicate Users Script
 * Scans Firestore 'users' collection to find:
 * 1. Users with the same email appearing multiple times
 * 2. Users where document ID doesn't match expected Firebase Auth UID pattern
 */

import { initializeApp, cert } from 'firebase-admin/app';
import { getFirestore } from 'firebase-admin/firestore';
import * as path from 'path';
import { fileURLToPath } from 'url';

// ES Module compatibility
const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

// Initialize Firebase Admin
const serviceAccountPath = path.join(__dirname, '../serviceAccountKey.json');

try {
    initializeApp({
        credential: cert(serviceAccountPath)
    });
} catch (e) {
    // App might already be initialized
}

const db = getFirestore();

interface UserDoc {
    id: string;
    email?: string;
    name?: string;
    role?: string;
    status?: string;
    businessId?: string;
    businessUnitIds?: string[];
    createdAt?: any;
}

async function detectDuplicates() {
    console.log('🔍 Scanning for duplicate users...\n');
    console.log('='.repeat(80));

    try {
        const usersSnapshot = await db.collection('users').get();
        const users: UserDoc[] = [];

        usersSnapshot.forEach(doc => {
            users.push({
                id: doc.id,
                ...doc.data()
            } as UserDoc);
        });

        console.log(`📊 Total users found: ${users.length}\n`);

        // Group by email
        const emailMap = new Map<string, UserDoc[]>();

        users.forEach(user => {
            const email = user.email?.toLowerCase() || 'NO_EMAIL';
            if (!emailMap.has(email)) {
                emailMap.set(email, []);
            }
            emailMap.get(email)!.push(user);
        });

        // Find duplicates
        let duplicateCount = 0;
        const duplicates: { email: string; users: UserDoc[] }[] = [];

        emailMap.forEach((userList, email) => {
            if (userList.length > 1) {
                duplicateCount++;
                duplicates.push({ email, users: userList });
            }
        });

        if (duplicates.length === 0) {
            console.log('✅ No duplicate users found!\n');
        } else {
            console.log(`⚠️  Found ${duplicates.length} email(s) with duplicates:\n`);
            console.log('='.repeat(80));

            duplicates.forEach(({ email, users: dupeUsers }, index) => {
                console.log(`\n📧 [${index + 1}] Email: ${email}`);
                console.log(`   Found ${dupeUsers.length} documents:\n`);

                dupeUsers.forEach((user, i) => {
                    console.log(`   Document ${i + 1}:`);
                    console.log(`   ├─ ID:       ${user.id}`);
                    console.log(`   ├─ Name:     ${user.name || 'N/A'}`);
                    console.log(`   ├─ Role:     ${user.role || 'N/A'}`);
                    console.log(`   ├─ Status:   ${user.status || 'N/A'}`);
                    console.log(`   ├─ BusinessId: ${user.businessId || 'N/A'}`);
                    console.log(`   └─ BU IDs:   ${user.businessUnitIds?.join(', ') || 'N/A'}`);
                    console.log('');
                });

                // Identify which one is likely the "correct" one
                // Usually the one with ACTIVE status or most recent
                const activeUsers = dupeUsers.filter(u => u.status === 'ACTIVE');
                if (activeUsers.length === 1) {
                    console.log(`   💡 Suggestion: Keep document ID "${activeUsers[0].id}" (ACTIVE status)`);
                    console.log(`   🗑️  Consider deleting other document(s)`);
                } else if (activeUsers.length > 1) {
                    console.log(`   ⚠️  Multiple ACTIVE documents! Manual review required.`);
                } else {
                    console.log(`   ⚠️  No ACTIVE documents found. Manual review required.`);
                }
                console.log('-'.repeat(80));
            });
        }

        // Summary
        console.log('\n' + '='.repeat(80));
        console.log('📋 SUMMARY');
        console.log('='.repeat(80));
        console.log(`   Total Users:     ${users.length}`);
        console.log(`   Unique Emails:   ${emailMap.size}`);
        console.log(`   Duplicate Sets:  ${duplicates.length}`);
        console.log(`   Documents to review: ${duplicates.reduce((sum, d) => sum + d.users.length - 1, 0)}`);
        console.log('='.repeat(80));

        // Return data for potential cleanup
        return {
            totalUsers: users.length,
            duplicates,
            allUsers: users
        };

    } catch (error) {
        console.error('❌ Error scanning users:', error);
        throw error;
    }
}

// Run the detection
detectDuplicates()
    .then(() => {
        console.log('\n✅ Scan complete.');
        process.exit(0);
    })
    .catch((err) => {
        console.error('Script failed:', err);
        process.exit(1);
    });

import React, { createContext, useContext, useState } from 'react';
import type { ReactNode } from 'react';

interface BusinessUnitContextType {
    selectedBusinessUnit: string;
    setSelectedBusinessUnit: (id: string) => void;
}

const BusinessUnitContext = createContext<BusinessUnitContextType | undefined>(undefined);

export const BusinessUnitProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
    const [selectedBusinessUnit, setSelectedBusinessUnit] = useState<string>('all');
    return (
        <BusinessUnitContext.Provider value={{ selectedBusinessUnit, setSelectedBusinessUnit }}>
            {children}
        </BusinessUnitContext.Provider>
    );
};

export const useBusinessUnit = () => {
    const context = useContext(BusinessUnitContext);
    if (context === undefined) {
        throw new Error('useBusinessUnit must be used within a BusinessUnitProvider');
    }
    return context;
};

import React, { createContext, useContext, useState, useEffect, useRef, useCallback } from 'react';
import { doc, getDoc, setDoc, onSnapshot, deleteField } from 'firebase/firestore';
import { db } from '../config/firebase';
import { ROLES_TO_PERMISSIONS } from '../config/permissions';
import type { Permission } from '../config/permissions';
import { SystemRole, DEFAULT_BUSINESS_ROLES } from '../features/procurement/types';

// Default roles: System roles + default business roles
const DEFAULT_ROLES: string[] = [
    ...Object.values(SystemRole),
    ...DEFAULT_BUSINESS_ROLES
];

interface PermissionsContextType {
    permissions: Record<string, Permission[]>;
    roles: string[]; // Changed to string[] for dynamic roles
    updatePermissions: (newPermissions: Record<string, Permission[]>) => Promise<void>;
    updateRoles: (newRoles: string[]) => Promise<void>;
    /**
     * Atomically saves both permissions and roles in a single Firestore write.
     * This prevents race conditions where two separate writes (updatePermissions + updateRoles)
     * could cause the roles array to be overwritten by a stale copy from another admin's session.
     *
     * IMPORTANT: This reads the latest server state first and merges custom roles/permissions
     * that may have been added by other admins, so nothing gets silently dropped.
     */
    savePermissionsAndRoles: (
        newPermissions: Record<string, Permission[]>,
        newRoles: string[],
        deletedRoles?: string[]
    ) => Promise<void>;
    loading: boolean;
    error: string | null;
}

const PermissionsContext = createContext<PermissionsContextType | undefined>(undefined);

export const usePermissionsContext = () => {
    const context = useContext(PermissionsContext);
    if (!context) {
        throw new Error('usePermissionsContext must be used within a PermissionsProvider');
    }
    return context;
};

export const PermissionsProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const [permissions, setPermissions] = useState<Record<string, Permission[]>>(ROLES_TO_PERMISSIONS);
    const [roles, setRoles] = useState<string[]>(DEFAULT_ROLES);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    // Track whether the document has been initialized from Firestore at least once.
    // This prevents the fallback "initialize if missing" block from firing on transient
    // snapshot states (e.g. cache miss before server round-trip).
    const hasInitialized = useRef(false);

    useEffect(() => {
        // Subscribe to the permissions document for real-time updates
        const unsub = onSnapshot(doc(db, 'config', 'permissions'), (docSnap) => {
            try {
                if (docSnap.exists()) {
                    const data = docSnap.data();
                    hasInitialized.current = true;

                    if (data.permissions) {
                        const savedPermissions: Record<string, Permission[]> = {};
                        for (const [role, perms] of Object.entries(data.permissions)) {
                            savedPermissions[role] = perms as Permission[];
                        }
                        setPermissions(savedPermissions);
                    }
                    if (data.roles && Array.isArray(data.roles)) {
                        // Merge DEFAULT_ROLES to guarantee system roles are always present,
                        // but preserve every custom role from Firestore as-is.
                        const uniqueRoles = Array.from(new Set([...DEFAULT_ROLES, ...data.roles]));
                        setRoles(uniqueRoles);
                    }
                } else if (!hasInitialized.current && !docSnap.metadata.fromCache) {
                    // Only initialize the document if it truly doesn't exist and we've
                    // never seen it before. This prevents accidental overwrites if the
                    // snapshot temporarily reports !exists() due to cache/network issues.
                    hasInitialized.current = true;
                    setDoc(doc(db, 'config', 'permissions'), {
                        permissions: ROLES_TO_PERMISSIONS,
                        roles: DEFAULT_ROLES
                    }).catch(console.error);
                }
                setLoading(false);
            } catch (err: any) {
                console.error('Error processing permissions update:', err);
                setError(err.message);
                setLoading(false);
            }
        }, (err: Error) => {
            console.error('Error subscribing to permissions:', err);
            setError(err.message);
            setLoading(false);
        });

        return () => unsub();
    }, []);

    // ------------------------------------------------------------------
    // Legacy single-field updaters (kept for backward compatibility)
    // Prefer savePermissionsAndRoles() for PermissionsMatrix saves.
    // ------------------------------------------------------------------

    const updatePermissions = useCallback(async (newPermissions: Record<string, Permission[]>) => {
        const previousPermissions = permissions;
        try {
            setPermissions(newPermissions);
            const docRef = doc(db, 'config', 'permissions');
            await setDoc(docRef, { permissions: newPermissions }, { merge: true });
        } catch (err: any) {
            console.error('Error saving permissions:', err);
            setPermissions(previousPermissions);
            throw err;
        }
    }, [permissions]);

    const updateRoles = useCallback(async (newRoles: string[]) => {
        const previousRoles = roles;
        try {
            setRoles(newRoles);
            const docRef = doc(db, 'config', 'permissions');
            await setDoc(docRef, { roles: newRoles }, { merge: true });
        } catch (err: any) {
            console.error('Error saving roles:', err);
            setRoles(previousRoles);
            throw err;
        }
    }, [roles]);

    // ------------------------------------------------------------------
    // Atomic save: reads latest server state, merges, writes once.
    // This is the PRIMARY save path used by PermissionsMatrix.
    // ------------------------------------------------------------------

    const savePermissionsAndRoles = useCallback(async (
        newPermissions: Record<string, Permission[]>,
        newRoles: string[],
        deletedRoles?: string[]
    ) => {
        const previousPermissions = permissions;
        const previousRoles = roles;

        try {
            // Optimistic local update for responsive UI
            setPermissions(newPermissions);
            setRoles(newRoles);

            const docRef = doc(db, 'config', 'permissions');

            // Read the latest server state to detect roles/permissions added by
            // other admins that our local (possibly stale) state doesn't know about.
            const serverSnap = await getDoc(docRef);
            const serverData = serverSnap.exists() ? serverSnap.data() : null;

            // --- Merge roles ---
            // Start with what the current admin intends to save, then union in any
            // roles that exist on the server but are NOT in the admin's local set.
            // This ensures that if Admin B doesn't know about Admin A's "HR" role,
            // Admin B's save won't delete it.
            const serverRoles: string[] = serverData?.roles ?? [];
            const mergedRoles = Array.from(new Set([
                ...DEFAULT_ROLES,
                ...newRoles,
                ...serverRoles.filter(r => !(deletedRoles || []).includes(r)),
            ]));

            // --- Merge permissions ---
            // For roles that the current admin explicitly manages (newRoles), use
            // the admin's version (they toggled checkboxes intentionally).
            // For roles that exist ONLY on the server (i.e. added by another admin),
            // preserve their server-side permissions unchanged.
            const serverPermissions: Record<string, Permission[]> = serverData?.permissions ?? {};
            const mergedPermissions: Record<string, Permission[]> = { ...newPermissions };

            for (const serverRole of Object.keys(serverPermissions)) {
                if (!(serverRole in mergedPermissions) && !(deletedRoles || []).includes(serverRole)) {
                    // This role exists on the server but the current admin didn't have it, and it was NOT explicitly deleted.
                    // Preserve it exactly as-is.
                    mergedPermissions[serverRole] = serverPermissions[serverRole];
                }
            }

            // Explicitly delete removed roles from Firestore since `{ merge: true }` ignores missing object keys
            if (deletedRoles && deletedRoles.length > 0) {
                deletedRoles.forEach(role => {
                    // @ts-ignore - deleteField() is the correct Firebase method, despite TS types for mergedPermissions
                    mergedPermissions[role] = deleteField();
                });
            }

            // Single atomic write — both roles and permissions in one setDoc call
            await setDoc(docRef, {
                roles: mergedRoles,
                permissions: mergedPermissions,
            }, { merge: true });

            // The onSnapshot listener will update local state with the merged result,
            // so no need to manually setPermissions/setRoles again here.
        } catch (err: any) {
            console.error('Error saving permissions and roles:', err);
            // Rollback on error
            setPermissions(previousPermissions);
            setRoles(previousRoles);
            throw err;
        }
    }, [permissions, roles]);

    return (
        <PermissionsContext.Provider value={{
            permissions,
            roles,
            updatePermissions,
            updateRoles,
            savePermissionsAndRoles,
            loading,
            error
        }}>
            {children}
        </PermissionsContext.Provider>
    );
};

import React, { createContext, useContext, useEffect, useState } from 'react';

type Theme = 'dark' | 'light';

interface ThemeContextType {
    theme: Theme;
    toggleTheme: () => void;
}

const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

export const ThemeProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    // Default to 'dark' as per current design
    const [theme, setTheme] = useState<Theme>(() => {
        const savedTheme = localStorage.getItem('theme');
        return (savedTheme as Theme) || 'dark';
    });

    useEffect(() => {
        const root = window.document.documentElement;

        // Remove the old theme class and add the new one
        root.classList.remove('light', 'dark');
        root.classList.add(theme);

        // Persist to local storage
        localStorage.setItem('theme', theme);
    }, [theme]);

    const toggleTheme = () => {
        setTheme(prev => prev === 'dark' ? 'light' : 'dark');
    };

    return (
        <ThemeContext.Provider value={{ theme, toggleTheme }}>
            {children}
        </ThemeContext.Provider>
    );
};

export const useTheme = () => {
    const context = useContext(ThemeContext);
    if (context === undefined) {
        throw new Error('useTheme must be used within a ThemeProvider');
    }
    return context;
};

