// =====================================================
// PCF STATUS ENUM
// =====================================================
export enum PCFStatus {
    DRAFT = 'DRAFT',
    AUDIT_REVIEW = 'AUDIT_REVIEW', // Pending Auditor Review (new step between Draft and Pending Approval)
    PENDING_APPROVAL = 'PENDING_APPROVAL',
    APPROVED = 'APPROVED',
    APPROVED_WAITING_RELEASE = 'APPROVED_WAITING_RELEASE',
    REPLENISHED = 'REPLENISHED',
    REJECTED = 'REJECTED',
    CANCELLED = 'CANCELLED',
}

// =====================================================
// EXPENSE CLASSIFICATION OPTIONS
// =====================================================
export const EXPENSE_CLASSIFICATIONS = [
    'Transportation',
    'Meals',
    'Supplies',
    'Communications',
    'Utilities',
    'Repairs & Maintenance',
    'Professional Fees',
    'Others',
] as const;

export type ExpenseClassification = typeof EXPENSE_CLASSIFICATIONS[number];

// =====================================================
// PCF EXPENSE ITEM - 10 AUDIT COLUMNS
// =====================================================
export interface PCFExpenseItem {
    id: string;
    date: string;                         // Column 1: Date
    payeeVendor: string;                  // Column 2: Payee | Vendor
    tin: string;                          // Column 3: TIN (optional)
    orNo: string;                         // Column 4: OR No. (required)
    completeAddress: string;              // Column 5: Complete Address
    // COA Fields (new) - replaces classification
    coaCode?: string;                     // Column 6: COA Account Code
    coaName?: string;                     // Column 6: COA Account Name
    classification?: ExpenseClassification; // Column 6: Legacy classification (deprecated)
    itemDescription: string;              // Column 7: Item Description
    vat: number;                          // Column 8: VAT Amount
    ewt: number;                          // Column 9: EWT Amount
    amount: number;                       // Column 10: Total Expense Amount
    buId?: string;                        // Business Unit ID (for expense sharing)
    buName?: string;                      // Business Unit Name
}

// =====================================================
// PCF LIQUIDATION INTERFACE
// =====================================================
// Audit note entry for tracking history of audit actions in PCF
export interface PCFAuditNoteEntry {
    id: string;                 // Unique ID for the note
    action: 'REJECTED' | 'CLEARED' | 'REFILE' | 'COMMENT' | 'AUDIT_REVIEW' | 'APPROVED';  // The action taken
    note: string;               // The auditor's note/reason
    actorId: string;            // Who performed the action
    actorName: string;          // Name of the actor
    timestamp: string;          // When the action was taken (ISO 8601)
}

export interface PCFLiquidation {
    id: string;
    userId: string;
    userName: string;
    businessId: string;
    expenses: PCFExpenseItem[];
    totalAmount: number;
    totalVat: number;
    totalEwt: number;
    netAmount: number;                    // totalAmount - totalEwt + totalVat (or your formula)
    receiptsLink?: string;
    attachments?: string[];
    remarks?: string;
    status: PCFStatus;
    dateCreated: string;
    dateSubmitted?: string;
    dateApproved?: string;
    approvedBy?: string;
    approvedByName?: string;
    rejectedBy?: string;
    rejectedByName?: string;
    rejectionReason?: string;
    // Cancellation fields
    cancelledBy?: string;
    cancelledByName?: string;
    cancellationReason?: string;
    dateCancelled?: string;
    replenishmentPrfId?: string;
    // Audit Review tracking (new)
    auditReviewedBy?: string;
    auditReviewedByName?: string;
    dateAuditReviewed?: string;
    auditRemarks?: string;        // Auditor's remarks when approving the liquidation
    auditClearedAt?: string;      // Timestamp when audit was cleared/approved
    // Audit Notes History - accumulates all audit actions
    auditNotesHistory?: PCFAuditNoteEntry[];
    // Late submission tracking
    isLate?: boolean;
    daysLate?: number;
    deadlineDay?: number;  // The deadline that was active at time of submission
    expenseMonth?: number; // The month (0-11) the expenses are for
}

const PCF_COLLECTION = 'pcf_liquidations';
const REQUISITIONS_COLLECTION = COLLECTIONS.REQUISITIONS;

// =====================================================
// PCF SERVICE CLASS
// =====================================================
export class PCFService {
    /**
     * Get all liquidations for a specific user
     */
    static async getUserLiquidations(userId: string): Promise<PCFLiquidation[]> {
        const liquidations = await FirestoreService.getDocuments<PCFLiquidation>(
            PCF_COLLECTION,
            [where('userId', '==', userId)]
        );
        return liquidations.sort((a, b) =>
            new Date(b.dateCreated).getTime() - new Date(a.dateCreated).getTime()
        );
    }

    /**
     * Get all liquidations from all users (for pcf:view:all permission)
     */
    static async getAllLiquidations(): Promise<PCFLiquidation[]> {
        const liquidations = await FirestoreService.getDocuments<PCFLiquidation>(
            PCF_COLLECTION,
            []
        );
        return liquidations.sort((a, b) =>
            new Date(b.dateCreated).getTime() - new Date(a.dateCreated).getTime()
        );
    }

    /**
     * Get all pending liquidations (for manager approval view)
     */
    static async getPendingLiquidations(): Promise<PCFLiquidation[]> {
        const liquidations = await FirestoreService.getDocuments<PCFLiquidation>(
            PCF_COLLECTION,
            [where('status', '==', PCFStatus.PENDING_APPROVAL)]
        );
        return liquidations.sort((a, b) =>
            new Date(a.dateCreated).getTime() - new Date(b.dateCreated).getTime()
        );
    }

    /**
     * Get active liquidations (DRAFT, PENDING_APPROVAL, APPROVED, APPROVED_WAITING_RELEASE)
     * These are liquidations that haven't been replenished yet
     */
    static async getActiveLiquidations(userId: string): Promise<PCFLiquidation[]> {
        const allLiquidations = await this.getUserLiquidations(userId);
        const activeStatuses = [
            PCFStatus.DRAFT,
            PCFStatus.AUDIT_REVIEW,
            PCFStatus.PENDING_APPROVAL,
            PCFStatus.APPROVED,
            PCFStatus.APPROVED_WAITING_RELEASE,
        ];
        return allLiquidations.filter(l => activeStatuses.includes(l.status));
    }

    /**
     * SAFETY NET: Calculate Cash On Hand
     * CashOnHand = UserCeiling - Sum(All Active Liquidations)
     */
    static async calculateCashOnHand(userId: string, pcfCeiling: number): Promise<{
        cashOnHand: number;
        activeLiquidationsTotal: number;
        activeLiquidationsCount: number;
    }> {
        const activeLiquidations = await this.getActiveLiquidations(userId);
        const activeLiquidationsTotal = activeLiquidations.reduce((sum, l) => sum + l.totalAmount, 0);
        const cashOnHand = Math.max(0, pcfCeiling - activeLiquidationsTotal);

        return {
            cashOnHand,
            activeLiquidationsTotal,
            activeLiquidationsCount: activeLiquidations.length,
        };
    }

    /**
     * Submit a new PCF Liquidation with the 10-column expense structure
     * Checks against configured deadline and marks as late if submitted after deadline
     * 
     * DEADLINE LOGIC: Expenses from Month X are due by Day Y of Month X+1
     * Example: November expenses → due by December 5th
     */
    static async submitLiquidation(
        userId: string,
        userName: string,
        businessId: string,
        expenses: PCFExpenseItem[],
        receiptsLink?: string,
        attachments?: string[],
        remarks?: string
    ): Promise<string> {
        // Calculate totals
        const totalAmount = expenses.reduce((sum, e) => sum + e.amount, 0);
        const totalVat = expenses.reduce((sum, e) => sum + e.vat, 0);
        const totalEwt = expenses.reduce((sum, e) => sum + e.ewt, 0);
        const netAmount = totalAmount - totalEwt + totalVat;

        // Check deadline for late submission based on EXPENSE DATES
        const settings = await SettingsService.getPcfSettings();
        const submissionDate = new Date();

        // Extract expense dates for deadline calculation
        const expenseDates = expenses.map(e => e.date).filter(Boolean);
        const { isLate, daysLate, expenseMonth } = SettingsService.calculateLatenessFromExpenses(
            submissionDate,
            expenseDates,
            settings.deadlineDay
        );

        const newLiquidation: Omit<PCFLiquidation, 'id'> = {
            userId,
            userName,
            businessId,
            expenses,
            totalAmount,
            totalVat,
            totalEwt,
            netAmount,
            receiptsLink: receiptsLink || '',
            attachments: attachments || [],
            remarks: remarks || '',
            status: PCFStatus.AUDIT_REVIEW, // Submit for audit review first
            dateCreated: new Date().toISOString(),
            dateSubmitted: new Date().toISOString(),
            // Late submission tracking
            isLate,
            daysLate: isLate ? daysLate : 0,
            deadlineDay: settings.deadlineDay,
            expenseMonth: expenseMonth, // Store which month these expenses are for
        };

        const docId = await FirestoreService.createDocument(PCF_COLLECTION, newLiquidation);

        // NOTIFICATION: Notify Auditors of new PCF
        try {
            await NotificationsService.notifyAuditorOnNewItem(
                'PCF',
                docId,
                userName,
                totalAmount
            );
        } catch (error) {
            console.error('Failed to create PCF notification:', error);
        }

        ActivityLogService.log(
            'Finance',
            'PCF Submitted',
            `${userName} submitted PCF liquidation (₱${totalAmount.toLocaleString()})`,
            { id: userId, name: userName },
            businessId,
            { entityId: docId, entityType: 'PCF Liquidation', severity: 'info' }
        );

        return docId;
    }

    /**
     * Create a draft liquidation (for saving without submitting)
     */
    static async createDraftLiquidation(
        userId: string,
        userName: string,
        businessId: string,
        expenses: PCFExpenseItem[],
        receiptsLink?: string,
        remarks?: string
    ): Promise<string> {
        const totalAmount = expenses.reduce((sum, e) => sum + e.amount, 0);
        const totalVat = expenses.reduce((sum, e) => sum + e.vat, 0);
        const totalEwt = expenses.reduce((sum, e) => sum + e.ewt, 0);
        const netAmount = totalAmount - totalEwt + totalVat;

        const newLiquidation: Omit<PCFLiquidation, 'id'> = {
            userId,
            userName,
            businessId,
            expenses,
            totalAmount,
            totalVat,
            totalEwt,
            netAmount,
            receiptsLink: receiptsLink || '',
            attachments: [],
            remarks: remarks || '',
            status: PCFStatus.DRAFT,
            dateCreated: new Date().toISOString(),
        };

        const docId = await FirestoreService.createDocument(PCF_COLLECTION, newLiquidation);
        return docId;
    }

    /**
     * Submit a draft for approval
     * FIX: Now includes late submission check based on expense dates
     */
    static async submitForApproval(liquidationId: string): Promise<void> {
        // Fetch the draft to get expense dates
        const liquidation = await this.getLiquidationById(liquidationId);
        if (!liquidation) {
            throw new Error('Liquidation not found');
        }

        // Check deadline for late submission based on expense dates
        const settings = await SettingsService.getPcfSettings();
        const submissionDate = new Date();
        const expenseDates = liquidation.expenses.map(e => e.date).filter(Boolean);
        const { isLate, daysLate, expenseMonth } = SettingsService.calculateLatenessFromExpenses(
            submissionDate,
            expenseDates,
            settings.deadlineDay
        );

        await FirestoreService.updateDocument(PCF_COLLECTION, liquidationId, {
            status: PCFStatus.AUDIT_REVIEW,
            dateSubmitted: new Date().toISOString(),
            isLate,
            daysLate: isLate ? daysLate : 0,
            deadlineDay: settings.deadlineDay,
            expenseMonth,
        });

        // NOTIFICATION: Notify Auditor (`AUDIT_REVIEW` status)
        try {
            await NotificationsService.createNotification({
                ...NOTIFICATION_TYPES.LIQUIDATION_FILED, // Or LIQUIDATION_READY_FOR_AUDIT if preferred
                type: 'AUDIT',
                subType: 'PENDING_ACTION',
                message: `New PCF Liquidation Filed: #${liquidationId.slice(-6)} by ${liquidation.userName}`,
                requisitionId: liquidationId,
                targetRoles: ['AUDITOR'],
                actionUrl: `/pcf-audit-review`,
                metadata: {
                    requisitionNumber: liquidationId.slice(-6),
                    requesterName: liquidation.userName,
                    amount: liquidation.totalAmount,
                    stage: 'Audit Review'
                }
            });
        } catch (error) {
            console.error('Failed to create auditor notification for PCF:', error);
        }
    }

    /**
     * Approve audit review - moves liquidation to PENDING_APPROVAL for manager
     * Only authorized auditors can perform this action
     */
    static async approveAuditReview(
        liquidationId: string,
        auditorId: string,
        auditorName: string,
        auditRemarks?: string
    ): Promise<void> {
        const liquidation = await this.getLiquidationById(liquidationId);
        if (!liquidation) {
            throw new Error('Liquidation not found');
        }
        if (liquidation.status !== PCFStatus.AUDIT_REVIEW) {
            throw new Error(`Cannot approve audit review: Liquidation is in ${liquidation.status} status`);
        }

        // Create audit note entry for history
        const auditNoteEntry: PCFAuditNoteEntry = {
            id: `audit-${Date.now()}`,
            action: 'CLEARED',
            note: auditRemarks || 'Audit review approved',
            actorId: auditorId,
            actorName: auditorName,
            timestamp: new Date().toISOString()
        };

        // Append to existing history or create new array
        const existingHistory = liquidation.auditNotesHistory || [];

        await FirestoreService.updateDocument(PCF_COLLECTION, liquidationId, {
            status: PCFStatus.PENDING_APPROVAL,
            auditReviewedBy: auditorId,
            auditReviewedByName: auditorName,
            dateAuditReviewed: new Date().toISOString(),
            auditRemarks: auditRemarks || '',
            auditClearedAt: new Date().toISOString(),
            auditNotesHistory: [...existingHistory, auditNoteEntry]
        });

        // NOTIFICATION: Notify Manager of PCF ready for approval
        try {
            await NotificationsService.createNotification({
                ...NOTIFICATION_TYPES.PENDING_APPROVAL,
                message: `PCF Liquidation #${liquidationId.slice(-6)} audited and ready for approval`,
                requisitionId: liquidationId,
                targetRoles: ['MANAGER'], // Target generic MANAGER role
                actionUrl: `/pcf-approvals`, // Use dedicated approvals view
                metadata: {
                    requisitionNumber: liquidationId.slice(-6),
                    requesterName: liquidation.userName,
                    amount: liquidation.totalAmount,
                    stage: 'Manager Approval'
                }
            });
        } catch (error) {
            console.error('Failed to create manager notification for PCF:', error);
        }

        ActivityLogService.log(
            'Finance',
            'PCF Audit Cleared',
            `${auditorName} cleared PCF #${liquidationId.slice(-6)} for approval`,
            { id: auditorId, name: auditorName },
            liquidation.businessId || '',
            { entityId: liquidationId, entityType: 'PCF Liquidation', severity: 'success' }
        );
    }

    /**
     * Get all liquidations pending audit review (for auditor view)
     */
    static async getAuditReviewLiquidations(): Promise<PCFLiquidation[]> {
        const liquidations = await FirestoreService.getDocuments<PCFLiquidation>(
            PCF_COLLECTION,
            [where('status', '==', PCFStatus.AUDIT_REVIEW)]
        );
        return liquidations.sort((a, b) =>
            new Date(a.dateCreated).getTime() - new Date(b.dateCreated).getTime()
        );
    }

    /**
     * FAST TRACK: Approve and Auto-Create PRF
     * 1. Update PCF status to APPROVED_WAITING_RELEASE
     * 2. Auto-create PRF with status: APPROVED (skips approval queue)
     */
    static async approveAndReplenish(
        liquidationId: string,
        approverId: string,
        approverName: string,
        businessId: string,
        custodianName: string
    ): Promise<{ prfId: string }> {
        let newPrfId = '';

        await runTransaction(db, async (transaction) => {
            // Step 1: Get the liquidation
            const liquidationRef = doc(db, PCF_COLLECTION, liquidationId);
            const liquidationSnap = await transaction.get(liquidationRef);

            if (!liquidationSnap.exists()) {
                throw new Error('PCF Liquidation not found');
            }

            const liquidation = liquidationSnap.data() as PCFLiquidation;

            if (liquidation.status !== PCFStatus.PENDING_APPROVAL) {
                throw new Error(`Cannot approve: Liquidation is in ${liquidation.status} status`);
            }

            // Step 2: Generate PCF Replenishment ID (uses its own PCF-00001 sequence)
            newPrfId = await CounterService.getNextId('PCF');

            // Step 3: Create auto-approved PRF (FAST TRACK - skips manager approval)
            const prfRef = doc(db, REQUISITIONS_COLLECTION, newPrfId);

            // Build PRF items from PCF expenses
            // FIX: Use coaName || classification for backward compatibility
            const prfItems: RequisitionItem[] = liquidation.expenses.map((expense, index) => ({
                itemId: `pcf-${liquidationId}-${index}`,
                name: `${expense.coaName || expense.classification || 'Expense'}: ${expense.itemDescription}`,
                quantity: 1,
                uom: 'lot',
                price: expense.amount,
                stockOnHand: 0,
            }));

            const supplierDetails: SupplierDetails = {
                name: 'PCF Replenishment',
                tin: '',
                address: '',
                paymentMode: 'Cash',
                terms: 'Immediate',
            };

            const newPrf: Partial<Requisition> = {
                id: newPrfId,
                status: RequisitionStatus.PENDING_FINANCE_HEAD_BR_APPROVAL, // Go through BR process
                businessId: businessId,
                description: `[PCF_REPLENISHMENT] PCF Replenishment for ${custodianName}`,
                remarks: `Auto-generated from PCF Liquidation ${liquidationId}. Approved by ${approverName}. Goes through BR process.`,
                items: prfItems,
                totalAmount: liquidation.totalAmount,
                requesterId: liquidation.userId,
                requesterName: liquidation.userName,
                dateCreated: new Date().toISOString(),
                timestamp: new Date().toISOString(),
                // Link to parent PCF for auto-update when funds are released
                linkedPcfId: liquidationId,
                // Flag to skip liquidation after fund release (already liquidated via PCF)
                isPcfReplenishment: true,
                prfDetails: {
                    supplier: supplierDetails,
                    preparedBy: approverId,
                    preparedByName: approverName,
                    datePrepared: new Date().toISOString(),
                    timestamp: new Date().toISOString(),
                },
                history: [{
                    date: new Date().toISOString(),
                    actorId: approverId,
                    actorName: approverName,
                    action: 'PCF_REPLENISHMENT_CREATED',
                    comments: `Auto-created from PCF Liquidation approval. Routed through BR workflow.`,
                    stage: RequisitionStatus.PENDING_FINANCE_HEAD_BR_APPROVAL,
                    timestamp: new Date().toISOString(),
                }],
            };

            transaction.set(prfRef, newPrf);

            // Step 4: Update PCF Status
            transaction.update(liquidationRef, {
                // The prompt says "Approve and Replenish", forcing creating PRF.
                // Logic says: "1. Update PCF status to APPROVED_WAITING_RELEASE" in comment, but effectively REPLENISHED if funds released?
                // Actually, let's stick to REPLENISHED if the PRF is created. Or closer to typical flow.
                // Given "Fast Track", let's assume REPLENISHED or APPROVED_WAITING_RELEASE.
                // Let's use APPROVED_WAITING_RELEASE as it waits for the PRF to be paid.
                status: PCFStatus.APPROVED_WAITING_RELEASE,
                dateApproved: new Date().toISOString(),
                approvedBy: approverId,
                approvedByName: approverName,
                replenishmentPrfId: newPrfId,
            });
        });

        // NOTIFICATION: Notify Custodian (Filer) that PCF is replenished/approved
        try {
            const liquidation = await this.getLiquidationById(liquidationId);
            if (liquidation) {
                await NotificationsService.createNotification({
                    ...NOTIFICATION_TYPES.LIQUIDATION_CLEARED,
                    message: `Your PCF Liquidation #${liquidationId.slice(-6)} has been approved. Replenishment PRF: #${newPrfId.slice(-6)}`,
                    requisitionId: liquidationId,
                    targetRoles: [liquidation.userId],
                    actionUrl: `/pcf`,
                    metadata: {
                        requisitionNumber: liquidationId.slice(-6),
                        amount: liquidation.totalAmount,
                        stage: 'Replenished'
                    }
                });
            }
        } catch (error) {
            console.error('Failed to notify custodian of PCF approval:', error);
        }

        return { prfId: newPrfId };
    }

    /**
     * Mark liquidation as replenished (after funds released)
     */
    static async markReplenished(liquidationId: string): Promise<void> {
        await FirestoreService.updateDocument(PCF_COLLECTION, liquidationId, {
            status: PCFStatus.REPLENISHED,
        });
    }

    /**
     * Reject a liquidation
     */
    static async rejectLiquidation(
        liquidationId: string,
        rejectedById: string,
        rejectedByName: string,
        reason: string
    ): Promise<void> {
        // Get existing liquidation to preserve history
        const liquidation = await this.getLiquidationById(liquidationId);

        // Create audit note entry for history
        const auditNoteEntry: PCFAuditNoteEntry = {
            id: `reject-${Date.now()}`,
            action: 'REJECTED',
            note: reason,
            actorId: rejectedById,
            actorName: rejectedByName,
            timestamp: new Date().toISOString()
        };

        // Append to existing history or create new array
        const existingHistory = liquidation?.auditNotesHistory || [];

        await FirestoreService.updateDocument(PCF_COLLECTION, liquidationId, {
            status: PCFStatus.REJECTED,
            rejectedBy: rejectedById,
            rejectedByName: rejectedByName,
            rejectionReason: reason,
            auditNotesHistory: [...existingHistory, auditNoteEntry]
        });

        // NOTIFICATION: Notify Custodian (Filer) of Rejection
        try {
            if (liquidation) {
                await NotificationsService.createNotification({
                    type: 'PCF',
                    subType: 'REJECTED',
                    message: `Your PCF Liquidation #${liquidationId.slice(-6)} was rejected. Reason: ${reason}`,
                    requisitionId: liquidationId,
                    targetRoles: [liquidation.userId],
                    actionUrl: `/pcf`,
                    priority: 'HIGH'
                });
            }
        } catch (error) {
            console.error('Failed to notify custodian of PCF rejection:', error);
        }

        ActivityLogService.log(
            'Finance',
            'PCF Rejected',
            `${rejectedByName} rejected PCF #${liquidationId.slice(-6)}: ${reason}`,
            { id: rejectedById, name: rejectedByName },
            liquidation?.businessId || '',
            { entityId: liquidationId, entityType: 'PCF Liquidation', severity: 'warning' }
        );
    }

    /**
     * Cancel a liquidation (returns amount to balance since CANCELLED is not in active statuses)
     */
    static async cancelLiquidation(
        liquidationId: string,
        cancelledById: string,
        cancelledByName: string,
        reason: string
    ): Promise<void> {
        await FirestoreService.updateDocument(PCF_COLLECTION, liquidationId, {
            status: PCFStatus.CANCELLED,
            cancelledBy: cancelledById,
            cancelledByName: cancelledByName,
            cancellationReason: reason,
            dateCancelled: new Date().toISOString(),
        });
    }

    /**
     * Get a single liquidation by ID
     */
    static async getLiquidationById(liquidationId: string): Promise<PCFLiquidation | null> {
        return await FirestoreService.getDocument<PCFLiquidation>(PCF_COLLECTION, liquidationId);
    }

    /**
     * Refile a rejected liquidation - resets to AUDIT_REVIEW
     * Clears rejection data and allows the user to submit again
     */
    static async refileLiquidation(
        liquidationId: string,
        expenses: PCFExpenseItem[],
        receiptsLink?: string,
        remarks?: string
    ): Promise<void> {
        // Calculate totals
        const totalAmount = expenses.reduce((sum, e) => sum + e.amount, 0);
        const totalVat = expenses.reduce((sum, e) => sum + e.vat, 0);
        const totalEwt = expenses.reduce((sum, e) => sum + e.ewt, 0);
        const netAmount = totalAmount - totalEwt + totalVat;

        // Get existing liquidation to preserve history
        const liquidation = await this.getLiquidationById(liquidationId);

        // Create audit note entry for refile action
        const auditNoteEntry: PCFAuditNoteEntry = {
            id: `refile-${Date.now()}`,
            action: 'REFILE',
            note: remarks || 'Liquidation refiled for approval',
            actorId: liquidation?.userId || '',
            actorName: liquidation?.userName || '',
            timestamp: new Date().toISOString()
        };

        // Append to existing history or create new array
        const existingHistory = liquidation?.auditNotesHistory || [];

        // Check if this was previously in the BR flow (has replenishmentPrfId)
        if (liquidation?.replenishmentPrfId) {
            // It was rejected in BR flow. We should refile the PRF directly!
            // First, update PCF Liquidation back to APPROVED_WAITING_RELEASE
            await FirestoreService.updateDocument(PCF_COLLECTION, liquidationId, {
                expenses,
                totalAmount,
                totalVat,
                totalEwt,
                netAmount,
                receiptsLink: receiptsLink || '',
                remarks: remarks || '',
                status: PCFStatus.APPROVED_WAITING_RELEASE,
                dateSubmitted: new Date().toISOString(),
                // Clear rejection data
                rejectedBy: null,
                rejectedByName: null,
                rejectionReason: null,
                auditNotesHistory: [...existingHistory, auditNoteEntry]
            });

            // Now refile the PRF and update its total amount
            // Import RequisitionService dynamically to avoid circular dependencies
            const { RequisitionService } = await import('../../procurement/services/requisitions.service');
            const prfItems = expenses.map((expense, index) => ({
                itemId: `pcf-${liquidationId}-${index}`,
                name: `${expense.coaName || expense.classification || 'Expense'}: ${expense.itemDescription}`,
                quantity: 1,
                uom: 'lot',
                price: expense.amount,
                stockOnHand: 0,
            }));

            await RequisitionService.reFileRequisition(
                liquidation.replenishmentPrfId,
                liquidation.userId,
                liquidation.userName,
                {
                    totalAmount,
                    items: prfItems as any,
                }
            );

            return;
        }

        await FirestoreService.updateDocument(PCF_COLLECTION, liquidationId, {
            expenses,
            totalAmount,
            totalVat,
            totalEwt,
            netAmount,
            receiptsLink: receiptsLink || '',
            remarks: remarks || '',
            status: PCFStatus.AUDIT_REVIEW,
            dateSubmitted: new Date().toISOString(),
            // Clear rejection data
            rejectedBy: null,
            rejectedByName: null,
            rejectionReason: null,
            auditNotesHistory: [...existingHistory, auditNoteEntry]
        });

        // NOTIFICATION: Notify Auditors of Refiled PCF
        try {
            await NotificationsService.notifyAuditorOnNewItem(
                'PCF',
                liquidationId,
                liquidation?.userName,
                totalAmount
            );
        } catch (error) {
            console.error('Failed to create PCF refile notification:', error);
        }
    }

    /**
     * Update a draft liquidation
     */
    static async updateDraftLiquidation(
        liquidationId: string,
        expenses: PCFExpenseItem[],
        receiptsLink?: string,
        remarks?: string
    ): Promise<void> {
        const totalAmount = expenses.reduce((sum, e) => sum + e.amount, 0);
        const totalVat = expenses.reduce((sum, e) => sum + e.vat, 0);
        const totalEwt = expenses.reduce((sum, e) => sum + e.ewt, 0);
        const netAmount = totalAmount - totalEwt + totalVat;

        await FirestoreService.updateDocument(PCF_COLLECTION, liquidationId, {
            expenses,
            totalAmount,
            totalVat,
            totalEwt,
            netAmount,
            receiptsLink: receiptsLink || '',
            remarks: remarks || '',
        });
    }
}

/**
 * BankReconView
 * 
 * Bank Reconciliation page under Finance module.
 * Upload multi-sheet Excel bank statements, smart-parse them,
 * view parsed data in tabbed tables, save to Firestore.
 */

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Upload, FileSpreadsheet, Trash2, Save, X, Download, Clock, Layers, Hash, Calendar, ArrowDownRight, ArrowUpRight, Settings, CheckCircle2, AlertTriangle, AlertCircle, Edit2, Send, CheckCircle, XCircle, RefreshCw } from 'lucide-react';
import { BankReconService, type ParsedWorkbook, type ParsedSheet, type BankReconStatement, type RowAuditStatus } from '../services/bankRecon.service';
import { CoaService } from '../../../shared/services/coa.service';
import type { ChartOfAccount } from '../../../shared/types/firebase.types';
import { fetchBusinesses } from '../../../shared/services/businessService';
import type { Business } from '../../../shared/types';
import { useAuth } from '../../../contexts/useAuth';
import { usePermissions } from '../../../hooks/usePermissions';
import { exportToCSV, type ExportColumn } from '../../../shared/utils/exportUtils';
import './BankReconView.css';

const BankReconView: React.FC = () => {
    const { currentUser } = useAuth();
    const { hasPermission } = usePermissions();
    const canAudit = hasPermission('finance:bank_recon:audit');
    const canEdit = hasPermission('finance:bank_recon:edit:remarks');
    const canViewAll = hasPermission('finance:bank_recon:view:all');

    // COA accounts for dropdown
    const [coaAccounts, setCoaAccounts] = useState<ChartOfAccount[]>([]);
    const [coaDropdownRow, setCoaDropdownRow] = useState<number | null>(null);
    const [coaSearchTerm, setCoaSearchTerm] = useState('');

    // BU filter
    const [businesses, setBusinesses] = useState<Business[]>([]);
    const [selectedBuFilter, setSelectedBuFilter] = useState<string>('my');

    // Upload states
    const [isDragging, setIsDragging] = useState(false);
    const [uploadedFile, setUploadedFile] = useState<File | null>(null);
    const [parsing, setParsing] = useState(false);
    const [parseError, setParseError] = useState<string | null>(null);
    const [generating, setGenerating] = useState(false);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Parsed data
    const [parsedWorkbook, setParsedWorkbook] = useState<ParsedWorkbook | null>(null);
    const [activeSheetIndex, setActiveSheetIndex] = useState(0);

    // Saved statements
    const [savedStatements, setSavedStatements] = useState<BankReconStatement[]>([]);
    const [loadingHistory, setLoadingHistory] = useState(true);
    const [saving, setSaving] = useState(false);

    // Viewing a saved statement
    const [viewingStatement, setViewingStatement] = useState<BankReconStatement | null>(null);
    const [viewingSheets, setViewingSheets] = useState<ParsedSheet[]>([]);
    const [viewingSheetIndex, setViewingSheetIndex] = useState(0);
    const [loadingView, setLoadingView] = useState(false);

    // List tabs
    const [listTab, setListTab] = useState<'ACTIVE' | 'HISTORY'>('ACTIVE');

    // Load saved statements on mount
    useEffect(() => {
        loadSavedStatements();
        // Load COA accounts for dropdown
        CoaService.getActiveAccounts().then(setCoaAccounts).catch(console.error);
        // Load businesses for BU filter
        if (canViewAll) {
            fetchBusinesses().then(setBusinesses).catch(console.error);
        }
    }, []);

    const loadSavedStatements = async () => {
        setLoadingHistory(true);
        try {
            // If canViewAll, fetch all statements (we filter client-side via BU selector)
            const userBuIds = currentUser?.businessUnitIds || (currentUser?.businessId ? [currentUser.businessId] : []);
            const statements = await BankReconService.getBankStatements(userBuIds, canViewAll);
            setSavedStatements(statements);
        } catch (err) {
            console.error('Failed to load bank statements:', err);
        } finally {
            setLoadingHistory(false);
        }
    };

    // Filtered statements based on BU selector
    const filteredStatements = savedStatements.filter(s => {
        if (selectedBuFilter === 'all') return true;
        if (selectedBuFilter === 'my') {
            const userBuIds = currentUser?.businessUnitIds || (currentUser?.businessId ? [currentUser.businessId] : []);
            return !s.businessUnitId || s.businessUnitId === '' || userBuIds.includes(s.businessUnitId);
        }
        // Specific BU ID selected
        return s.businessUnitId === selectedBuFilter;
    });

    // File handling
    const handleFileSelect = useCallback(async (file: File) => {
        const ext = file.name.split('.').pop()?.toLowerCase();
        if (!ext || !['xlsx', 'xls', 'csv'].includes(ext)) {
            setParseError('Please upload an Excel file (.xlsx or .xls)');
            return;
        }

        setUploadedFile(file);
        setParsing(true);
        setParseError(null);
        setParsedWorkbook(null);
        setActiveSheetIndex(0);

        // Clear any viewed statement
        setViewingStatement(null);
        setViewingSheets([]);

        try {
            const workbook = await BankReconService.parseExcelFile(file);
            setParsedWorkbook(workbook);
            if (workbook.sheets.length === 0) {
                setParseError('No data found in the uploaded file.');
            }
        } catch (err: any) {
            setParseError(err.message || 'Failed to parse the file.');
            console.error(err);
        } finally {
            setParsing(false);
        }
    }, []);

    const handleDrop = useCallback((e: React.DragEvent) => {
        e.preventDefault();
        setIsDragging(false);
        const file = e.dataTransfer.files[0];
        if (file) handleFileSelect(file);
    }, [handleFileSelect]);

    const handleDragOver = useCallback((e: React.DragEvent) => {
        e.preventDefault();
        setIsDragging(true);
    }, []);

    const handleDragLeave = useCallback(() => {
        setIsDragging(false);
    }, []);

    const handleClickUpload = () => {
        fileInputRef.current?.click();
    };

    const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) handleFileSelect(file);
        // Reset so the same file can be re-uploaded
        e.target.value = '';
    };

    const clearUpload = () => {
        setUploadedFile(null);
        setParsedWorkbook(null);
        setParseError(null);
        setActiveSheetIndex(0);
    };

    // Save to Firestore
    // Save to Firestore with specific status
    const handleSaveStatus = async (status: 'PENDING_MATCH' | 'PENDING_AUDIT' | 'COMPLETED') => {
        if (!parsedWorkbook || !currentUser) return;
        setSaving(true);
        try {
            await BankReconService.saveBankStatement(
                parsedWorkbook,
                currentUser.id,
                currentUser.name,
                status,
                currentUser.businessId,
                '' // BU name - will be populated from context if available
            );
            await loadSavedStatements();
            clearUpload();
        } catch (err: any) {
            console.error(`Failed to save as ${status}:`, err);
            alert(`Failed to save bank statement: ${err?.message || err}`);
        } finally {
            setSaving(false);
        }
    };

    const handleSaveDraft = () => handleSaveStatus('PENDING_MATCH');

    const handleSubmitAudit = async () => {
        if (viewingStatement) {
            setSaving(true);
            try {
                await BankReconService.updateStatementStatus(viewingStatement.id!, 'PENDING_AUDIT');
                setViewingStatement({ ...viewingStatement, status: 'PENDING_AUDIT' });
                await loadSavedStatements();
            } catch (err: any) {
                console.error('Failed to submit for audit:', err);
                alert(`Failed to submit: ${err?.message || err}`);
            } finally {
                setSaving(false);
            }
        } else {
            handleSaveStatus('PENDING_AUDIT');
        }
    };

    const handleMarkAudited = async () => {
        if (!viewingStatement || viewingStatement.status !== 'PENDING_AUDIT' || !canAudit) return;
        if (!confirm('Are you sure you want to mark this statement as completely audited?')) return;

        setSaving(true);
        try {
            await BankReconService.updateStatementStatus(viewingStatement.id!, 'COMPLETED');
            // Update local state and history
            setViewingStatement({ ...viewingStatement, status: 'COMPLETED' });
            await loadSavedStatements();
        } catch (err: any) {
            console.error('Failed to mark as audited:', err);
            alert(`Failed to update status: ${err?.message || err}`);
        } finally {
            setSaving(false);
        }
    };

    const handleSaveAuditProgress = async () => {
        if (!viewingStatement || viewingStatement.status !== 'PENDING_AUDIT' || !canAudit) return;

        setSaving(true);
        try {
            await BankReconService.updateStatementStatus(viewingStatement.id!, 'PENDING_AUDIT');
            await loadSavedStatements();
            closeViewStatement();
        } catch (err: any) {
            console.error('Failed to save audit progress:', err);
            alert(`Failed to save progress: ${err?.message || err}`);
        } finally {
            setSaving(false);
        }
    };

    // View saved statement
    const handleViewStatement = async (statement: BankReconStatement) => {
        setLoadingView(true);
        setViewingStatement(statement);
        setViewingSheetIndex(0);
        // Clear upload view
        clearUpload();
        try {
            const sheets = await BankReconService.getStatementSheetData(statement.id!);
            setViewingSheets(sheets);
        } catch (err) {
            console.error('Failed to load sheet data:', err);
            setViewingSheets([]);
        } finally {
            setLoadingView(false);
        }
    };

    const closeViewStatement = () => {
        setViewingStatement(null);
        setViewingSheets([]);
        setViewingSheetIndex(0);
    };

    // Delete statement
    const handleDelete = async (statementId: string, e: React.MouseEvent) => {
        e.stopPropagation();
        if (!confirm('Delete this bank statement? This cannot be undone.')) return;
        try {
            await BankReconService.deleteBankStatement(statementId);
            if (viewingStatement?.id === statementId) closeViewStatement();
            setSavedStatements(prev => prev.filter(s => s.id !== statementId));
        } catch (err) {
            console.error('Failed to delete:', err);
            alert('Failed to delete. Please try again.');
        }
    };

    // Export current sheet as CSV
    const handleExportCSV = (sheets: ParsedSheet[], sheetIdx: number) => {
        const sheet = sheets[sheetIdx];
        if (!sheet || sheet.rows.length === 0) return;

        const columns: ExportColumn<Record<string, any>>[] = sheet.headers.map(h => ({
            header: h,
            accessor: (row) => {
                const val = row[h];
                return val !== null && val !== undefined ? String(val) : '';
            }
        }));

        exportToCSV(sheet.rows, columns, `bank_recon_${sheet.sheetName}`);
    };

    // Generate Reconciliation Engine Match
    const handleGenerateReport = async () => {
        const activeSheets = viewingStatement ? viewingSheets : (parsedWorkbook?.sheets || []);
        const activeIdx = viewingStatement ? viewingSheetIndex : activeSheetIndex;
        const currentSheet = activeSheets[activeIdx];

        if (!currentSheet || currentSheet.rows.length === 0) return;

        setGenerating(true);
        try {
            const enrichedRows = await BankReconService.generateReconciliationReport(currentSheet);

            // Build updated sheet
            // We ensure that newly added columns (Remarks, Linked Chart of Accounts)
            // are added to the headers list if they aren't there yet
            const updatedHeaders = [...currentSheet.headers];
            if (!updatedHeaders.includes('Remarks')) updatedHeaders.push('Remarks');
            if (!updatedHeaders.includes('Linked Chart of Accounts')) updatedHeaders.push('Linked Chart of Accounts');

            const updatedSheet = {
                ...currentSheet,
                headers: updatedHeaders,
                rows: enrichedRows
            };

            // Update state depending on whether we're viewing a saved statement or an unsaved one
            if (viewingStatement) {
                const newViewingSheets = [...viewingSheets];
                newViewingSheets[viewingSheetIndex] = updatedSheet;
                setViewingSheets(newViewingSheets);
            } else if (parsedWorkbook) {
                const newSheets = [...parsedWorkbook.sheets];
                newSheets[activeSheetIndex] = updatedSheet;
                setParsedWorkbook({
                    ...parsedWorkbook,
                    sheets: newSheets
                });
            }
        } catch (err: any) {
            console.error('Failed to generate matching report:', err);
            alert(`Failed to generate matched report: ${err.message}`);
        } finally {
            setGenerating(false);
        }
    };

    // Audit: Approve a row
    const handleAuditApprove = async (rowIdx: number) => {
        if (!canAudit) return;
        if (viewingStatement && viewingStatement.status !== 'PENDING_AUDIT') return;

        const activeSheets = viewingStatement ? viewingSheets : (parsedWorkbook?.sheets || []);
        const activeIdx = viewingStatement ? viewingSheetIndex : activeSheetIndex;
        const currentSheet = activeSheets[activeIdx];
        if (!currentSheet) return;

        const newRows = [...currentSheet.rows];
        newRows[rowIdx] = {
            ...newRows[rowIdx],
            auditStatus: 'APPROVED' as RowAuditStatus,
            rejectionReason: '',
            auditedBy: currentUser?.id || '',
            auditedByName: currentUser?.name || '',
            Cleared: true // backward compatible
        };

        const newSheet = { ...currentSheet, rows: newRows };

        if (viewingStatement) {
            const newViewingSheets = [...viewingSheets];
            newViewingSheets[activeIdx] = newSheet;
            setViewingSheets(newViewingSheets);
            try {
                if (!newSheet.id) throw new Error('Sheet ID is missing.');
                await BankReconService.updateSheetData(viewingStatement.id!, newSheet.id, newRows);
            } catch (err) {
                console.error('Failed to approve row:', err);
                alert('Failed to save audit status.');
                newRows[rowIdx].auditStatus = 'PENDING';
                newRows[rowIdx].Cleared = false;
                newViewingSheets[activeIdx] = { ...currentSheet, rows: newRows };
                setViewingSheets([...newViewingSheets]);
            }
        } else if (parsedWorkbook) {
            const newSheets = [...parsedWorkbook.sheets];
            newSheets[activeIdx] = newSheet;
            setParsedWorkbook({ ...parsedWorkbook, sheets: newSheets });
        }
    };

    // Audit: Reject a row
    const handleAuditReject = async (rowIdx: number) => {
        if (!canAudit) return;
        if (viewingStatement && viewingStatement.status !== 'PENDING_AUDIT') return;

        const reason = prompt('Enter rejection reason:');
        if (!reason) return; // cancelled or empty

        const activeSheets = viewingStatement ? viewingSheets : (parsedWorkbook?.sheets || []);
        const activeIdx = viewingStatement ? viewingSheetIndex : activeSheetIndex;
        const currentSheet = activeSheets[activeIdx];
        if (!currentSheet) return;

        const newRows = [...currentSheet.rows];
        newRows[rowIdx] = {
            ...newRows[rowIdx],
            auditStatus: 'REJECTED' as RowAuditStatus,
            rejectionReason: reason,
            auditedBy: currentUser?.id || '',
            auditedByName: currentUser?.name || '',
            Cleared: false
        };

        const newSheet = { ...currentSheet, rows: newRows };

        if (viewingStatement) {
            const newViewingSheets = [...viewingSheets];
            newViewingSheets[activeIdx] = newSheet;
            setViewingSheets(newViewingSheets);
            try {
                if (!newSheet.id) throw new Error('Sheet ID is missing.');
                await BankReconService.updateSheetData(viewingStatement.id!, newSheet.id, newRows);
            } catch (err) {
                console.error('Failed to reject row:', err);
                alert('Failed to save rejection.');
                newRows[rowIdx].auditStatus = 'PENDING';
                newRows[rowIdx].rejectionReason = '';
                newViewingSheets[activeIdx] = { ...currentSheet, rows: newRows };
                setViewingSheets([...newViewingSheets]);
            }
        } else if (parsedWorkbook) {
            const newSheets = [...parsedWorkbook.sheets];
            newSheets[activeIdx] = newSheet;
            setParsedWorkbook({ ...parsedWorkbook, sheets: newSheets });
        }
    };

    // Refile: Uploader can refile rejected rows (resets to PENDING)
    const handleRefileRow = async (rowIdx: number) => {
        const activeSheets = viewingStatement ? viewingSheets : (parsedWorkbook?.sheets || []);
        const activeIdx = viewingStatement ? viewingSheetIndex : activeSheetIndex;
        const currentSheet = activeSheets[activeIdx];
        if (!currentSheet) return;

        const row = currentSheet.rows[rowIdx];
        if (row.auditStatus !== 'REJECTED') return;

        // Only the uploader can refile
        if (viewingStatement && viewingStatement.uploadedBy !== currentUser?.id) return;

        const newRows = [...currentSheet.rows];
        newRows[rowIdx] = {
            ...newRows[rowIdx],
            auditStatus: 'PENDING' as RowAuditStatus,
            rejectionReason: '',
            Cleared: false
        };

        const newSheet = { ...currentSheet, rows: newRows };

        if (viewingStatement) {
            const newViewingSheets = [...viewingSheets];
            newViewingSheets[activeIdx] = newSheet;
            setViewingSheets(newViewingSheets);
            try {
                if (!newSheet.id) throw new Error('Sheet ID is missing.');
                await BankReconService.updateSheetData(viewingStatement.id!, newSheet.id, newRows);
            } catch (err) {
                console.error('Failed to refile row:', err);
                alert('Failed to refile.');
                newRows[rowIdx].auditStatus = 'REJECTED';
                newViewingSheets[activeIdx] = { ...currentSheet, rows: newRows };
                setViewingSheets([...newViewingSheets]);
            }
        } else if (parsedWorkbook) {
            const newSheets = [...parsedWorkbook.sheets];
            newSheets[activeIdx] = newSheet;
            setParsedWorkbook({ ...parsedWorkbook, sheets: newSheets });
        }
    };

    // Edit COA for a row
    const handleEditCoa = async (rowIdx: number, selectedCoa: ChartOfAccount) => {
        if (!canEdit) return;

        const activeSheets = viewingStatement ? viewingSheets : (parsedWorkbook?.sheets || []);
        const activeIdx = viewingStatement ? viewingSheetIndex : activeSheetIndex;
        const currentSheet = activeSheets[activeIdx];
        if (!currentSheet) return;

        const newCoaValue = `${selectedCoa.code} - ${selectedCoa.name}`;
        const newRows = [...currentSheet.rows];
        newRows[rowIdx] = {
            ...newRows[rowIdx],
            'Linked Chart of Accounts': newCoaValue
        };

        const newSheet = { ...currentSheet, rows: newRows };

        if (viewingStatement) {
            const newViewingSheets = [...viewingSheets];
            newViewingSheets[activeIdx] = newSheet;
            setViewingSheets(newViewingSheets);
            try {
                if (!newSheet.id) throw new Error('Sheet ID is missing.');
                await BankReconService.updateSheetData(viewingStatement.id!, newSheet.id, newRows);
            } catch (err) {
                console.error('Failed to update COA:', err);
                alert('Failed to save COA update.');
            }
        } else if (parsedWorkbook) {
            const newSheets = [...parsedWorkbook.sheets];
            newSheets[activeIdx] = newSheet;
            setParsedWorkbook({ ...parsedWorkbook, sheets: newSheets });
        }
        setCoaDropdownRow(null);
    };

    // Edit Remark
    const handleEditRemark = async (rowIdx: number, currentRemark: string) => {
        if (!canEdit) return; // Prevent unauthorized edits
        if (viewingStatement && viewingStatement.status === 'COMPLETED') return; // Cannot edit if completed
        if (viewingStatement && viewingStatement.status === 'PENDING_AUDIT' && !canAudit) return; // Usually only finance edits before audit, but auditor could edit too

        const newRemark = prompt('Edit Remark:', currentRemark);
        if (newRemark === null || newRemark === currentRemark) return; // Cancelled or no change

        const activeSheets = viewingStatement ? viewingSheets : (parsedWorkbook?.sheets || []);
        const activeIdx = viewingStatement ? viewingSheetIndex : activeSheetIndex;
        const currentSheet = activeSheets[activeIdx];
        if (!currentSheet) return;

        const newRows = [...currentSheet.rows];
        newRows[rowIdx] = {
            ...newRows[rowIdx],
            Remarks: newRemark
        };

        const newSheet = {
            ...currentSheet,
            rows: newRows
        };

        if (viewingStatement) {
            const newViewingSheets = [...viewingSheets];
            newViewingSheets[activeIdx] = newSheet;
            setViewingSheets(newViewingSheets);

            // Persist to Firestore
            try {
                if (!newSheet.id) throw new Error("Sheet ID is missing.");
                await BankReconService.updateSheetData(viewingStatement.id!, newSheet.id, newRows);
            } catch (err) {
                console.error('Failed to update remark:', err);
                alert('Failed to save remark to database.');
                // Revert locally on error
                newRows[rowIdx].Remarks = currentRemark;
                newViewingSheets[activeIdx] = { ...currentSheet, rows: newRows };
                setViewingSheets([...newViewingSheets]);
            }
        } else if (parsedWorkbook) {
            const newSheets = [...parsedWorkbook.sheets];
            newSheets[activeIdx] = newSheet;
            setParsedWorkbook({
                ...parsedWorkbook,
                sheets: newSheets
            });
        }
    };

    // Get summary stats for a sheet
    const getSheetStats = (sheet: ParsedSheet) => {
        const debitCol = sheet.headers.find(h =>
            h.toLowerCase().includes('debit') ||
            h.toLowerCase().includes('withdrawal') ||
            h.toLowerCase().includes('dr')
        );
        const creditCol = sheet.headers.find(h =>
            h.toLowerCase().includes('credit') ||
            h.toLowerCase().includes('deposit') ||
            h.toLowerCase().includes('cr')
        );
        const dateCol = sheet.headers.find(h =>
            h.toLowerCase().includes('date') ||
            h.toLowerCase().includes('posting') ||
            h.toLowerCase().includes('value')
        );

        let totalDebit = 0;
        let totalCredit = 0;
        const dates: string[] = [];

        sheet.rows.forEach(row => {
            if (debitCol && typeof row[debitCol] === 'number') totalDebit += row[debitCol] as number;
            if (creditCol && typeof row[creditCol] === 'number') totalCredit += row[creditCol] as number;
            if (dateCol && row[dateCol]) dates.push(String(row[dateCol]));
        });

        const sortedDates = dates.filter(Boolean).sort();
        return {
            totalRows: sheet.rows.length,
            totalDebit,
            totalCredit,
            debitCol,
            creditCol,
            dateRange: sortedDates.length > 0
                ? { start: sortedDates[0], end: sortedDates[sortedDates.length - 1] }
                : null,
        };
    };

    // Determine which sheets to render
    const activeSheets = viewingStatement ? viewingSheets : (parsedWorkbook?.sheets || []);
    const activeIdx = viewingStatement ? viewingSheetIndex : activeSheetIndex;
    const setActiveIdx = viewingStatement ? setViewingSheetIndex : setActiveSheetIndex;
    const currentSheet = activeSheets[activeIdx];

    // Check if a column represents currency
    const isCurrencyColumn = (header: string): boolean => {
        const h = header.toLowerCase();
        return ['debit', 'credit', 'amount', 'balance', 'withdrawal', 'deposit', 'dr', 'cr'].some(term => h.includes(term));
    };

    // Check if a value is numeric for right-alignment
    const isNumericColumn = (sheet: ParsedSheet, header: string): boolean => {
        const sample = sheet.rows.slice(0, 10);
        const numericCount = sample.filter(row => typeof row[header] === 'number').length;
        return numericCount > sample.length * 0.5;
    };

    const formatCurrency = (val: number) =>
        new Intl.NumberFormat('en-PH', {
            style: 'currency',
            currency: 'PHP',
            minimumFractionDigits: 2,
        }).format(val);

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-slate-900 dark:text-white">Bank Reconciliation</h1>
                    <p className="text-slate-500 dark:text-slate-400 text-sm">Upload and parse multi-sheet bank statements for reconciliation.</p>
                </div>
                {parsedWorkbook && !viewingStatement && (
                    <div className="flex items-center gap-2">
                        <button
                            onClick={handleGenerateReport}
                            disabled={generating}
                            className="bg-blue-600 hover:bg-blue-700 disabled:opacity-50 text-white px-3 py-2 rounded-lg font-medium flex items-center gap-2 transition-colors text-sm"
                        >
                            {generating ? <div className="bank-recon-spinner w-4 h-4" /> : <Settings size={16} />}
                            {generating ? 'Generating...' : 'Generate Match'}
                        </button>
                        <button
                            onClick={() => handleExportCSV(parsedWorkbook.sheets, activeSheetIndex)}
                            className="bg-emerald-600 hover:bg-emerald-700 text-white px-3 py-2 rounded-lg font-medium flex items-center gap-2 transition-colors text-sm"
                        >
                            <Download size={16} />
                            Export Sheet
                        </button>
                        <button
                            onClick={handleSaveDraft}
                            disabled={saving}
                            className="bg-slate-600 hover:bg-slate-700 disabled:opacity-50 text-white px-4 py-2 rounded-lg font-medium flex items-center gap-2 transition-colors text-sm"
                        >
                            {saving ? <div className="bank-recon-spinner w-4 h-4" /> : <Save size={16} />}
                            Save Draft
                        </button>
                        <button
                            onClick={handleSubmitAudit}
                            disabled={saving}
                            className="bg-purple-600 hover:bg-purple-700 disabled:opacity-50 text-white px-4 py-2 rounded-lg font-medium flex items-center gap-2 transition-colors text-sm"
                        >
                            {saving ? <div className="bank-recon-spinner w-4 h-4" /> : <Send size={16} />}
                            Submit for Audit
                        </button>
                        <button
                            onClick={clearUpload}
                            className="bg-slate-200 dark:bg-slate-700 hover:bg-slate-300 dark:hover:bg-slate-600 text-slate-700 dark:text-slate-300 px-3 py-2 rounded-lg font-medium flex items-center gap-2 transition-colors text-sm"
                        >
                            <X size={16} />
                            Clear
                        </button>
                    </div>
                )}
                {viewingStatement && (
                    <div className="flex items-center gap-2">
                        <button
                            onClick={handleGenerateReport}
                            disabled={generating}
                            className="bg-blue-600 hover:bg-blue-700 disabled:opacity-50 text-white px-3 py-2 rounded-lg font-medium flex items-center gap-2 transition-colors text-sm"
                        >
                            {generating ? <div className="bank-recon-spinner w-4 h-4" /> : <Settings size={16} />}
                            {generating ? 'Generating...' : 'Generate Match'}
                        </button>
                        <button
                            onClick={() => handleExportCSV(viewingSheets, viewingSheetIndex)}
                            className="bg-emerald-600 hover:bg-emerald-700 text-white px-3 py-2 rounded-lg font-medium flex items-center gap-2 transition-colors text-sm"
                        >
                            <Download size={16} />
                            Export Sheet
                        </button>
                        {(viewingStatement.status === 'PENDING_MATCH' || !viewingStatement.status) && (
                            <button
                                onClick={handleSubmitAudit}
                                disabled={saving}
                                className="bg-purple-600 hover:bg-purple-700 disabled:opacity-50 text-white px-4 py-2 rounded-lg font-medium flex items-center gap-2 transition-colors text-sm"
                            >
                                {saving ? <div className="bank-recon-spinner w-4 h-4" /> : <Send size={16} />}
                                Submit for Audit
                            </button>
                        )}
                        {viewingStatement.status === 'PENDING_AUDIT' && canAudit && (
                            <>
                                <button
                                    onClick={handleSaveAuditProgress}
                                    disabled={saving}
                                    className="bg-slate-600 hover:bg-slate-700 disabled:opacity-50 text-white px-4 py-2 rounded-lg font-medium flex items-center gap-2 transition-colors text-sm"
                                >
                                    {saving ? <div className="bank-recon-spinner w-4 h-4" /> : <Save size={16} />}
                                    Save Progress
                                </button>
                                <button
                                    onClick={handleMarkAudited}
                                    disabled={saving}
                                    className="bg-emerald-600 hover:bg-emerald-700 disabled:opacity-50 text-white px-4 py-2 rounded-lg font-medium flex items-center gap-2 transition-colors text-sm"
                                >
                                    {saving ? <div className="bank-recon-spinner w-4 h-4" /> : <CheckCircle size={16} />}
                                    Mark Audited
                                </button>
                            </>
                        )}
                        <button
                            onClick={closeViewStatement}
                            className="bg-slate-200 dark:bg-slate-700 hover:bg-slate-300 dark:hover:bg-slate-600 text-slate-700 dark:text-slate-300 px-3 py-2 rounded-lg font-medium flex items-center gap-2 transition-colors text-sm"
                        >
                            <X size={16} />
                            Close
                        </button>
                    </div>
                )}
            </div>

            {/* Main View Layout */}
            {!parsedWorkbook && !viewingStatement ? (
                /* Bento Grid Layout for Empty State */
                <div className="grid grid-cols-1 xl:grid-cols-3 gap-6">
                    {/* Left Col: Upload Zone */}
                    <div className="xl:col-span-2">
                        <div className="recon-glass-panel p-2">
                            <div
                                className={`bank-recon-upload-zone ${isDragging ? 'dragging' : ''} ${uploadedFile ? 'has-file' : ''}`}
                                onDrop={handleDrop}
                                onDragOver={handleDragOver}
                                onDragLeave={handleDragLeave}
                                onClick={handleClickUpload}
                            >
                                <input
                                    ref={fileInputRef}
                                    type="file"
                                    accept=".xlsx,.xls,.csv"
                                    onChange={handleInputChange}
                                    className="hidden"
                                />
                                {parsing ? (
                                    <div className="flex flex-col items-center gap-4">
                                        <div className="bank-recon-spinner w-10 h-10 border-4 border-purple-500/30 border-t-purple-500" />
                                        <p className="text-slate-600 dark:text-slate-300 font-medium text-lg">
                                            Parsing <span className="text-gradient-primary font-bold">{uploadedFile?.name}</span>...
                                        </p>
                                    </div>
                                ) : uploadedFile ? (
                                    <div className="flex flex-col items-center gap-3">
                                        <div className="p-4 bg-emerald-100 dark:bg-emerald-900/30 rounded-2xl mb-2">
                                            <FileSpreadsheet className="w-12 h-12 text-emerald-600 dark:text-emerald-400" />
                                        </div>
                                        <p className="text-xl font-bold text-slate-900 dark:text-white">{uploadedFile.name}</p>
                                        <p className="text-slate-500 dark:text-slate-400 font-medium">Ready to process</p>
                                    </div>
                                ) : (
                                    <div className="flex flex-col items-center gap-4">
                                        <div className="p-5 bg-white shadow-xl dark:bg-slate-800 rounded-2xl mb-2 bank-recon-upload-icon-container">
                                            <Upload className="w-10 h-10 text-purple-600 dark:text-purple-400" />
                                        </div>
                                        <h3 className="text-2xl font-bold text-slate-900 dark:text-white">Upload Bank Statement</h3>
                                        <p className="text-slate-500 dark:text-slate-400 max-w-sm mx-auto">
                                            Drag and drop your Excel file here, or click to browse. Supports <span className="font-semibold text-slate-700 dark:text-slate-300">.xlsx</span> and <span className="font-semibold text-slate-700 dark:text-slate-300">.xls</span>.
                                        </p>
                                    </div>
                                )}
                            </div>
                            {parseError && (
                                <div className="mt-4 p-4 rounded-xl bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800/50 flex items-start gap-3">
                                    <AlertTriangle className="text-red-500 mt-0.5 flex-shrink-0" size={18} />
                                    <div>
                                        <h4 className="text-red-800 dark:text-red-300 font-semibold mb-1">Parse Error</h4>
                                        <p className="text-red-600 dark:text-red-400 text-sm">{parseError}</p>
                                    </div>
                                </div>
                            )}
                        </div>
                    </div>

                    {/* Right Col: History */}
                    <div className="xl:col-span-1">
                        <div className="recon-glass-panel flex flex-col h-full max-h-[600px]">
                            <div className="p-4 border-b border-slate-200 dark:border-slate-700/50 flex flex-col gap-4">
                                <div className="flex items-center justify-between">
                                    <h2 className="text-lg font-bold text-slate-900 dark:text-white flex items-center gap-2">
                                        <Clock size={18} className="text-purple-500" />
                                        Statements
                                    </h2>
                                    {(canViewAll || (currentUser?.businessUnitIds && currentUser.businessUnitIds.length > 1)) && (
                                        <select
                                            value={selectedBuFilter}
                                            onChange={(e) => setSelectedBuFilter(e.target.value)}
                                            className="px-3 py-1 border border-slate-200 dark:border-slate-700 rounded-lg text-xs bg-white dark:bg-slate-800 text-slate-800 dark:text-white focus:ring-2 focus:ring-purple-500 shadow-sm"
                                        >
                                            <option value="my">My Business Units</option>
                                            {canViewAll && <option value="all">All Business Units</option>}
                                            {canViewAll ? (
                                                businesses.map(b => <option key={b.id} value={b.id}>{b.name}</option>)
                                            ) : (
                                                currentUser?.businessUnitIds?.map(buId => {
                                                    const b = businesses.find(bz => bz.id === buId);
                                                    return b ? <option key={b.id} value={b.id}>{b.name}</option> : null;
                                                })
                                            )}
                                        </select>
                                    )}
                                </div>
                                <div className="flex items-center gap-1 p-1 bg-slate-100 dark:bg-slate-800/50 rounded-lg">
                                    <button
                                        onClick={() => setListTab('ACTIVE')}
                                        className={`flex-1 px-3 py-1.5 text-sm font-medium rounded-md transition-colors ${listTab === 'ACTIVE'
                                            ? 'bg-white dark:bg-slate-700 text-slate-900 dark:text-white shadow-sm'
                                            : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-300'
                                            }`}
                                    >
                                        Active
                                    </button>
                                    <button
                                        onClick={() => setListTab('HISTORY')}
                                        className={`flex-1 px-3 py-1.5 text-sm font-medium rounded-md transition-colors ${listTab === 'HISTORY'
                                            ? 'bg-white dark:bg-slate-700 text-slate-900 dark:text-white shadow-sm'
                                            : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-300'
                                            }`}
                                    >
                                        History
                                    </button>
                                </div>
                            </div>
                            <div className="p-4 overflow-y-auto flex-1 space-y-3">
                                {loadingHistory ? (
                                    <div className="flex flex-col items-center justify-center h-40 gap-3">
                                        <div className="bank-recon-spinner border-slate-300 border-t-purple-500" />
                                        <span className="text-slate-500 dark:text-slate-400 text-sm font-medium">Loading history...</span>
                                    </div>
                                ) : (() => {
                                    const displayedListStatements = filteredStatements.filter(stmt => {
                                        if (listTab === 'HISTORY') return stmt.status === 'COMPLETED';
                                        return stmt.status !== 'COMPLETED';
                                    });

                                    if (displayedListStatements.length === 0) {
                                        return (
                                            <div className="flex flex-col items-center justify-center text-center h-40 px-4">
                                                <Layers size={32} className="text-slate-300 dark:text-slate-600 mb-3" />
                                                <p className="text-slate-500 dark:text-slate-400 text-sm">
                                                    {listTab === 'HISTORY' ? 'No completed statements yet.' : 'No active statements.'}
                                                </p>
                                            </div>
                                        );
                                    }

                                    return displayedListStatements.map(stmt => (
                                        <div
                                            key={stmt.id}
                                            className="bank-recon-history-item group"
                                            onClick={() => handleViewStatement(stmt)}
                                        >
                                            <div className="flex items-start gap-3 w-full">
                                                <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-indigo-50 to-purple-50 dark:from-indigo-900/30 dark:to-purple-900/30 flex items-center justify-center flex-shrink-0 border border-indigo-100 dark:border-indigo-800/50">
                                                    <FileSpreadsheet size={18} className="text-indigo-600 dark:text-indigo-400" />
                                                </div>
                                                <div className="flex-1 min-w-0">
                                                    <p className="text-sm font-bold text-slate-900 dark:text-white truncate pr-2 group-hover:text-purple-600 dark:group-hover:text-purple-400 transition-colors">
                                                        {stmt.fileName}
                                                    </p>
                                                    <div className="flex items-center gap-2 mt-1 text-xs text-slate-500 dark:text-slate-400">
                                                        <span className={`px-2 py-0.5 rounded border text-[10px] font-bold tracking-wider ${stmt.status === 'COMPLETED' ? 'bg-emerald-100/50 text-emerald-700 border-emerald-200 dark:bg-emerald-900/30 dark:text-emerald-400 dark:border-emerald-800' :
                                                            stmt.status === 'PENDING_AUDIT' ? 'bg-blue-100/50 text-blue-700 border-blue-200 dark:bg-blue-900/30 dark:text-blue-400 dark:border-blue-800' :
                                                                'bg-slate-100/50 text-slate-700 border-slate-200 dark:bg-slate-800 dark:text-slate-400 dark:border-slate-700'
                                                            }`}>
                                                            {stmt.status?.replace('_', ' ') || 'PENDING MATCH'}
                                                        </span>
                                                        <span>{stmt.totalRows} rows</span>
                                                        <span className="w-1 h-1 rounded-full bg-slate-300 dark:bg-slate-600"></span>
                                                        <span>{new Date(stmt.uploadedAt).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}</span>
                                                    </div>
                                                </div>
                                                <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                                    <button
                                                        onClick={(e) => handleDelete(stmt.id!, e)}
                                                        className="p-1.5 text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/30 rounded-lg transition-colors"
                                                        title="Delete"
                                                    >
                                                        <Trash2 size={16} />
                                                    </button>
                                                </div>
                                            </div>
                                        </div>
                                    ));
                                })()}
                            </div>
                        </div>
                    </div>
                </div>
            ) : (
                /* Detail View Layout (When viewing statement or parsed workbook) */
                <div className="space-y-6">
                    {/* Viewing banner for saved statements */}
                    {viewingStatement && (
                        <div className="recon-glass-panel p-5">
                            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                                <div className="flex items-center gap-4">
                                    <div className="w-12 h-12 rounded-xl bg-gradient-to-br from-purple-500 to-indigo-600 flex items-center justify-center shadow-lg shadow-purple-500/20">
                                        <FileSpreadsheet size={24} className="text-white" />
                                    </div>
                                    <div>
                                        <h2 className="text-xl font-bold text-slate-900 dark:text-white leading-tight flex items-center gap-3">
                                            {viewingStatement.fileName}
                                            <span className={`px-2 py-0.5 rounded border text-xs font-bold tracking-wider ${viewingStatement.status === 'COMPLETED' ? 'bg-emerald-100/50 text-emerald-700 border-emerald-200 dark:bg-emerald-900/30 dark:text-emerald-400 dark:border-emerald-800' :
                                                viewingStatement.status === 'PENDING_AUDIT' ? 'bg-blue-100/50 text-blue-700 border-blue-200 dark:bg-blue-900/30 dark:text-blue-400 dark:border-blue-800' :
                                                    'bg-slate-100/50 text-slate-700 border-slate-200 dark:bg-slate-800 dark:text-slate-400 dark:border-slate-700'
                                                }`}>
                                                {viewingStatement.status?.replace('_', ' ') || 'PENDING MATCH'}
                                            </span>
                                        </h2>
                                        <p className="text-sm text-slate-500 dark:text-slate-400 mt-0.5">
                                            Uploaded by <span className="font-medium text-slate-700 dark:text-slate-300">{viewingStatement.uploadedByName}</span> on {new Date(viewingStatement.uploadedAt).toLocaleDateString()}
                                            <span className="mx-2 opacity-50">•</span>
                                            {viewingStatement.totalRows} rows across {viewingStatement.sheetCount} sheet{viewingStatement.sheetCount > 1 ? 's' : ''}
                                        </p>
                                    </div>
                                </div>
                            </div>
                        </div>
                    )}

                    {/* Sheet Tabs + Data Table */}
                    {activeSheets.length > 0 && !loadingView && (
                        <div className="space-y-6">
                            {/* Summary Stats */}
                            {currentSheet && currentSheet.rows.length > 0 && (() => {
                                const stats = getSheetStats(currentSheet);
                                return (
                                    <div className="bank-recon-summary">
                                        <div className="bank-recon-stat">
                                            <div className="bank-recon-stat-label"><Hash size={14} className="inline mr-1.5 text-slate-400" />Total Rows</div>
                                            <div className="bank-recon-stat-value">{stats.totalRows.toLocaleString()}</div>
                                        </div>
                                        {stats.dateRange && (
                                            <div className="bank-recon-stat">
                                                <div className="bank-recon-stat-label"><Calendar size={14} className="inline mr-1.5 text-slate-400" />Date Range</div>
                                                <div className="bank-recon-stat-value text-xl mt-1">{stats.dateRange.start} <span className="text-slate-300 mx-1">—</span> {stats.dateRange.end}</div>
                                            </div>
                                        )}
                                        {stats.debitCol && stats.totalDebit > 0 && (
                                            <div className="bank-recon-stat">
                                                <div className="bank-recon-stat-label"><ArrowDownRight size={14} className="inline mr-1.5 text-red-400" />Total Debit</div>
                                                <div className="bank-recon-stat-value debit">{formatCurrency(stats.totalDebit)}</div>
                                            </div>
                                        )}
                                        {stats.creditCol && stats.totalCredit > 0 && (
                                            <div className="bank-recon-stat">
                                                <div className="bank-recon-stat-label"><ArrowUpRight size={14} className="inline mr-1.5 text-emerald-400" />Total Credit</div>
                                                <div className="bank-recon-stat-value credit">{formatCurrency(stats.totalCredit)}</div>
                                            </div>
                                        )}
                                    </div>
                                );
                            })()}

                            {/* Sheet Tabs */}
                            {activeSheets.length > 1 && (
                                <div className="bank-recon-sheet-tabs">
                                    {activeSheets.map((sheet, idx) => (
                                        <button
                                            key={sheet.sheetName}
                                            className={`bank-recon-sheet-tab ${idx === activeIdx ? 'active' : ''}`}
                                            onClick={() => setActiveIdx(idx)}
                                        >
                                            <Layers size={14} className="inline mr-1.5 -mt-0.5" />
                                            {sheet.sheetName}
                                            <span className="ml-1.5 text-xs opacity-60 bg-slate-100 dark:bg-slate-800 px-1.5 py-0.5 rounded-md">
                                                {sheet.rows.length}
                                            </span>
                                        </button>
                                    ))}
                                </div>
                            )}

                            {/* Data Table */}
                            {currentSheet && currentSheet.rows.length > 0 ? (
                                <div className="bank-recon-table-container">
                                    <table className="bank-recon-table">
                                        <thead>
                                            <tr>
                                                <th className="!text-center" style={{ width: 50 }}>#</th>
                                                {(!viewingStatement || viewingStatement.status === 'PENDING_AUDIT') && (
                                                    <th className="!text-center" style={{ width: 140 }}>Audit</th>
                                                )}
                                                {currentSheet.headers.map(header => (
                                                    <th key={header}>{header}</th>
                                                ))}
                                            </tr>
                                        </thead>
                                        <tbody>
                                            {currentSheet.rows.map((row, rowIdx) => {
                                                const rowAuditStatus = (row.auditStatus as RowAuditStatus) || (row['Cleared'] ? 'APPROVED' : 'PENDING');
                                                const isUploader = viewingStatement && viewingStatement.uploadedBy === currentUser?.id;

                                                return (
                                                <tr key={rowIdx} className={rowAuditStatus === 'REJECTED' ? 'audit-row-rejected' : rowAuditStatus === 'APPROVED' ? 'audit-row-approved' : ''}>
                                                    <td className="!text-center text-slate-400 dark:text-slate-600 text-xs font-mono">{rowIdx + 1}</td>
                                                    {(!viewingStatement || viewingStatement.status === 'PENDING_AUDIT') && (
                                                        <td className="!text-center">
                                                            <div className="audit-cell">
                                                                {/* Status badge */}
                                                                {rowAuditStatus === 'APPROVED' && (
                                                                    <span className="audit-badge audit-badge-approved" title="Approved">
                                                                        <CheckCircle2 size={14} /> Approved
                                                                    </span>
                                                                )}
                                                                {rowAuditStatus === 'REJECTED' && (
                                                                    <span className="audit-badge audit-badge-rejected" title={`Rejected: ${row.rejectionReason || ''}`}>
                                                                        <XCircle size={14} /> Rejected
                                                                    </span>
                                                                )}
                                                                {rowAuditStatus === 'PENDING' && (
                                                                    <span className="audit-badge audit-badge-pending">
                                                                        Pending
                                                                    </span>
                                                                )}
                                                                {/* Action buttons */}
                                                                <div className="audit-actions">
                                                                    {canAudit && rowAuditStatus !== 'APPROVED' && (
                                                                        <button
                                                                            onClick={() => handleAuditApprove(rowIdx)}
                                                                            className="audit-btn audit-btn-approve"
                                                                            title="Approve"
                                                                        >
                                                                            <CheckCircle size={14} />
                                                                        </button>
                                                                    )}
                                                                    {canAudit && rowAuditStatus !== 'REJECTED' && (
                                                                        <button
                                                                            onClick={() => handleAuditReject(rowIdx)}
                                                                            className="audit-btn audit-btn-reject"
                                                                            title="Reject"
                                                                        >
                                                                            <XCircle size={14} />
                                                                        </button>
                                                                    )}
                                                                    {rowAuditStatus === 'REJECTED' && isUploader && (
                                                                        <button
                                                                            onClick={() => handleRefileRow(rowIdx)}
                                                                            className="audit-btn audit-btn-refile"
                                                                            title="Refile (reset to pending)"
                                                                        >
                                                                            <RefreshCw size={14} />
                                                                        </button>
                                                                    )}
                                                                </div>
                                                            </div>
                                                        </td>
                                                    )}
                                                    {currentSheet.headers.map(header => {
                                                        const value = row[header];
                                                        const isNum = isNumericColumn(currentSheet, header);
                                                        const isCurrency = isCurrencyColumn(header);
                                                        const isCheck = header.toLowerCase().includes('check') || header.toLowerCase().includes('chk');

                                                        let displayValue: React.ReactNode = <span className="text-slate-300 dark:text-slate-700">—</span>;

                                                        if (header === 'Remarks') {
                                                            const remarks = (value !== null && value !== undefined) ? String(value) : '';
                                                            const isEditable = (!viewingStatement || viewingStatement.status !== 'COMPLETED') && canEdit;

                                                            let badge = <span className="text-slate-300 dark:text-slate-600 italic">No remark</span>;
                                                            if (remarks) {
                                                                if (remarks.includes('Partial Match')) {
                                                                    badge = <span className="inline-flex items-center px-2 py-1 rounded-md text-xs font-semibold bg-yellow-100/80 text-yellow-800 border border-yellow-200 dark:border-yellow-900/50 dark:bg-yellow-900/30 dark:text-yellow-400"><AlertTriangle size={12} className="mr-1.5 flex-shrink-0" /> {remarks}</span>;
                                                                } else if (remarks === 'Unidentified Transaction') {
                                                                    badge = <span className="inline-flex items-center px-2 py-1 rounded-md text-xs font-semibold bg-slate-100/80 text-slate-700 border border-slate-200 dark:border-slate-700 dark:bg-slate-800/80 dark:text-slate-300"><AlertCircle size={12} className="mr-1.5 flex-shrink-0" /> {remarks}</span>;
                                                                } else {
                                                                    badge = <span className="inline-flex items-center px-2 py-1 rounded-md text-xs font-semibold bg-emerald-100/80 text-emerald-800 border border-emerald-200 dark:border-emerald-900/50 dark:bg-emerald-900/30 dark:text-emerald-400"><CheckCircle2 size={12} className="mr-1.5 flex-shrink-0" /> {remarks}</span>;
                                                                }
                                                            }

                                                            displayValue = (
                                                                <div className="flex items-center gap-2">
                                                                    {badge}
                                                                    {isEditable && (
                                                                        <button
                                                                            onClick={() => handleEditRemark(rowIdx, remarks)}
                                                                            className="p-1 rounded-md text-slate-400 hover:text-blue-600 hover:bg-blue-50 dark:hover:text-blue-400 dark:hover:bg-blue-900/30 transition-colors"
                                                                            title="Edit Remark"
                                                                        >
                                                                            <Edit2 size={14} />
                                                                        </button>
                                                                    )}
                                                                </div>
                                                            );
                                                        } else if (header === 'Linked Chart of Accounts') {
                                                            const coaVal = (value !== null && value !== undefined) ? String(value) : '';
                                                            const isCoaEditable = (!viewingStatement || viewingStatement.status !== 'COMPLETED') && canEdit;

                                                            displayValue = (
                                                                <div className="coa-cell" style={{ position: 'relative' }}>
                                                                    {coaVal ? (
                                                                        <span className="inline-flex items-center px-2 py-1 rounded-md text-xs font-semibold border border-indigo-100 dark:border-indigo-500/20 bg-indigo-50/50 dark:bg-indigo-500/10 text-indigo-700 dark:text-indigo-300 shadow-sm">
                                                                            <Layers size={12} className="mr-1.5 text-indigo-400 flex-shrink-0" /> {coaVal}
                                                                        </span>
                                                                    ) : (
                                                                        <span className="text-slate-300 dark:text-slate-600 italic">No COA</span>
                                                                    )}
                                                                    {isCoaEditable && (
                                                                        <button
                                                                            onClick={() => setCoaDropdownRow(coaDropdownRow === rowIdx ? null : rowIdx)}
                                                                            className="p-1 rounded-md text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 dark:hover:text-indigo-400 dark:hover:bg-indigo-900/30 transition-colors ml-1"
                                                                            title="Edit Chart of Account"
                                                                        >
                                                                            <Edit2 size={14} />
                                                                        </button>
                                                                    )}
                                                                    {coaDropdownRow === rowIdx && (
                                                                        <div className="coa-dropdown">
                                                                            <div className="coa-dropdown-header flex flex-col gap-2">
                                                                                <span>Select Account</span>
                                                                                <input 
                                                                                    type="text" 
                                                                                    autoFocus
                                                                                    placeholder="Search account..." 
                                                                                    value={coaSearchTerm}
                                                                                    onChange={e => setCoaSearchTerm(e.target.value)}
                                                                                    onClick={e => e.stopPropagation()}
                                                                                    className="w-full px-2 py-1 text-xs border border-slate-200 dark:border-slate-600 rounded bg-white dark:bg-slate-700 text-slate-800 dark:text-white"
                                                                                />
                                                                            </div>
                                                                            <div className="coa-dropdown-list">
                                                                                {coaAccounts
                                                                                    .filter(coa => 
                                                                                        coa.code.toLowerCase().includes(coaSearchTerm.toLowerCase()) || 
                                                                                        coa.name.toLowerCase().includes(coaSearchTerm.toLowerCase())
                                                                                    )
                                                                                    .map(coa => (
                                                                                    <button
                                                                                        key={coa.code}
                                                                                        className="coa-dropdown-item"
                                                                                        onClick={() => {
                                                                                            handleEditCoa(rowIdx, coa);
                                                                                            setCoaSearchTerm('');
                                                                                        }}
                                                                                    >
                                                                                        <span className="font-mono text-xs text-indigo-600 dark:text-indigo-400">{coa.code}</span>
                                                                                        <span className="text-xs">{coa.name}</span>
                                                                                    </button>
                                                                                ))}
                                                                            </div>
                                                                        </div>
                                                                    )}
                                                                </div>
                                                            );
                                                        } else if (value !== null && value !== undefined && value !== '') {
                                                            if (isCurrency && typeof value === 'number') {
                                                                displayValue = value.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
                                                            } else if (isCheck) {
                                                                // Strip commas explicitly from check numbers per user request
                                                                displayValue = String(value).replace(/,/g, '');
                                                            } else {
                                                                displayValue = String(value);
                                                            }
                                                        }

                                                        return (
                                                            <td
                                                                key={header}
                                                                className={isNum ? 'numeric' : ''}
                                                                title={value !== null ? String(value) : ''}
                                                            >
                                                                {displayValue}
                                                            </td>
                                                        );
                                                    })}
                                                </tr>
                                                );
                                            })}
                                        </tbody>
                                    </table>
                                </div>
                            ) : currentSheet ? (
                                <div className="recon-glass-panel flex flex-col items-center justify-center py-16 px-4">
                                    <AlertCircle size={48} className="text-slate-300 dark:text-slate-600 mb-4" />
                                    <h3 className="text-lg font-semibold text-slate-700 dark:text-slate-300">No Data Found</h3>
                                    <p className="text-slate-500 mt-1">Sheet "{currentSheet.sheetName}" is empty.</p>
                                </div>
                            ) : null}
                        </div>
                    )}

                    {loadingView && (
                        <div className="recon-glass-panel py-20 flex flex-col items-center justify-center">
                            <div className="bank-recon-spinner border-slate-300 border-t-purple-500 w-12 h-12 mb-4" />
                            <span className="text-slate-600 dark:text-slate-400 font-medium">Loading statement data...</span>
                        </div>
                    )}
                </div>
            )}
        </div>
    );
};

export default BankReconView;

import React, { useState, useMemo, useEffect } from 'react';
import { useSearchParams } from 'react-router-dom';
import type { Requisition } from '../../procurement/types';
import { RequisitionStatus, isSuperAdmin } from '../../procurement/types';
import type { User, Business } from '../../../shared/types';
import Card from '../../../shared/components/Card';
import ReleaseFundModal from '../components/ReleaseFundModal';
import CheckPrepModal from '../components/CheckPrepModal';
import RequisitionDrawer from '../../../shared/components/RequisitionDrawer';
import RejectionModal from '../../../shared/components/RejectionModal';
import { ExternalLink, Search, Wallet, CheckCircle, XCircle, FileText, Printer, Download } from 'lucide-react';
import { exportToCSV, formatDateForExport, formatCurrencyForExport, type ExportColumn } from '../../../shared/utils/exportUtils';
import { usePermissions } from '../../../hooks/usePermissions';
import { useBusinessUnit } from '../../../contexts/BusinessUnitContext';
import { PCFService, PCFStatus, type PCFLiquidation } from '../services/pcf.service';
import { RequisitionService } from '../../procurement/services/requisitions.service';
import { DateRangeFilter } from '../../../shared/components/DateRangeFilter';
import { executeWorkflowAction } from '../../procurement/services/workflowService';
import { SettingsService } from '../../../shared/services/settings.service';
import type { ApproverAssignments } from '../../../shared/services/settings.service';
import PRFPrintModal from '../../procurement/components/PRFPrintModal';
import SignatureModal from '../../../shared/components/SignatureModal';
import { SignatureService } from '../../../shared/services/signature.service';

interface FinanceViewProps {
    currentUser: User;
    requisitions: Requisition[];
    getStatusBadge: (status: RequisitionStatus) => React.ReactNode;
    handleReleaseFunds: (id: string, checkVoucherNumber: string, checkVoucherLink?: string, coaCode?: string) => void;
    businesses: Business[];
    allUsers: User[];
}

export const FinanceView: React.FC<FinanceViewProps> = ({
    currentUser,
    requisitions,
    getStatusBadge,
    handleReleaseFunds,
    businesses,
    allUsers
}) => {
    const [searchParams] = useSearchParams();
    const initialTab = (searchParams.get('tab') as any) || 'br_pending';

    const [isReleaseModalOpen, setReleaseModalOpen] = useState(false);
    const [isCheckPrepModalOpen, setCheckPrepModalOpen] = useState(false);
    const [selectedReq, setSelectedReq] = useState<Requisition | null>(null);
    const [activeTab, setActiveTab] = useState<'prf_pending' | 'prf_released' | 'pcf_pending' | 'pcf_released' | 'br_pending' | 'check_prep' | 'check_pending'>(initialTab);
    const [drawerReq, setDrawerReq] = useState<Requisition | null>(null);
    const [searchTerm, setSearchTerm] = useState('');
    const [pcfLiquidations, setPcfLiquidations] = useState<PCFLiquidation[]>([]);
    const [dateRange, setDateRange] = useState<{ start: string | null; end: string | null }>({ start: null, end: null });
    const [rejectingReq, setRejectingReq] = useState<Requisition | null>(null);
    const [printReq, setPrintReq] = useState<Requisition | null>(null);
    const { selectedBusinessUnit } = useBusinessUnit(); // Global BU context
    const { hasPermission } = usePermissions();
    const [approverAssignments, setApproverAssignments] = useState<ApproverAssignments>({});
    const [signingReq, setSigningReq] = useState<Requisition | null>(null);
    const [signatureLoading, setSignatureLoading] = useState(false);

    // Fetch approver assignments for BU-specific checks
    useEffect(() => {
        SettingsService.getApproverAssignments().then(setApproverAssignments);
    }, []);

    // Helper function to filter requisitions by search term and BU
    const applyFilters = (reqs: Requisition[]) => {
        let filtered = reqs;

        // Apply BU filter using global context
        if (selectedBusinessUnit !== 'all') {
            filtered = filtered.filter(req => req.businessId === selectedBusinessUnit);
        }

        // Apply search filter
        if (searchTerm.trim()) {
            const term = searchTerm.toLowerCase();
            filtered = filtered.filter(req =>
                req.id.toLowerCase().includes(term) ||
                req.description?.toLowerCase().includes(term) ||
                businesses.find(b => b.id === req.businessId)?.name.toLowerCase().includes(term) ||
                allUsers.find(u => u.id === req.requesterId)?.name.toLowerCase().includes(term)
            );
        }

        // Date Filter
        if (dateRange.start && dateRange.end) {
            const start = new Date(dateRange.start);
            const end = new Date(dateRange.end);
            end.setHours(23, 59, 59, 999);

            filtered = filtered.filter(req => {
                const reqDate = new Date(req.dateCreated);
                return reqDate >= start && reqDate <= end;
            });
        }

        return filtered;
    };

    // Approve handler for BR and Check Auth items
    const handleApprove = async (req: Requisition, e: React.MouseEvent) => {
        e.stopPropagation();
        // BOD users skip signature modal — approve directly
        if (hasPermission('procurement:approval:approve:skip_signature')) {
            try {
                await RequisitionService.approveRequisition(
                    req.id, currentUser.id, currentUser.name, undefined, undefined
                );
                if (drawerReq?.id === req.id) setDrawerReq(null);
            } catch (error: unknown) {
                const message = error instanceof Error ? error.message : 'Unknown error';
                console.error('Error approving:', error);
                alert(`Failed to approve: ${message}`);
            }
            return;
        }
        setSigningReq(req);
    };

    const handleSignatureConfirm = async (signatureBlob: Blob) => {
        if (!signingReq) return;
        setSignatureLoading(true);
        try {
            const signatureUrl = await SignatureService.uploadSignature(
                signingReq.id,
                currentUser.id,
                signatureBlob
            );
            await RequisitionService.approveRequisition(
                signingReq.id,
                currentUser.id,
                currentUser.name,
                undefined,
                signatureUrl
            );
            setSigningReq(null);
            if (drawerReq?.id === signingReq.id) setDrawerReq(null);
        } catch (error: unknown) {
            console.error('Error approving:', error);
            const message = error instanceof Error ? error.message : 'Unknown error';
            alert(`Failed to approve: ${message}`);
        } finally {
            setSignatureLoading(false);
        }
    };

    // Reject handler for BR and Check Auth items
    const handleRejectClick = (req: Requisition, e: React.MouseEvent) => {
        e.stopPropagation();
        setRejectingReq(req);
    };

    const handleRejectConfirm = async (reason: string) => {
        if (rejectingReq) {
            try {
                await RequisitionService.rejectRequisition(
                    rejectingReq.id,
                    currentUser.id,
                    currentUser.name,
                    reason
                );
                setRejectingReq(null);
            } catch (error: unknown) {
                console.error('Error rejecting:', error);
                const message = error instanceof Error ? error.message : 'Unknown error';
                alert(`Failed to reject: ${message}`);
            }
        }
    };

    // Allow Super Admin AND Finance role (or anyone with finance:release_funds implicitly via role check)
    // In types.ts, hasGlobalAccess is strict to Super Admin.


    const handleRelease = (req: Requisition) => {
        setSelectedReq(req);
        setReleaseModalOpen(true);
    };

    const confirmRelease = (checkVoucherNumber: string, checkVoucherLink: string, coaCode: string) => {
        if (selectedReq) {
            handleReleaseFunds(selectedReq.id, checkVoucherNumber, checkVoucherLink, coaCode);
            setReleaseModalOpen(false);
            setSelectedReq(null);
            setDrawerReq(null); // Close drawer after release
        }
    };

    // Load PCF liquidations for PCF tabs
    useEffect(() => {
        if ((activeTab === 'pcf_pending' || activeTab === 'pcf_released') && hasPermission('ui:module_access:view:pcf')) {
            const loadPcfData = async () => {
                const data = await PCFService.getAllLiquidations();
                // Filter to show approved/replenished PCF liquidations
                const pcfData = data.filter(liq =>
                    [PCFStatus.APPROVED, PCFStatus.APPROVED_WAITING_RELEASE, PCFStatus.REPLENISHED].includes(liq.status)
                );
                setPcfLiquidations(pcfData);
            };
            loadPcfData();
        }
    }, [activeTab, hasPermission]);

    // Filter for approved requisitions awaiting fund release
    // Includes both new workflow (FOR_FUND_RELEASE) and legacy (APPROVED_FOR_PAYMENT)
    const pendingReleaseReqs = requisitions.filter(
        req => req.status === RequisitionStatus.FOR_FUND_RELEASE ||
            req.status === RequisitionStatus.APPROVED_FOR_PAYMENT
    );

    // Filter for released requisitions
    const releasedReqs = requisitions.filter(
        req => [
            RequisitionStatus.FUNDS_RELEASED,
            RequisitionStatus.LIQUIDATION_FILED,
            RequisitionStatus.LIQUIDATION_REJECTED,
            RequisitionStatus.AUDITED_CLEARED
        ].includes(req.status)
    ).sort((a, b) => new Date(b.fundReleaseDate || b.timestamp).getTime() - new Date(a.fundReleaseDate || a.timestamp).getTime());

    const displayedReqs = activeTab === 'prf_pending' ? pendingReleaseReqs : releasedReqs;

    // PCF pending vs released
    const pcfPending = pcfLiquidations.filter(liq => liq.status === PCFStatus.APPROVED_WAITING_RELEASE);
    const pcfReleased = pcfLiquidations.filter(liq =>
        [PCFStatus.APPROVED, PCFStatus.REPLENISHED].includes(liq.status)
    );

    // BR (Budget Request) - Finance Head, GM Budget (Steps 3-4)
    // Note: Step 5 (BOD) now feeds into Check Preparation, not directly to Fund Release
    const brPendingReqs = requisitions.filter(req =>
        req.status === RequisitionStatus.PENDING_FINANCE_HEAD_BR_APPROVAL ||
        req.status === RequisitionStatus.PENDING_GM_BR_APPROVAL ||
        req.status === RequisitionStatus.PENDING_BOD_APPROVAL || // Step 5: BOD Approval
        req.status === RequisitionStatus.PENDING_CFO_APPROVAL // Legacy support
    );

    // Check Preparation - Finance uploads check (Step 6)
    const checkPrepReqs = requisitions.filter(req =>
        req.status === RequisitionStatus.FOR_CHECK_PREPARATION
    );

    // Check Authorization - BOD Check Auth (Step 7)
    const checkAuthReqs = requisitions.filter(req =>
        req.status === RequisitionStatus.PENDING_CHECK_AUTH_BOD
    );

    // Apply filters to all requisition lists
    const filteredBrPendingReqs = useMemo(() => applyFilters(brPendingReqs), [brPendingReqs, searchTerm, selectedBusinessUnit, businesses, allUsers, dateRange]);
    const filteredCheckPrepReqs = useMemo(() => applyFilters(checkPrepReqs), [checkPrepReqs, searchTerm, selectedBusinessUnit, businesses, allUsers, dateRange]);
    const filteredCheckAuthReqs = useMemo(() => applyFilters(checkAuthReqs), [checkAuthReqs, searchTerm, selectedBusinessUnit, businesses, allUsers, dateRange]);
    const filteredPcfPending = useMemo(() => {
        let filtered = pcfPending;
        if (selectedBusinessUnit !== 'all') filtered = filtered.filter(liq => liq.businessId === selectedBusinessUnit);
        if (searchTerm.trim()) {
            const term = searchTerm.toLowerCase();
            filtered = filtered.filter(liq =>
                liq.replenishmentPrfId?.toLowerCase().includes(term) ||
                liq.userName?.toLowerCase().includes(term) ||
                businesses.find(b => b.id === liq.businessId)?.name.toLowerCase().includes(term)
            );
        }
        if (dateRange.start && dateRange.end) {
            const start = new Date(dateRange.start);
            const end = new Date(dateRange.end);
            end.setHours(23, 59, 59, 999);
            filtered = filtered.filter(liq => {
                const liqDate = new Date(liq.dateCreated || new Date());
                return liqDate >= start && liqDate <= end;
            });
        }
        return filtered;
    }, [pcfPending, searchTerm, selectedBusinessUnit, businesses, dateRange]);
    const filteredPcfReleased = useMemo(() => {
        let filtered = pcfReleased;
        if (selectedBusinessUnit !== 'all') filtered = filtered.filter(liq => liq.businessId === selectedBusinessUnit);
        if (searchTerm.trim()) {
            const term = searchTerm.toLowerCase();
            filtered = filtered.filter(liq =>
                liq.replenishmentPrfId?.toLowerCase().includes(term) ||
                liq.userName?.toLowerCase().includes(term) ||
                businesses.find(b => b.id === liq.businessId)?.name.toLowerCase().includes(term)
            );
        }
        if (dateRange.start && dateRange.end) {
            const start = new Date(dateRange.start);
            const end = new Date(dateRange.end);
            end.setHours(23, 59, 59, 999);
            filtered = filtered.filter(liq => {
                const liqDate = new Date(liq.dateCreated || new Date());
                return liqDate >= start && liqDate <= end;
            });
        }
        return filtered;
    }, [pcfReleased, searchTerm, selectedBusinessUnit, businesses, dateRange]);

    // Filter requisitions for PRF tabs (Fund Release)
    const filteredReqs = useMemo(() => {
        return applyFilters(displayedReqs);
    }, [displayedReqs, searchTerm, selectedBusinessUnit, businesses, allUsers, dateRange]);

    // Export handler for current tab's filtered data
