import { useState, useEffect } from 'react';
import { collection, getDocs, addDoc, doc, updateDoc, query, where } from "firebase/firestore";
import { db } from "../../../config/firebase";
import { COLLECTIONS } from "../../../shared/types/firebase.types";
import type { Supplier } from "../../procurement/types";

export const useSuppliers = () => {
    const [suppliers, setSuppliers] = useState<Supplier[]>([]);
    const [loading, setLoading] = useState(true);

    const suppliersCollection = collection(db, COLLECTIONS.SUPPLIERS);

    useEffect(() => {
        const fetchSuppliers = async () => {
            try {
                // Fetch ALL suppliers first, then filter client-side
                // This handles legacy data without a 'status' field
                const querySnapshot = await getDocs(suppliersCollection);
                const suppliersData = querySnapshot.docs
                    .map(doc => ({ id: doc.id, ...doc.data() } as Supplier))
                    // Filter out archived suppliers (keep those without status field = legacy/active)
                    .filter(s => s.status !== 'ARCHIVED');
                setSuppliers(suppliersData);
            } catch (error) {
                console.error("Error fetching suppliers: ", error);
            }
            setLoading(false);
        };

        fetchSuppliers();
    }, []);

    const createSupplier = async (supplierData: Omit<Supplier, 'id'>) => {
        try {
            // Task 1: Prevent Duplicates
            // Use simple single-field queries to avoid composite index requirements
            // Then filter client-side for non-archived suppliers

            // Check for existing name (simple query, filter client-side)
            const nameQuery = query(suppliersCollection, where('name', '==', supplierData.name));
            const nameSnapshot = await getDocs(nameQuery);
            const activeNameMatch = nameSnapshot.docs.find(doc => {
                const data = doc.data();
                return data.status !== 'ARCHIVED';
            });
            if (activeNameMatch) {
                throw new Error("Supplier with this Name already exists.");
            }

            // Check for existing TIN if provided
            if (supplierData.tin) {
                const tinQuery = query(suppliersCollection, where('tin', '==', supplierData.tin));
                const tinSnapshot = await getDocs(tinQuery);
                const activeTinMatch = tinSnapshot.docs.find(doc => {
                    const data = doc.data();
                    return data.status !== 'ARCHIVED';
                });
                if (activeTinMatch) {
                    throw new Error("Supplier with this TIN already exists.");
                }
            }

            const docRef = await addDoc(suppliersCollection, { ...supplierData, status: 'ACTIVE' });
            setSuppliers(prev => [...prev, { id: docRef.id, ...supplierData, status: 'ACTIVE' }]);
        } catch (error: any) {
            console.error("Error creating supplier: ", error);
            throw error; // Re-throw to let component handle it
        }
    };

    const updateSupplier = async (supplierData: Supplier) => {
        try {
            const supplierDoc = doc(db, COLLECTIONS.SUPPLIERS, supplierData.id);
            await updateDoc(supplierDoc, { ...supplierData });
            setSuppliers(prev => prev.map(s => s.id === supplierData.id ? supplierData : s));
        } catch (error) {
            console.error("Error updating supplier: ", error);
        }
    };

    const deleteSupplier = async (id: string) => {
        try {
            // Task 2: Implement Soft Delete
            const supplierDoc = doc(db, COLLECTIONS.SUPPLIERS, id);
            await updateDoc(supplierDoc, { status: 'ARCHIVED' });
            // Update local state to remove it from UI
            setSuppliers(prev => prev.filter(s => s.id !== id));
        } catch (error) {
            console.error("Error deleting supplier: ", error);
        }
    };

    return { suppliers, loading, createSupplier, updateSupplier, deleteSupplier };
};

import {
    collection,
    doc,
    addDoc,
    query,
    where,
    orderBy,
    onSnapshot,
    serverTimestamp,
    Timestamp,
    runTransaction
} from 'firebase/firestore';
import { db } from '../../../config/firebase';
import { getTenantConstraints } from '../../../shared/utils/tenantFilters';
import type { User } from '../../procurement/types';

export interface TimelineEvent {
    id: string;
    timestamp: string;
    action: string;
    actor?: string;
    createdAt: Date;
}

export interface InvestigationCase {
    id?: string;
    businessId: string;
    itemId: string;
    itemName: string;
    category: string;
    totalLoss: number;
    date: string;
    time: string;
    assignee: string;
    assigneeRole: string;
    initialNote: string;
    priority: 'urgent' | 'watch';
    status: 'active' | 'resolved';
    resolvedAt?: string;
    resolvedBy?: string;
    timeline: TimelineEvent[];
    createdAt: Timestamp;
}

export class InvestigationsService {
    /**
     * Subscribe to investigation cases in real-time.
     *
     * @param userOrBuId - Pass a `User` for multi-BU-aware subscription,
     *                     or a `string` businessId for single-BU scope.
     */
    static subscribeToInvestigations(
        userOrBuId: User | string,
        callback: (cases: InvestigationCase[]) => void
    ) {
        const tenantConstraints = typeof userOrBuId === 'string'
            ? [where('businessId', '==', userOrBuId)]
            : getTenantConstraints(userOrBuId, 'businessId');

        const q = query(
            collection(db, 'inventory_investigations'),
            ...tenantConstraints,
            orderBy('createdAt', 'desc')
        );

        return onSnapshot(q, (snapshot) => {
            const cases: InvestigationCase[] = snapshot.docs.map(doc => {
                const data = doc.data();
                return {
                    ...data,
                    id: doc.id,
                    timeline: data.timeline?.map((t: any) => ({
                        ...t,
                        createdAt: t.createdAt?.toDate() || new Date()
                    })) || []
                } as InvestigationCase;
            });
            callback(cases);
        }, (error) => {
            console.error("Error subscribing to investigations:", error);
            callback([]); // Return empty on error to handle gracefully
        });
    }

    static async assignInvestigation(data: Omit<InvestigationCase, 'id' | 'createdAt' | 'status' | 'timeline'>, creatorName: string) {
        const newCase: Omit<InvestigationCase, 'id'> = {
            ...data,
            status: 'active',
            timeline: [
                {
                    id: crypto.randomUUID(),
                    action: 'Flagged automatically by variance engine',
                    actor: 'System',
                    timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
                    createdAt: new Date()
                },
                {
                    id: crypto.randomUUID(),
                    action: `Assigned to ${data.assignee} (${data.assigneeRole})`,
                    actor: creatorName,
                    timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
                    createdAt: new Date()
                }
            ],
            createdAt: serverTimestamp() as Timestamp
        };

        if (data.initialNote) {
            newCase.timeline.push({
                id: crypto.randomUUID(),
                action: `Note: ${data.initialNote}`,
                actor: creatorName,
                timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
                createdAt: new Date()
            });
        }

        const docRef = await addDoc(collection(db, 'inventory_investigations'), newCase);
        return docRef.id;
    }

    static async resolveInvestigation(caseId: string, resolverName: string, resolutionNote: string = 'Case resolved') {
        const docRef = doc(db, 'inventory_investigations', caseId);

        await runTransaction(db, async (transaction) => {
            const snap = await transaction.get(docRef);
            if (!snap.exists()) throw new Error(`Investigation case ${caseId} not found`);

            const existing = snap.data();

            const resolveEvent: TimelineEvent = {
                id: crypto.randomUUID(),
                action: resolutionNote,
                actor: resolverName,
                timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
                createdAt: new Date()
            };

            const newTimeline = [...(existing.timeline || []), resolveEvent];

            transaction.update(docRef, {
                status: 'resolved',
                resolvedAt: new Date().toLocaleString([], { dateStyle: 'short', timeStyle: 'short' }),
                resolvedBy: resolverName,
                timeline: newTimeline
            });
        });
    }

    static async addTimelineEvent(caseId: string, action: string, actor: string) {
        const docRef = doc(db, 'inventory_investigations', caseId);

        await runTransaction(db, async (transaction) => {
            const snap = await transaction.get(docRef);
            if (!snap.exists()) throw new Error(`Investigation case ${caseId} not found`);

            const existing = snap.data();

            const newEvent: TimelineEvent = {
                id: crypto.randomUUID(),
                action,
                actor,
                timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
                createdAt: new Date()
            };

            const newTimeline = [...(existing.timeline || []), newEvent];

            transaction.update(docRef, {
                timeline: newTimeline
            });
        });
    }
}

