                    setShowItemModal(false);
                    setEditingItem(null);
                }}
                onSave={handleSaveItem}
                item={editingItem}
                businessUnitId={selectedBusinessUnit}
                storageAreas={storageAreas}
                uomOptions={uomOptions}
            />

