                        <X size={20} />
                    </button>
                </div>

                <form onSubmit={handleSubmit} className="p-6 space-y-6">
                    {errorMessage && (
                        <div className="p-3 bg-red-50 dark:bg-red-900/50 border border-red-200 dark:border-red-500 rounded text-red-600 dark:text-red-200 text-sm">
                            {errorMessage}
                        </div>
