                            Cancel
                        </button>
                        <button type="submit" disabled={isSubmitting || !isTinValid} className="px-4 py-2 bg-purple-600 text-white hover:bg-purple-700 rounded-lg font-medium transition-colors disabled:opacity-50 disabled:cursor-not-allowed">
                            {isSubmitting ? 'Saving...' : (supplier ? 'Save Changes' : 'Add Supplier')}
                        </button>
                    </div>
                </form>
            </Card>
        </div >
    );
};


const SuppliersView: React.FC<SuppliersViewProps> = ({ suppliers, onCreateSupplier, onUpdateSupplier, onDeleteSupplier, currentUser, businesses }) => {
    const { hasPermission } = usePermissions();
    const { selectedBusinessUnit } = useBusinessUnit();
    const [searchTerm, setSearchTerm] = useState('');
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingSupplier, setEditingSupplier] = useState<Supplier | undefined>(undefined);

    // Show all suppliers - the filter dropdown will handle BU-specific filtering
    const visibleSuppliers = suppliers;

    // Memoized filtering with strict "Empty = Global" rule
    const filteredSuppliers = React.useMemo(() => {
        return visibleSuppliers.filter(supplier => {
            // 1. If filter is ALL, show everything
            if (selectedBusinessUnit === 'all') {
                // Still apply search filter
                if (searchTerm) {
                    const term = searchTerm.toLowerCase();
                    return supplier.name.toLowerCase().includes(term) ||
                        supplier.category.toLowerCase().includes(term);
                }
                return true;
            }

            const tags = supplier.businessUnitIds || [];

            // 2. Logic: Show if Tagged Match OR Tagged Global OR No Tags (Empty)
            const isTaggedForBu = tags.includes(selectedBusinessUnit);
            const isGlobal = tags.includes('GLOBAL');
            const hasNoTags = tags.length === 0;

            const passesBusinessUnitFilter = isTaggedForBu || isGlobal || hasNoTags;

            if (!passesBusinessUnitFilter) return false;

            // Apply search filter
            if (searchTerm) {
                const term = searchTerm.toLowerCase();
                return supplier.name.toLowerCase().includes(term) ||
                    supplier.category.toLowerCase().includes(term);
            }

            return true;
        });
    }, [visibleSuppliers, selectedBusinessUnit, searchTerm]);

    const handleAdd = () => {
        setEditingSupplier(undefined);
        setIsModalOpen(true);
    };

    const handleEdit = (supplier: Supplier) => {
        setEditingSupplier(supplier);
        setIsModalOpen(true);
    };

    const handleDelete = (id: string) => {
        if (confirm('Are you sure you want to delete this supplier?')) {
            onDeleteSupplier(id); // Use onDeleteSupplier prop
        }
    };

    const handleSave = async (data: Supplier | Omit<Supplier, 'id'>) => {
        try {
            if ('id' in data) {
                await onUpdateSupplier(data as Supplier);
            } else {
                await onCreateSupplier(data as Omit<Supplier, 'id'>);
            }
            setIsModalOpen(false);
        } catch (error) {
            console.error(error);
            throw error; // Re-throw so modal can catch it
        }
    };

    return (
        <div className="space-y-6">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-slate-900 dark:text-white">Suppliers</h1>
                    <p className="text-slate-500 dark:text-slate-300">Manage vendor relationships</p>
                </div>
                <div className="flex flex-col md:flex-row gap-4 w-full md:w-auto items-stretch md:items-center">
                    <div className="relative flex-1 md:flex-none">
                        <Search size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 dark:text-slate-400" />
                        <input
                            className="pl-10 p-2 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg text-sm w-full md:w-64 text-slate-900 dark:text-white focus:ring-2 focus:ring-purple-500 focus:outline-none shadow-sm dark:shadow-none"
                            placeholder="Search suppliers..."
                            value={searchTerm}
                            onChange={e => setSearchTerm(e.target.value)}
                        />
                    </div>
                    {hasPermission('master_data:supplier:create') && (
                        <button
                            onClick={handleAdd}
                            className="bg-purple-600 hover:bg-purple-700 text-white px-4 py-2 rounded-lg font-medium flex items-center justify-center gap-2"
                        >
                            <Plus size={18} /> Add Supplier
                        </button>
                    )}
                </div>
            </div>

            <Card className="overflow-hidden !p-0 border border-slate-200 dark:border-slate-700 shadow-sm dark:shadow-none bg-white dark:bg-slate-800">
                <div className="overflow-x-auto max-h-[600px] overflow-y-auto">
                    <table className="w-full text-left text-sm">
                        <thead className="bg-slate-50 dark:bg-slate-900/80 text-xs uppercase font-semibold text-slate-500 dark:text-slate-400 sticky top-0 z-20 backdrop-blur-sm border-b border-slate-200 dark:border-slate-700">
                            <tr>
                                <th className="px-6 py-4">Name</th>
                                <th className="px-6 py-4">Category</th>
                                <th className="px-6 py-4">Business Units</th>
                                <th className="px-6 py-4">Details</th>
                                <th className="px-6 py-4">Rating</th>
                                <th className="px-6 py-4 text-right">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-200 dark:divide-slate-700">
                            {filteredSuppliers.map(supplier => (
                                <tr key={supplier.id} className="hover:bg-slate-50 dark:hover:bg-slate-800/60 transition-colors">
                                    <td className="px-6 py-4 font-medium text-slate-900 dark:text-slate-200">{supplier.name}</td>
                                    <td className="px-6 py-4">
                                        <span className="bg-slate-100 dark:bg-slate-700 text-slate-600 dark:text-slate-300 px-2 py-1 rounded text-xs font-medium">
                                            {supplier.category}
                                        </span>
                                    </td>
                                    <td className="px-6 py-4">
                                        <div className="flex flex-wrap gap-1">
                                            {supplier.businessUnitIds && supplier.businessUnitIds.length > 0 ? (
                                                supplier.businessUnitIds.map(id => {
                                                    const biz = businesses.find(b => b.id === id);
                                                    return biz ? (
                                                        <span key={id} className="text-xs bg-purple-100 dark:bg-purple-900/30 border border-purple-200 dark:border-purple-700/50 px-2 py-1 rounded text-purple-700 dark:text-purple-300 flex items-center gap-1">
                                                            <Building2 size={12} /> {biz.name}
                                                        </span>
                                                    ) : null;
                                                })
                                            ) : (
                                                <span className="text-xs text-slate-500 italic">All Units</span>
                                            )}
                                        </div>
                                    </td>
                                    <td className="px-6 py-4 text-xs text-slate-500 dark:text-slate-400">
                                        {supplier.tin && <div>TIN: {supplier.tin}</div>}
                                        {supplier.address && <div className="truncate max-w-[150px]">{supplier.address}</div>}
                                        {supplier.bankDetails?.bankName && (
                                            <div className="text-slate-400 dark:text-slate-500 mt-1">
                                                Bank: {supplier.bankDetails.bankName} - {supplier.bankDetails.accountNumber}
                                            </div>
                                        )}
                                    </td>
                                    <td className="px-6 py-4">
                                        <div className="flex items-center gap-1 text-amber-500 dark:text-amber-400">
                                            <Star size={14} fill="currentColor" />
                                            <span className="text-slate-600 dark:text-slate-300 font-medium">{supplier.rating}</span>
                                        </div>
                                    </td>
                                    <td className="px-6 py-4 text-right">
                                        <div className="flex justify-end gap-2">
                                            {hasPermission('master_data:supplier:edit') && (
                                                <button
                                                    onClick={() => handleEdit(supplier)}
                                                    className="text-cyan-600 dark:text-cyan-400 hover:text-cyan-700 dark:hover:text-cyan-300 p-1 hover:bg-slate-100 dark:hover:bg-slate-700 rounded"
                                                >
                                                    <Edit2 size={16} />
                                                </button>
                                            )}
                                            {hasPermission('master_data:supplier:delete') && (
                                                <button
                                                    onClick={() => handleDelete(supplier.id)}
                                                    className="text-red-600 dark:text-red-400 hover:text-red-700 dark:hover:text-red-300 p-1 hover:bg-slate-100 dark:hover:bg-slate-700 rounded"
                                                >
                                                    <Trash2 size={16} />
                                                </button>
                                            )}
                                        </div>
                                    </td>
                                </tr>
                            ))}
                            {filteredSuppliers.length === 0 && (
                                <tr>
                                    <td colSpan={7} className="px-6 py-8 text-center text-slate-500 italic">
                                        No suppliers found.
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </Card>

            <SupplierModal
                isOpen={isModalOpen}
                supplier={editingSupplier}
                onClose={() => setIsModalOpen(false)}
                onSave={handleSave}
                businesses={businesses}
                currentUser={currentUser}
            />
        </div>
    );
};

export default SuppliersView;

import React, { useState, useEffect } from 'react';
import { X, Plus, Trash2, ChefHat, AlertTriangle, CheckSquare } from 'lucide-react';
import type { 
    CreateBlackBookRecipeInput, 
    BlackBookIngredient, 
    PrepStation 
} from '../types/blackbook.types';
import { PREP_STATIONS } from '../types/blackbook.types';
import type { ProductionRecipe, MenuItem } from '../types/menu.types';
import { ProductionRecipeService } from '../services/production-recipe.service';
import { getMenuItems } from '../services/recipes.service';
import { BlackBookService } from '../services/blackbook.service';
import { useBusinessUnit } from '../../../contexts/BusinessUnitContext';

interface CreateBlackBookModalProps {
    isOpen: boolean;
    onClose: () => void;
    onRecipeCreated: () => void;
}

const INITIAL_FORM: CreateBlackBookRecipeInput = {
    businessUnitId: '',
    name: '',
    prepStation: 'Prep Station',
    productionRecipeId: '',
    menuItemId: '',
    batchYield: '',
    cookTempTime: '',
    costPerServing: '',
    ingredients: [],
    methodSteps: [{ stepNumber: 1, instruction: '' }],
    mistakesFixes: [],
    qualityChecklist: [],
    platingPhotoUrl: '',
    trainingVideoUrl: '',
    youtubeVideoUrl: ''
};

const CreateBlackBookModal: React.FC<CreateBlackBookModalProps> = ({ isOpen, onClose, onRecipeCreated }) => {
    const { selectedBusinessUnit } = useBusinessUnit();
    const [formData, setFormData] = useState<CreateBlackBookRecipeInput>(INITIAL_FORM);

    const [productionRecipes, setProductionRecipes] = useState<ProductionRecipe[]>([]);
    const [menuItems, setMenuItems] = useState<MenuItem[]>([]);
    const [isSaving, setIsSaving] = useState(false);
    const [error, setError] = useState<string | null>(null);

    // Load available recipes and menu items for linking
    useEffect(() => {
        if (!isOpen || !selectedBusinessUnit || selectedBusinessUnit === 'all') return;

        const loadData = async () => {
            try {
                const [recipes, items] = await Promise.all([
                    ProductionRecipeService.getRecipes(selectedBusinessUnit),
                    getMenuItems(selectedBusinessUnit)
                ]);
                setProductionRecipes(recipes);
                setMenuItems(items);
                setFormData(prev => ({ ...prev, businessUnitId: selectedBusinessUnit }));
            } catch (err) {
                console.error("Failed to load linked data:", err);
                setError("Failed to load production recipes and menu items.");
            }
        };

        loadData();
    }, [isOpen, selectedBusinessUnit]);

    const [sourceType, setSourceType] = useState<'production' | 'finished'>('production');

    // Handle Production Recipe Selection -> Auto-fill ingredients
    const handleProductionRecipeChange = (recipeId: string) => {
        setFormData(prev => ({ ...prev, productionRecipeId: recipeId, menuItemId: '' }));

        const recipe = productionRecipes.find(r => r.id === recipeId);
        if (recipe) {
            // Pre-fill Name if empty
            const updates: Partial<CreateBlackBookRecipeInput> = {};
            if (!formData.name) updates.name = recipe.name;
            if (!formData.batchYield) updates.batchYield = `${recipe.yieldQuantity} ${recipe.yieldUnit}`;
            if (!formData.costPerServing && recipe.costPerUnit) updates.costPerServing = `₱${recipe.costPerUnit.toFixed(2)}`;

            // Auto-populate ingredients
            const blackBookIngredients: BlackBookIngredient[] = recipe.ingredients.map(ing => ({
                ...ing,
                specStandard: '',
                allowedSubstitute: ''
            }));

            setFormData(prev => ({ 
                ...prev, 
                ...updates,
                ingredients: blackBookIngredients 
            }));
        }
    };

    // Handle Menu Item Selection -> Auto-fill ingredients
    const handleMenuItemChange = (menuId: string) => {
        setFormData(prev => ({ ...prev, menuItemId: menuId, productionRecipeId: '' }));

        const item = menuItems.find(m => m.id === menuId);
        if (item) {
            // Pre-fill Name if empty
            const updates: Partial<CreateBlackBookRecipeInput> = {};
            if (!formData.name) updates.name = item.name;
            if (!formData.batchYield) updates.batchYield = `1 portion`;
            if (!formData.costPerServing && item.calculatedCost) updates.costPerServing = `₱${item.calculatedCost.toFixed(2)}`;

            // Auto-populate ingredients
            const blackBookIngredients: BlackBookIngredient[] = (item.ingredients || []).map(ing => ({
                ...ing,
                specStandard: '',
                allowedSubstitute: ''
            }));

            setFormData(prev => ({ 
                ...prev, 
                ...updates,
                ingredients: blackBookIngredients 
            }));
        }
    };

    const handleSave = async () => {
        try {
            setError(null);
            if (!formData.name) throw new Error("Recipe name is required");
            if (!formData.businessUnitId || formData.businessUnitId === 'all') throw new Error("Select a specific Business Unit first");

            setIsSaving(true);

            // Clean up empty steps/items
            const cleanData = {
                ...formData,
                methodSteps: formData.methodSteps.filter(s => s.instruction.trim()),
                mistakesFixes: formData.mistakesFixes.filter(m => m.mistake.trim()),
                qualityChecklist: formData.qualityChecklist.filter(q => q.label.trim())
            };

            // Ensure step numbers are sequential
            cleanData.methodSteps.forEach((step, idx) => {
                step.stepNumber = idx + 1;
            });

            await BlackBookService.createRecipe(cleanData);
            onRecipeCreated();
            setFormData(INITIAL_FORM); // Reset
            onClose();
        } catch (err: any) {
            setError(err.message || "Failed to save recipe");
        } finally {
            setIsSaving(false);
        }
    };

    if (!isOpen) return null;

    if (selectedBusinessUnit === 'all') {
        return (
            <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
                <div className="bg-white dark:bg-slate-800 rounded-xl max-w-md w-full p-6 shadow-2xl border border-slate-200 dark:border-slate-700">
                    <h3 className="text-lg font-bold text-slate-800 dark:text-white mb-2">Select Business Unit</h3>
                    <p className="text-slate-600 dark:text-slate-400 mb-6">Please select a specific business unit from the top navigation before creating a new recipe.</p>
                    <button onClick={onClose} className="w-full px-4 py-2 bg-slate-100 dark:bg-slate-700 text-slate-800 dark:text-white rounded-lg font-medium">Close</button>
                </div>
            </div>
        );
    }

    return (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex justify-end">
            <div className="bg-[#faf8f5] dark:bg-slate-900 w-full max-w-4xl h-full shadow-2xl flex flex-col animate-slide-in-right border-l border-[#e8e0d4] dark:border-slate-700">
                {/* Header */}
                <div className="flex items-center justify-between px-6 py-4 border-b border-[#e8e0d4] dark:border-slate-700 bg-white dark:bg-slate-800 shrink-0">
                    <div>
                        <h2 className="text-xl font-bold text-slate-800 dark:text-white">Create New Black Book Recipe</h2>
                        <p className="text-sm text-slate-500 dark:text-slate-400">Standardize your kitchen operations</p>
                    </div>
                    <div className="flex items-center gap-3">
                        <button onClick={onClose} className="p-2 text-slate-400 hover:text-slate-600 dark:hover:text-slate-300 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors">
                            <X size={20} />
                        </button>
                    </div>
                </div>

                {/* Form Body */}
                <div className="flex-1 overflow-y-auto p-6 space-y-8">
                    {error && (
                        <div className="bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 p-4 rounded-lg text-sm border border-red-100 dark:border-red-900/30 flex items-center gap-2">
                            <AlertTriangle size={16} />
                            {error}
                        </div>
                    )}

                    {/* Section 1: Core Details */}
                    <section className="bg-white dark:bg-slate-800 p-6 rounded-xl border border-[#e8e0d4] dark:border-slate-700 shadow-sm space-y-4">
                        <h3 className="text-sm font-bold text-slate-800 dark:text-white uppercase tracking-wider mb-4 flex items-center gap-2">
                            <ChefHat size={16} className="text-amber-500" />
                            Core Details
                        </h3>

                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="block text-xs font-medium text-slate-500 dark:text-slate-400 mb-1">Recipe Name *</label>
                                <input
                                    type="text"
                                    value={formData.name}
                                    onChange={e => setFormData(prev => ({ ...prev, name: e.target.value }))}
                                    className="w-full px-3 py-2 bg-[#faf8f5] dark:bg-slate-900 border border-[#e8e0d4] dark:border-slate-700 rounded-lg text-slate-800 dark:text-white focus:ring-2 focus:ring-amber-500/50 focus:border-amber-500 outline-none transition-all"
                                    placeholder="e.g. Signature Beef Tapa"
                                />
                            </div>
                            <div>
                                <label className="block text-xs font-medium text-slate-500 dark:text-slate-400 mb-1">Prep Station</label>
                                <select
                                    value={formData.prepStation}
                                    onChange={e => setFormData(prev => ({ ...prev, prepStation: e.target.value as PrepStation }))}
                                    className="w-full px-3 py-2 bg-[#faf8f5] dark:bg-slate-900 border border-[#e8e0d4] dark:border-slate-700 rounded-lg text-slate-800 dark:text-white focus:ring-2 focus:ring-amber-500/50 outline-none"
                                >
                                    {PREP_STATIONS.map(station => (
                                        <option key={station} value={station}>{station}</option>
                                    ))}
                                </select>
                            </div>
                            <div className="col-span-2">
                                <label className="block text-xs font-medium text-slate-500 dark:text-slate-400 mb-2">Recipe Source Type</label>
                                <div className="flex gap-4">
                                    <label className="flex items-center gap-2 cursor-pointer">
                                        <input 
                                            type="radio" 
                                            name="sourceType" 
                                            checked={sourceType === 'production'} 
                                            onChange={() => setSourceType('production')} 
                                            className="text-amber-500 focus:ring-amber-500"
                                        />
                                        <span className="text-sm text-slate-700 dark:text-slate-300">Production Recipe</span>
                                    </label>
                                    <label className="flex items-center gap-2 cursor-pointer">
                                        <input 
                                            type="radio" 
                                            name="sourceType" 
                                            checked={sourceType === 'finished'} 
                                            onChange={() => setSourceType('finished')} 
                                            className="text-amber-500 focus:ring-amber-500"
                                        />
                                        <span className="text-sm text-slate-700 dark:text-slate-300">Finished Good (Menu Item)</span>
                                    </label>
                                </div>
                            </div>

                            {sourceType === 'production' && (
                                <div className="col-span-2">
                                    <label className="block text-xs font-medium text-slate-500 dark:text-slate-400 mb-1">Select Production Recipe</label>
                                    <select
                                        value={formData.productionRecipeId}
                                        onChange={e => handleProductionRecipeChange(e.target.value)}
                                        className="w-full px-3 py-2 bg-[#faf8f5] dark:bg-slate-900 border border-[#e8e0d4] dark:border-slate-700 rounded-lg text-slate-800 dark:text-white focus:ring-2 focus:ring-amber-500/50 outline-none"
                                    >
                                        <option value="">-- Select Production Recipe --</option>
                                        {productionRecipes.map(r => (
                                            <option key={r.id} value={r.id}>{r.name} ({r.yieldQuantity} {r.yieldUnit})</option>
                                        ))}
                                    </select>
                                </div>
                            )}

                            {sourceType === 'finished' && (
                                <div className="col-span-2">
                                    <label className="block text-xs font-medium text-slate-500 dark:text-slate-400 mb-1">Select Menu Item (Finished Good)</label>
                                    <select
                                        value={formData.menuItemId}
                                        onChange={e => handleMenuItemChange(e.target.value)}
                                        className="w-full px-3 py-2 bg-[#faf8f5] dark:bg-slate-900 border border-[#e8e0d4] dark:border-slate-700 rounded-lg text-slate-800 dark:text-white focus:ring-2 focus:ring-amber-500/50 outline-none"
                                    >
