            <div className="flex items-start justify-between mb-3">
                <div className="flex items-center gap-3">
                    <div className="p-2 bg-amber-50 dark:bg-amber-500/20 rounded-lg">
                        <Factory size={20} className="text-amber-500 dark:text-amber-400" />
                    </div>
                    <div>
                        <h3 className="font-semibold text-slate-900 dark:text-white">{recipe.name}</h3>
                        <span className="text-xs text-amber-400 bg-amber-500/10 px-2 py-0.5 rounded-full">
                            {recipe.category}
                        </span>
                        {(recipe as any).serviceType && (
                            <span className={`text-xs px-2 py-0.5 rounded-full font-medium ml-1 ${
                                (recipe as any).serviceType === 'Alacarte'
                                    ? 'bg-indigo-500/10 text-indigo-400'
                                    : (recipe as any).serviceType === 'Event'
                                        ? 'bg-teal-500/10 text-teal-400'
                                        : 'bg-orange-500/10 text-orange-400'
                            }`}>
                                {(recipe as any).serviceType}
                            </span>
                        )}
                    </div>
                </div>
                <div className="flex items-center gap-1">
                    {hasPermission('menu:production_log:create') && (
                        <button
                            onClick={() => onRecordYield(recipe)}
                            title="Record Production Yield"
                            className="p-2 hover:bg-green-100 dark:hover:bg-green-500/20 rounded-lg text-slate-400 hover:text-green-600 dark:hover:text-green-400 transition-colors"
                        >
                            <Play size={16} />
                        </button>
                    )}
                    {hasPermission('menu:recipe:edit') && (
                        <button
                            onClick={() => onEdit(recipe)}
                            className="p-2 hover:bg-slate-100 dark:hover:bg-slate-600 rounded-lg text-slate-400 hover:text-slate-700 dark:hover:text-white transition-colors"
                        >
                            <Edit size={16} />
                        </button>
                    )}
                    {hasPermission('menu:recipe:delete') && (
                        <button
                            onClick={() => onDelete(recipe)}
                            className="p-2 hover:bg-red-100 dark:hover:bg-red-500/20 rounded-lg text-slate-400 hover:text-red-500 dark:hover:text-red-400 transition-colors"
                        >
                            <Trash2 size={16} />
                        </button>
                    )}
                </div>
            </div>

            {/* Missing Production Alert */}
            {todayStats && (todayStats.soldToday > 0 && todayStats.productionRecordedToday < todayStats.soldToday) && (
                <div className="bg-red-50 dark:bg-red-500/10 border border-red-200 dark:border-red-500/30 rounded-lg p-3 mb-3">
                    <div className="flex items-center gap-2 text-red-600 dark:text-red-400 font-bold text-sm mb-2">
                        <span className="text-lg">⚠️</span> Missing Production Alert
                    </div>
                    <div className="grid grid-cols-3 gap-2 text-xs mb-2">
                        <div className="bg-white/50 dark:bg-slate-900/50 p-2 rounded">
                            <p className="text-slate-500">Sold today</p>
                            <p className="font-bold text-red-600 dark:text-red-400">{todayStats.soldToday.toLocaleString()} {recipe.yieldUnit}</p>
                        </div>
                        <div className="bg-white/50 dark:bg-slate-900/50 p-2 rounded">
                            <p className="text-slate-500">Produced</p>
                            <p className="font-bold text-slate-700 dark:text-slate-300">{todayStats.productionRecordedToday.toLocaleString()} {recipe.yieldUnit}</p>
                        </div>
                        <div className="bg-white/50 dark:bg-slate-900/50 p-2 rounded">
                            <p className="text-slate-500">Expected Stock</p>
                            <p className={`font-bold ${productionStock !== null && productionStock < 0 ? 'text-red-600 dark:text-red-400' : 'text-slate-700 dark:text-slate-300'}`}>
                                {productionStock === null ? '—' : productionStock.toLocaleString()} {recipe.yieldUnit}
                            </p>
                        </div>
                    </div>
                    <p className="text-xs text-red-600/80 dark:text-red-400/80 mb-3">
                        The POS shows sales, but production was not fully encoded.
                    </p>
                    <button
                        onClick={() => onRecordYield(recipe, todayStats.soldToday - todayStats.productionRecordedToday)}
                        className="w-full py-2 bg-red-600 hover:bg-red-700 text-white rounded-lg text-sm font-semibold transition-colors flex items-center justify-center gap-2"
                    >
                        <Play size={14} />
                        Encode missed production
                    </button>
                </div>
            )}

            {/* Yield Info */}
            <div className="bg-slate-50 dark:bg-slate-900/50 rounded-lg p-3 mb-3">
                <p className="text-xs text-slate-500 mb-1">Batch Yield</p>
                <p className="text-lg font-bold text-slate-900 dark:text-white">
                    {recipe.yieldQuantity} {recipe.yieldUnit}
                </p>
            </div>

            {/* Stock Remaining */}
            <div className={`rounded-lg p-3 mb-3 flex items-center gap-2 ${
                productionStock === null
                    ? 'bg-slate-50 dark:bg-slate-900/50'
                    : productionStock <= 0
                        ? 'bg-red-50 dark:bg-red-500/10 border border-red-200 dark:border-red-500/30'
                        : 'bg-green-50 dark:bg-green-500/10 border border-green-200 dark:border-green-500/30'
            }`}>
                <Layers size={14} className={
                    productionStock === null
                        ? 'text-slate-400'
                        : productionStock <= 0
                            ? 'text-red-500 dark:text-red-400'
                            : 'text-green-600 dark:text-green-400'
                } />
                <div>
                    <p className="text-xs text-slate-500">Servings Remaining</p>
                    <p className={`text-sm font-bold ${
                        productionStock === null
                            ? 'text-slate-400'
                            : productionStock <= 0
                                ? 'text-red-600 dark:text-red-400'
                                : 'text-green-700 dark:text-green-400'
                    }`}>
                        {productionStock === null
                            ? '—'
                            : `${productionStock.toLocaleString()} ${recipe.yieldUnit}`
                        }
                    </p>
                </div>
            </div>

            {/* Cost Info */}
            <div className="grid grid-cols-2 gap-3">
                <div className="bg-slate-50 dark:bg-slate-900/50 rounded-lg p-3 text-center">
                    <p className="text-xs text-slate-500 mb-1">Total Cost</p>
                    <p className="text-sm font-medium text-slate-900 dark:text-white flex items-center justify-center gap-1">
                        <PesoSign size={14} />
                        {recipe.calculatedCost.toLocaleString('en-PH', { minimumFractionDigits: 2 })}
                    </p>
                </div>
                <div className="bg-slate-50 dark:bg-slate-900/50 rounded-lg p-3 text-center">
                    <p className="text-xs text-slate-500 mb-1">Cost/Unit</p>
                    <p className="text-sm font-medium text-amber-500 dark:text-amber-400 flex items-center justify-center gap-1">
                        <PesoSign size={14} />
                        {recipe.costPerUnit.toLocaleString('en-PH', { minimumFractionDigits: 2 })}
                    </p>
                </div>
            </div>

            {/* Ingredients count */}
            <div className="mt-3 pt-3 border-t border-slate-200 dark:border-slate-700">
                <p className="text-xs text-slate-500">
                    {recipe.ingredients.length} ingredient{recipe.ingredients.length !== 1 ? 's' : ''}
                </p>
            </div>
        </div>
    );
};

