import React, { useState, useEffect, useMemo } from 'react';
import {
    X, Save, Plus, Trash2, Loader2, ChefHat,
    TrendingUp, Search, AlertTriangle, Package, Sparkles
} from 'lucide-react';
import PesoSign from '../../../shared/components/PesoSign';
import { GeminiVisionService } from '../../../shared/services/gemini-vision.service';
import type { InventoryItem } from '../../inventory/types/InventoryItem';
import { InventoryService } from '../../inventory/services/inventory.service';
import type { MenuItem, MenuCategory } from '../types/menu.types';
import type { ServiceType } from '../../inventory/types/InventoryItem';
import { SERVICE_TYPES } from '../../inventory/types/InventoryItem';
import {
    MENU_CATEGORIES,
    getFoodCostStatus,
    getFoodCostColor,
    getFoodCostBgColor
} from '../types/menu.types';
import {
    RecipesService,
    calculateIngredientCost,
    getAvailableUnits
} from '../services/recipes.service';

// ============================================================
// TYPES
// ============================================================

interface RecipeEditorProps {
    isOpen: boolean;
    onClose: () => void;
    onSave: () => void;
    menuItem?: MenuItem | null;
    businessUnitId: string;
}

interface IngredientFormData {
    id: string; // Temporary ID for UI
    inventoryItemId: string;
    inventoryItemName: string;
    quantity: number;
    unit: string;
    availableUnits: string[];
    costPerUnit: number;
    totalCost: number;
}

/**
 * Resolves the recipe unit for an inventory item, handling legacy Firestore docs
 * that may use 'countUnit' instead of 'recipeUnit'.
 */
function getItemRecipeUnit(item: InventoryItem): string {
    return item.units?.recipeUnit
        || (item.units as any)?.countUnit
        || 'EA';
}

// ============================================================
// INGREDIENT ROW COMPONENT
// ============================================================

const IngredientRow: React.FC<{
    ingredient: IngredientFormData;
    inventoryItems: InventoryItem[];
    onUpdate: (id: string, updates: Partial<IngredientFormData>) => void;
    onRemove: (id: string) => void;
}> = ({ ingredient, inventoryItems, onUpdate, onRemove }) => {
    const selectedItem = inventoryItems.find(i => i.id === ingredient.inventoryItemId);

    return (
        <div className="flex items-center gap-3 p-3 bg-slate-50 dark:bg-slate-700/50 border border-slate-200 dark:border-slate-600 rounded-lg">
            {/* Item Name */}
            <div className="flex-1 min-w-0">
                <p className="font-medium text-slate-900 dark:text-white truncate">{ingredient.inventoryItemName}</p>
                <p className="text-xs text-slate-500 dark:text-slate-400">
                    {selectedItem?.category} • ₱{ingredient.costPerUnit.toFixed(2)}/{selectedItem ? getItemRecipeUnit(selectedItem) : ''}
                </p>
            </div>

            {/* Quantity Input */}
            <div className="flex items-center gap-2">
                <input
                    type="number"
                    min="0"
                    step="0.01"
                    value={ingredient.quantity || ''}
                    onChange={(e) => onUpdate(ingredient.id, { quantity: parseFloat(e.target.value) || 0 })}
                    className="w-20 px-2 py-1.5 bg-white dark:bg-slate-800 border border-slate-300 dark:border-slate-600 rounded text-slate-900 dark:text-white text-sm text-right focus:ring-2 focus:ring-purple-500 focus:outline-none"
                    placeholder="0"
                />

                {/* Unit Selector */}
                <select
                    value={ingredient.unit}
                    onChange={(e) => onUpdate(ingredient.id, { unit: e.target.value })}
                    className="px-2 py-1.5 bg-white dark:bg-slate-800 border border-slate-300 dark:border-slate-600 rounded text-slate-900 dark:text-white text-sm focus:ring-2 focus:ring-purple-500 focus:outline-none"
                >
                    {ingredient.availableUnits.map(unit => (
                        <option key={unit} value={unit}>{unit}</option>
                    ))}
                </select>
            </div>

            {/* Cost Display */}
            <div className="w-24 text-right">
                <span className="text-cyan-600 dark:text-cyan-400 font-medium">₱{ingredient.totalCost.toFixed(2)}</span>
            </div>

            {/* Remove Button */}
            <button
                onClick={() => onRemove(ingredient.id)}
                className="p-1.5 text-slate-400 hover:text-red-500 dark:hover:text-red-400 hover:bg-red-100 dark:hover:bg-red-500/10 rounded transition-colors"
            >
                <Trash2 size={16} />
            </button>
        </div>
    );
};

// ============================================================
// LIVE COST CARD COMPONENT
// ============================================================

const LiveCostCard: React.FC<{
    totalCost: number;
    sellingPrice: number;
}> = ({ totalCost, sellingPrice }) => {
    const grossMargin = sellingPrice - totalCost;
    const foodCostPercent = sellingPrice > 0 ? (totalCost / sellingPrice) * 100 : 0;
    const marginPercent = sellingPrice > 0 ? (grossMargin / sellingPrice) * 100 : 0;

    const status = getFoodCostStatus(foodCostPercent);
    const textColor = getFoodCostColor(status);
    const bgColor = getFoodCostBgColor(status);

    return (
        <div className={`p-4 rounded-xl border ${bgColor}`}>
            <h4 className="text-sm font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wide mb-3 flex items-center gap-2">
                <PesoSign size={14} />
                Live Costing
            </h4>

            <div className="space-y-3">
                {/* Total Cost */}
                <div className="flex justify-between items-center">
                    <span className="text-slate-600 dark:text-slate-300">Recipe Cost</span>
                    <span className="text-xl font-bold text-slate-900 dark:text-white">
                        ₱{totalCost.toFixed(2)}
                    </span>
                </div>

                {/* Food Cost % */}
                <div className="flex justify-between items-center">
                    <span className="text-slate-300">Food Cost %</span>
                    <span className={`text-xl font-bold ${textColor}`}>
                        {foodCostPercent.toFixed(1)}%
                    </span>
                </div>

                {/* Gross Margin */}
                <div className="flex justify-between items-center pt-2 border-t border-slate-200 dark:border-slate-600/50">
                    <span className="text-slate-600 dark:text-slate-300 flex items-center gap-1">
                        <TrendingUp size={14} />
                        Gross Margin
                    </span>
                    <div className="text-right">
                        <span className="text-lg font-bold text-slate-900 dark:text-white">
                            ₱{grossMargin.toFixed(2)}
                        </span>
                        <span className="text-sm text-slate-500 dark:text-slate-400 ml-2">
                            ({marginPercent.toFixed(1)}%)
                        </span>
                    </div>
                </div>
            </div>

            {/* Status Indicator */}
            <div className={`mt-3 text-xs ${textColor} text-center`}>
                {status === 'excellent' && '✨ Excellent margin!'}
                {status === 'good' && '👍 Good margin'}
                {status === 'warning' && '⚠️ Consider reducing costs'}
                {status === 'danger' && '🚨 Food cost too high!'}
            </div>
        </div>
    );
};

// ============================================================
// MAIN RECIPE EDITOR COMPONENT
// ============================================================

const RecipeEditor: React.FC<RecipeEditorProps> = ({
    isOpen,
    onClose,
    onSave,
    menuItem,
    businessUnitId
}) => {
    // Form state
    const fileInputRef = React.useRef<HTMLInputElement>(null);
    const [name, setName] = useState('');
    const [category, setCategory] = useState<MenuCategory>('Mains');
    const [serviceType, setServiceType] = useState<ServiceType | ''>('');
    const [description, setDescription] = useState('');
    const [sellingPrice, setSellingPrice] = useState(0);
    const [ingredients, setIngredients] = useState<IngredientFormData[]>([]);

    // UI state
    const [inventoryItems, setInventoryItems] = useState<InventoryItem[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [isSaving, setIsSaving] = useState(false);
    const [isImporting, setIsImporting] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [importWarning, setImportWarning] = useState<string | null>(null);

    // Search state for adding ingredients
    const [searchQuery, setSearchQuery] = useState('');
    const [showSearch, setShowSearch] = useState(false);

    const isEditing = !!menuItem;

    // Load inventory items
    useEffect(() => {
        const loadData = async () => {
            if (!businessUnitId) return;

            setIsLoading(true);
            try {
                const items = await InventoryService.getInventory(businessUnitId);
                // Only show RAW_MATERIAL and PRODUCTION items for recipes
                setInventoryItems(items.filter(i =>
                    i.type === 'RAW_MATERIAL' || i.type === 'PRODUCTION'
                ));
            } catch (err) {
                console.error('Error loading inventory:', err);
                setError('Failed to load inventory items');
            } finally {
                setIsLoading(false);
            }
        };

        if (isOpen) {
            loadData();
        }
    }, [businessUnitId, isOpen]);

    // Populate form when editing
    useEffect(() => {
        if (menuItem) {
            setName(menuItem.name);
            setCategory(menuItem.category);
            setServiceType((menuItem as any).serviceType || '');
            setDescription(menuItem.description || '');
            setSellingPrice(menuItem.sellingPrice);

            // Convert existing ingredients to form data
            const formIngredients: IngredientFormData[] = menuItem.ingredients.map((ing, idx) => {
                const invItem = inventoryItems.find(i => i.id === ing.inventoryItemId);
                const recipeUnit = invItem ? getItemRecipeUnit(invItem) : ing.unit;
                return {
                    id: `existing-${idx}`,
                    inventoryItemId: ing.inventoryItemId,
                    inventoryItemName: ing.inventoryItemName,
                    quantity: ing.quantity,
                    unit: ing.unit,
                    availableUnits: getAvailableUnits(recipeUnit),
                    costPerUnit: ing.costPerBaseUnit,
                    totalCost: ing.totalCost
                };
            });
            setIngredients(formIngredients);
        } else {
            // Reset for new item
            setName('');
            setCategory('Mains');
            setServiceType('');
            setDescription('');
            setSellingPrice(0);
            setIngredients([]);
        }
    }, [menuItem, inventoryItems, isOpen]);

    // Calculate total cost
    const totalCost = useMemo(() => {
        return ingredients.reduce((sum, ing) => sum + ing.totalCost, 0);
    }, [ingredients]);

    // Filtered inventory for search
    // Rule: items must match the menu item's service type.
    // Exception: Retail items are universal — always available regardless of service type.
    const filteredInventory = useMemo(() => {
        let items = inventoryItems;

        // Apply service type filter (if a service type is selected and it's not Retail)
        if (serviceType && serviceType !== 'Retail') {
            items = items.filter(item =>
                // Include items with matching service type OR Retail items (universal)
                (item as any).serviceType === serviceType ||
                (item as any).serviceType === 'Retail' ||
                !(item as any).serviceType  // Include unclassified items too
            );
        }

        // Apply search query
        if (!searchQuery) return items;
        const query = searchQuery.toLowerCase();
        return items.filter(item =>
            item.name.toLowerCase().includes(query) ||
            item.category.toLowerCase().includes(query)
        );
    }, [inventoryItems, searchQuery, serviceType]);

    // Add ingredient
    const handleAddIngredient = (item: InventoryItem) => {
        // Check if already added
        if (ingredients.some(ing => ing.inventoryItemId === item.id)) {
            return;
        }

        const recipeUnit = getItemRecipeUnit(item);
        const availableUnits = getAvailableUnits(recipeUnit);
        const defaultUnit = availableUnits.includes('G') ? 'G' :
            availableUnits.includes('ML') ? 'ML' :
                recipeUnit;

        // Use baseCost (per recipe-unit) when available.
        const perBaseUnit = item.baseCost
            ?? (item.buyCost != null && item.units?.conversion > 0
                ? item.buyCost / item.units.conversion
                : item.costPerUnit ?? 0);

        const newIngredient: IngredientFormData = {
            id: `new-${Date.now()}`,
            inventoryItemId: item.id,
            inventoryItemName: item.name,
            quantity: 0,
            unit: defaultUnit,
            availableUnits,
            costPerUnit: perBaseUnit,
            totalCost: 0
        };

        setIngredients([...ingredients, newIngredient]);
        setShowSearch(false);
        setSearchQuery('');
    };

    // Update ingredient
    const handleUpdateIngredient = (id: string, updates: Partial<IngredientFormData>) => {
        setIngredients(prev => prev.map(ing => {
            if (ing.id !== id) return ing;

            const updated = { ...ing, ...updates };

            // Recalculate cost if quantity or unit changed
            if (updates.quantity !== undefined || updates.unit !== undefined) {
                const invItem = inventoryItems.find(i => i.id === updated.inventoryItemId);
                if (invItem) {
                    const { totalCost } = calculateIngredientCost(
                        updated.quantity,
                        updated.unit,
                        invItem
                    );
                    updated.totalCost = totalCost;
                }
            }

            return updated;
        }));
    };

    // Remove ingredient
    const handleRemoveIngredient = (id: string) => {
        setIngredients(prev => prev.filter(ing => ing.id !== id));
    };

    // Smart Import logic
    const handleSmartImport = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        setIsImporting(true);
        setError(null);
        setImportWarning(null);

        try {
            const extracted = await GeminiVisionService.extractRecipeFromDocument(file);

            setName(extracted.name || '');
            if (extracted.category && MENU_CATEGORIES.includes(extracted.category as MenuCategory)) {
                setCategory(extracted.category as MenuCategory);
            }
            if (extracted.procedure) {
                setDescription(extracted.procedure);
            }

            // Match ingredients
            let matchedCount = 0;
            const newIngredients: IngredientFormData[] = [];

            for (const extractedIng of extracted.ingredients) {
                // Try to find a match in inventory
                const searchLower = extractedIng.name.toLowerCase();
                const matchedInvItem = inventoryItems.find(i => 
                    i.name.toLowerCase().includes(searchLower) || searchLower.includes(i.name.toLowerCase())
                );

                if (matchedInvItem) {
                    matchedCount++;
                    const recipeUnit = getItemRecipeUnit(matchedInvItem);
                    const availableUnits = getAvailableUnits(recipeUnit);

                    // Try to match the unit if possible, else use default
                    let matchedUnit = availableUnits.find(u => u.toLowerCase() === extractedIng.unit.toLowerCase());
                    if (!matchedUnit) {
                        matchedUnit = availableUnits.includes('G') ? 'G' :
                                      availableUnits.includes('ML') ? 'ML' : recipeUnit;
                    }

                    const perBaseUnit = matchedInvItem.baseCost
                        ?? (matchedInvItem.buyCost != null && matchedInvItem.units?.conversion > 0
                            ? matchedInvItem.buyCost / matchedInvItem.units.conversion
                            : matchedInvItem.costPerUnit ?? 0);

                    newIngredients.push({
                        id: `import-${Date.now()}-${Math.random()}`,
                        inventoryItemId: matchedInvItem.id,
                        inventoryItemName: matchedInvItem.name,
                        quantity: extractedIng.quantity,
                        unit: matchedUnit,
                        availableUnits,
                        costPerUnit: perBaseUnit,
                        totalCost: 0 // Will be calculated on save or update
                    });
                }
            }

            // Recalculate costs
            const ingredientsWithCosts = newIngredients.map(ing => {
                const invItem = inventoryItems.find(i => i.id === ing.inventoryItemId);
                if (invItem) {
                    const { totalCost } = calculateIngredientCost(ing.quantity, ing.unit, invItem);
                    return { ...ing, totalCost };
                }
                return ing;
            });

            // Append to existing or replace? Let's append
            setIngredients(prev => [...prev, ...ingredientsWithCosts]);

            if (matchedCount < extracted.ingredients.length) {
                setImportWarning(`Imported recipe but only matched ${matchedCount} out of ${extracted.ingredients.length} ingredients. Please add the missing ones manually.`);
            } else {
                setImportWarning(`Successfully imported ${matchedCount} ingredients!`);
            }

        } catch (err: any) {
            console.error('Smart import error:', err);
            setError(err.message || 'Failed to import recipe');
        } finally {
            setIsImporting(false);
            // Reset input so the same file can be selected again if needed
            if (fileInputRef.current) fileInputRef.current.value = '';
        }
    };

    // Handle save
    const handleSave = async () => {
        if (!name.trim()) {
            setError('Please enter a menu item name');
            return;
        }

        if (sellingPrice <= 0) {
            setError('Please enter a valid selling price');
            return;
        }

        if (ingredients.length === 0) {
            setError('Please add at least one ingredient');
            return;
        }

        setIsSaving(true);
        setError(null);

        try {
            const ingredientInputs = ingredients.map(ing => ({
                inventoryItemId: ing.inventoryItemId,
                inventoryItemName: ing.inventoryItemName,
                quantity: ing.quantity,
                unit: ing.unit,
                baseQuantity: 0, // Will be calculated by service
                costPerBaseUnit: ing.costPerUnit,
                totalCost: ing.totalCost
            }));

            if (menuItem) {
                await RecipesService.updateMenuItem(menuItem.id, {
                    name: name.trim(),
                    category,
                    ...(serviceType && { serviceType: serviceType as ServiceType }),
                    description: description.trim() || '',
                    sellingPrice,
                    ingredients: ingredientInputs
                });
            } else {
                await RecipesService.createMenuItem({
                    businessUnitId,
                    name: name.trim(),
                    category,
                    ...(serviceType && { serviceType: serviceType as ServiceType }),
                    description: description.trim() || '',
                    sellingPrice,
                    ingredients: ingredientInputs
                });
            }

            onSave();
            onClose();
        } catch (err: any) {
            console.error('Error saving menu item (Full Details):', err);
            // Log specific Firestore error code if available
            if (err.code) console.error('Firestore Error Code:', err.code);
            if (err.message) console.error('Error Message:', err.message);

            setError(`Failed to save menu item: ${err.message || 'Unknown error'}`);
        } finally {
            setIsSaving(false);
        }
    };

    if (!isOpen) return null;

    const inputClass = "w-full p-2.5 bg-white dark:bg-slate-900/50 border border-slate-300 dark:border-slate-600 rounded-lg text-slate-900 dark:text-white focus:ring-2 focus:ring-purple-500 focus:outline-none placeholder-slate-400 dark:placeholder-slate-500";
    const labelClass = "block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1.5";

    return (
        <>
            {/* Backdrop */}
            <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50" onClick={onClose} />

            {/* Modal */}
            <div className="fixed inset-0 flex items-center justify-center z-50 p-4">
                <div className="bg-white dark:bg-slate-800 rounded-xl shadow-2xl border border-slate-200 dark:border-slate-700 w-full max-w-4xl max-h-[90vh] overflow-hidden flex flex-col">
                    {/* Header */}
                    <div className="flex items-center justify-between p-4 border-b border-slate-200 dark:border-slate-700">
                        <h3 className="text-lg font-bold text-slate-900 dark:text-white flex items-center gap-2">
                            <ChefHat size={20} className="text-purple-600 dark:text-purple-400" />
                            {isEditing ? 'Edit Recipe' : 'Create New Recipe'}
                        </h3>
                        <div className="flex items-center gap-2">
                            <input 
                                type="file" 
                                ref={fileInputRef}
                                className="hidden" 
                                accept="image/*,application/pdf"
                                onChange={handleSmartImport}
                            />
                            <button
                                onClick={() => fileInputRef.current?.click()}
                                disabled={isImporting}
                                className="px-3 py-1.5 bg-indigo-50 dark:bg-indigo-500/10 text-indigo-600 dark:text-indigo-400 hover:bg-indigo-100 dark:hover:bg-indigo-500/20 rounded-lg text-sm font-medium transition-colors flex items-center gap-2"
                            >
                                {isImporting ? <Loader2 size={16} className="animate-spin" /> : <Sparkles size={16} />}
                                Smart Import
                            </button>
                            <button
                                onClick={onClose}
                                className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg text-slate-500 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white transition-colors"
                            >
                                <X size={20} />
                            </button>
                        </div>
                    </div>

                    {/* Content */}
                    <div className="flex-1 overflow-y-auto">
                        {isLoading ? (
                            <div className="flex items-center justify-center h-64">
                                <Loader2 size={32} className="text-purple-400 animate-spin" />
                            </div>
                        ) : (
                            <div className="grid grid-cols-1 lg:grid-cols-5 gap-6 p-6">
                                {/* Left Panel - Basic Info */}
                                <div className="lg:col-span-2 space-y-6">
                                    {/* Error Display */}
                                    {error && (
                                        <div className="p-3 bg-red-900/30 border border-red-700/50 rounded-lg text-red-300 text-sm flex items-center gap-2">
                                            <AlertTriangle size={16} />
                                            {error}
                                        </div>
                                    )}

                                    {/* Warning Display */}
                                    {importWarning && (
                                        <div className="p-3 bg-indigo-900/30 border border-indigo-700/50 rounded-lg text-indigo-300 text-sm flex items-center gap-2">
                                            <Sparkles size={16} />
                                            {importWarning}
                                        </div>
                                    )}

                                    {/* Name */}
                                    <div>
                                        <label className={labelClass}>Menu Item Name *</label>
                                        <input
                                            type="text"
                                            value={name}
                                            onChange={(e) => setName(e.target.value)}
                                            className={inputClass}
                                            placeholder="e.g., Classic Margarita"
                                        />
                                    </div>

                                    {/* Category */}
                                    <div>
                                        <label className={labelClass}>Category</label>
                                        <select
                                            value={category}
                                            onChange={(e) => setCategory(e.target.value as MenuCategory)}
                                            className={inputClass}
                                        >
                                            {MENU_CATEGORIES.map(cat => (
                                                <option key={cat} value={cat} className="bg-white dark:bg-slate-800">{cat}</option>
                                            ))}
                                        </select>
                                    </div>

                                    {/* Service Type */}
                                    <div>
                                        <label className={labelClass}>Service Type</label>
                                        <select
                                            value={serviceType}
                                            onChange={(e) => setServiceType(e.target.value as ServiceType | '')}
                                            className={inputClass}
                                        >
                                            <option value="">— Select —</option>
                                            {SERVICE_TYPES.map(st => (
                                                <option key={st} value={st} className="bg-white dark:bg-slate-800">{st}</option>
                                            ))}
                                        </select>
                                        <p className="text-xs text-slate-500 dark:text-slate-400 mt-1">Alacarte or Event classification</p>
                                    </div>

                                    {/* Description */}
                                    <div>
                                        <label className={labelClass}>Description</label>
                                        <textarea
                                            value={description}
                                            onChange={(e) => setDescription(e.target.value)}
                                            className={`${inputClass} min-h-[80px] resize-y`}
                                            placeholder="Brief description of the dish..."
                                        />
                                    </div>

                                    {/* Selling Price */}
                                    <div>
                                        <label className={labelClass}>Selling Price (₱) *</label>
                                        <input
                                            type="number"
                                            min="0"
                                            step="0.01"
                                            value={sellingPrice || ''}
                                            onChange={(e) => setSellingPrice(parseFloat(e.target.value) || 0)}
                                            className={inputClass}
                                            placeholder="0.00"
                                        />
                                    </div>

                                    {/* Live Cost Card */}
                                    <LiveCostCard
                                        totalCost={totalCost}
                                        sellingPrice={sellingPrice}
                                    />
                                </div>

                                {/* Right Panel - Ingredients */}
                                <div className="lg:col-span-3 space-y-4">
                                    <div className="flex items-center justify-between">
                                        <h4 className="text-sm font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wide flex items-center gap-2">
                                            <Package size={14} />
                                            Ingredients ({ingredients.length})
                                        </h4>
                                        <button
                                            onClick={() => setShowSearch(true)}
                                            className="px-3 py-1.5 bg-purple-600 hover:bg-purple-700 text-white rounded-lg text-sm font-medium flex items-center gap-1 transition-colors"
                                        >
                                            <Plus size={14} />
                                            Add
                                        </button>
                                    </div>

                                    {/* Ingredient Search */}
                                    {showSearch && (
                                        <div className="bg-slate-100 dark:bg-slate-700/50 rounded-lg p-3 space-y-3 border border-slate-200 dark:border-slate-600">
                                            <div className="relative">
                                                <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 dark:text-slate-400" />
                                                <input
                                                    type="text"
                                                    value={searchQuery}
                                                    onChange={(e) => setSearchQuery(e.target.value)}
                                                    className="w-full pl-9 pr-4 py-2 bg-white dark:bg-slate-800 border border-slate-300 dark:border-slate-600 rounded-lg text-slate-900 dark:text-white text-sm placeholder-slate-400 dark:placeholder-slate-500 focus:ring-2 focus:ring-purple-500 focus:outline-none"
                                                    placeholder="Search ingredients..."
                                                    autoFocus
                                                />
                                            </div>

                                            {/* Service type filter notice */}
                                            {serviceType && (
                                                <div className="flex items-center gap-2 px-2 py-1.5 bg-indigo-500/10 border border-indigo-500/20 rounded-lg">
                                                    <span className={`text-[10px] font-bold uppercase px-1.5 py-0.5 rounded ${
                                                        serviceType === 'Alacarte'
                                                            ? 'bg-indigo-500/20 text-indigo-400'
                                                            : 'bg-teal-500/20 text-teal-400'
                                                    }`}>{serviceType}</span>
                                                    <p className="text-xs text-slate-500 dark:text-slate-400">
                                                        Showing <span className="font-medium text-slate-700 dark:text-slate-300">{serviceType}</span> & Retail items only
                                                    </p>
                                                </div>
                                            )}

                                            <div className="max-h-48 overflow-y-auto space-y-1">
                                                {filteredInventory.length === 0 ? (
                                                    <p className="text-sm text-slate-500 dark:text-slate-400 text-center py-4">
                                                        No ingredients found
                                                    </p>
                                                ) : (
                                                    filteredInventory.map(item => (
                                                        <button
                                                            key={item.id}
                                                            onClick={() => handleAddIngredient(item)}
                                                            disabled={ingredients.some(ing => ing.inventoryItemId === item.id)}
                                                            className="w-full flex items-center justify-between p-2 rounded hover:bg-slate-200 dark:hover:bg-slate-600/50 disabled:opacity-50 disabled:cursor-not-allowed transition-colors text-left"
                                                        >
                                                            <div>
                                                                <p className="text-slate-900 dark:text-white text-sm">{item.name}</p>
                                                                <p className="text-xs text-slate-500 dark:text-slate-400">{item.category}</p>
                                                            </div>
                                                            <span className="text-xs text-slate-500 dark:text-slate-500">
                                                                ₱{(item.baseCost ?? item.costPerUnit ?? 0).toFixed(2)}/{getItemRecipeUnit(item)}
                                                            </span>
                                                        </button>
                                                    ))
                                                )}
                                            </div>

                                            <button
                                                onClick={() => { setShowSearch(false); setSearchQuery(''); }}
                                                className="w-full py-1.5 text-sm text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-white transition-colors"
                                            >
                                                Cancel
                                            </button>
                                        </div>
                                    )}

                                    {/* Ingredients List */}
                                    <div className="space-y-2">
                                        {ingredients.length === 0 ? (
                                            <div className="text-center py-12 bg-slate-50 dark:bg-slate-700/30 rounded-lg border border-dashed border-slate-300 dark:border-slate-600">
                                                <Package size={32} className="mx-auto text-slate-400 dark:text-slate-500 mb-2" />
                                                <p className="text-slate-500 dark:text-slate-400 text-sm">No ingredients added yet</p>
                                                <p className="text-slate-400 dark:text-slate-500 text-xs mt-1">Click "Add" to add ingredients</p>
                                            </div>
                                        ) : (
                                            ingredients.map(ing => (
                                                <IngredientRow
                                                    key={ing.id}
                                                    ingredient={ing}
                                                    inventoryItems={inventoryItems}
                                                    onUpdate={handleUpdateIngredient}
                                                    onRemove={handleRemoveIngredient}
                                                />
                                            ))
                                        )}
                                    </div>

                                    {/* Summary Row */}
                                    {ingredients.length > 0 && (
                                        <div className="flex items-center justify-between p-3 bg-white dark:bg-slate-900/50 rounded-lg border border-slate-200 dark:border-slate-600 shadow-sm dark:shadow-none">
                                            <span className="font-medium text-slate-700 dark:text-white">Total Ingredient Cost</span>
                                            <span className="text-xl font-bold text-cyan-600 dark:text-cyan-400">
                                                ₱{totalCost.toFixed(2)}
                                            </span>
                                        </div>
                                    )}
                                </div>
                            </div>
                        )}
                    </div>

                    {/* Footer */}
                    <div className="flex justify-end gap-3 p-4 border-t border-slate-200 dark:border-slate-700">
                        <button
                            onClick={onClose}
                            className="px-4 py-2.5 bg-slate-100 dark:bg-slate-700 hover:bg-slate-200 dark:hover:bg-slate-600 text-slate-700 dark:text-white rounded-lg transition-colors"
                        >
                            Cancel
                        </button>
                        <button
                            onClick={handleSave}
                            disabled={isSaving || isLoading}
                            className="px-6 py-2.5 bg-gradient-to-r from-purple-600 to-cyan-500 hover:opacity-90 text-white rounded-lg flex items-center gap-2 transition-all disabled:opacity-50"
                        >
                            {isSaving ? (
                                <Loader2 size={18} className="animate-spin" />
                            ) : (
                                <Save size={18} />
                            )}
                            {isSaving ? 'Saving...' : isEditing ? 'Update Recipe' : 'Create Recipe'}
                        </button>
                    </div>
                </div>
            </div>
        </>
    );
};

export default RecipeEditor;

import React, { useState } from 'react';
import { X, Plus, Trash2, ChefHat, AlertTriangle, CheckSquare, FileEdit } from 'lucide-react';
import type { 
    BlackBookRecipe,
    PrepStation 
} from '../types/blackbook.types';
import { PREP_STATIONS } from '../types/blackbook.types';
import { BlackBookService } from '../services/blackbook.service';
import type { User } from '../../procurement/types';

interface UpdateBlackBookVersionModalProps {
    isOpen: boolean;
    onClose: () => void;
    onRecipeUpdated: () => void;
    recipe: BlackBookRecipe;
    currentUser: User;
}

const UpdateBlackBookVersionModal: React.FC<UpdateBlackBookVersionModalProps> = ({ 
    isOpen, 
    onClose, 
    onRecipeUpdated,
    recipe,
    currentUser
}) => {
    // We only need fields that are editable, omitting id, createdAt, version, approvalStatus, etc.
    const [formData, setFormData] = useState<Partial<Omit<BlackBookRecipe, 'id' | 'createdAt'>>>({
        name: recipe.name,
        prepStation: recipe.prepStation,
        batchYield: recipe.batchYield,
        cookTempTime: recipe.cookTempTime,
        costPerServing: recipe.costPerServing,
        ingredients: recipe.ingredients,
        methodSteps: recipe.methodSteps,
        mistakesFixes: recipe.mistakesFixes,
        qualityChecklist: recipe.qualityChecklist,
        platingPhotoUrl: recipe.platingPhotoUrl || '',
        trainingVideoUrl: recipe.trainingVideoUrl || '',
        youtubeVideoUrl: recipe.youtubeVideoUrl || ''
    });

    const [versionDescription, setVersionDescription] = useState('');
    const [isSaving, setIsSaving] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const handleSave = async () => {
        try {
            setError(null);
            if (!formData.name) throw new Error("Recipe name is required");
            if (!versionDescription.trim()) throw new Error("Reason for update is required for the version log.");

            setIsSaving(true);

            // Clean up empty steps/items
            const cleanData = {
                ...formData,
                methodSteps: (formData.methodSteps || []).filter(s => s.instruction.trim()),
                mistakesFixes: (formData.mistakesFixes || []).filter(m => m.mistake.trim()),
                qualityChecklist: (formData.qualityChecklist || []).filter(q => q.label.trim())
            };

            // Ensure step numbers are sequential
            cleanData.methodSteps.forEach((step, idx) => {
                step.stepNumber = idx + 1;
            });

            await BlackBookService.updateRecipe(
                recipe.id, 
                cleanData, 
                versionDescription, 
                currentUser.name
            );

            onRecipeUpdated();
            onClose();
        } catch (err: any) {
            setError(err.message || "Failed to update recipe");
        } finally {
            setIsSaving(false);
        }
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex justify-end">
            <div className="bg-[#faf8f5] dark:bg-slate-900 w-full max-w-4xl h-full shadow-2xl flex flex-col animate-slide-in-right border-l border-[#e8e0d4] dark:border-slate-700">
                {/* Header */}
                <div className="flex items-center justify-between px-6 py-4 border-b border-[#e8e0d4] dark:border-slate-700 bg-white dark:bg-slate-800 shrink-0">
                    <div>
                        <h2 className="text-xl font-bold text-slate-800 dark:text-white">Update Recipe Version</h2>
                        <p className="text-sm text-slate-500 dark:text-slate-400">Create a new version of {recipe.recipeId}</p>
                    </div>
                    <div className="flex items-center gap-3">
                        <button onClick={onClose} className="p-2 text-slate-400 hover:text-slate-600 dark:hover:text-slate-300 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors">
                            <X size={20} />
                        </button>
                    </div>
                </div>

                {/* Form Body */}
                <div className="flex-1 overflow-y-auto p-6 space-y-8">
                    {error && (
                        <div className="bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 p-4 rounded-lg text-sm border border-red-100 dark:border-red-900/30 flex items-center gap-2">
                            <AlertTriangle size={16} />
                            {error}
                        </div>
                    )}

                    {/* Version Reason (Required) */}
                    <section className="bg-amber-50 dark:bg-amber-900/20 p-6 rounded-xl border border-amber-200 dark:border-amber-700/50 shadow-sm space-y-4">
                        <h3 className="text-sm font-bold text-amber-800 dark:text-amber-200 flex items-center gap-2">
                            <FileEdit size={16} />
                            Version Update Log
                        </h3>
                        <div>
                            <label className="block text-xs font-medium text-amber-800 dark:text-amber-300 mb-1">Reason for update / What's new? *</label>
                            <textarea
                                value={versionDescription}
                                onChange={e => setVersionDescription(e.target.value)}
                                className="w-full px-3 py-2 bg-white dark:bg-slate-800 border border-amber-200 dark:border-amber-700/50 rounded-lg text-slate-800 dark:text-white focus:ring-2 focus:ring-amber-500/50 outline-none"
                                rows={2}
                                placeholder="e.g. Adjusted batch yield from 10 to 12 portions, updated cooking time."
                            />
                        </div>
                    </section>

