import React, { useState, useEffect } from 'react';
import { collection, query, where, onSnapshot, orderBy, limit } from 'firebase/firestore';
import { db } from '../../../config/firebase';
import type { RunningBill, POSOrder } from '../types/pos.types';
import { Clock, ChefHat, CheckSquare } from 'lucide-react';

interface KitchenDisplayViewProps {
    businessUnitId: string;
}

type KitchenTicket = {
    id: string;
    title: string; // Table Name or Order Number
    type: 'table' | 'counter';
    items: { name: string; quantity: number; notes?: string }[];
    timestamp: Date;
    status: 'pending' | 'completed'; // Simplified status
};

export const KitchenDisplayView: React.FC<KitchenDisplayViewProps> = ({ businessUnitId }) => {
    const [tickets, setTickets] = useState<KitchenTicket[]>([]);

    useEffect(() => {
        if (!businessUnitId) return;

        const openBillsQuery = query(
            collection(db, 'pos_running_bills'),
            where('businessUnitId', '==', businessUnitId),
            where('status', '==', 'OPEN')
        );

        const counterOrdersQuery = query(
            collection(db, 'pos_orders'),
            where('businessUnitId', '==', businessUnitId),
            where('status', '==', 'COMPLETED'), // Assuming counter orders are completed when paid
            orderBy('createdAt', 'desc'),
            limit(10)
        );

        const unsubscribeBills = onSnapshot(openBillsQuery, (snapshot) => {
            const bills = snapshot.docs.map(doc => {
                const data = doc.data() as RunningBill;
                return {
                    id: doc.id,
                    title: `Table: ${data.tableName}`,
                    type: 'table' as const,
                    items: data.items.map(i => ({ name: i.productName, quantity: i.quantity, notes: i.notes })),
                    timestamp: data.updatedAt?.toDate() || new Date(),
                    status: 'pending' as const
                };
            });
            updateTickets(prev => mergeTickets(prev, bills, 'table'));
        });

        const unsubscribeOrders = onSnapshot(counterOrdersQuery, (snapshot) => {
            const orders = snapshot.docs.map(doc => {
                const data = doc.data() as POSOrder;
                return {
                    id: doc.id,
                    title: `Order: ${data.orderNumber}`,
                    type: 'counter' as const,
                    items: data.items.map(i => ({ name: i.productName, quantity: i.quantity, notes: i.notes })),
                    timestamp: data.createdAt?.toDate() || new Date(),
                    status: 'pending' as const
                };
            });
            updateTickets(prev => mergeTickets(prev, orders, 'counter'));
        });

        return () => {
            unsubscribeBills();
            unsubscribeOrders();
        };
    }, [businessUnitId]);

    // Helper to merge live streams
    const mergeTickets = (prev: KitchenTicket[], incoming: KitchenTicket[], type: 'table' | 'counter') => {
        const filtered = prev.filter(t => t.type !== type);
        return [...filtered, ...incoming].sort((a, b) => b.timestamp.getTime() - a.timestamp.getTime());
    };

    const updateTickets = (updater: (prev: KitchenTicket[]) => KitchenTicket[]) => {
        setTickets(updater);
    };

    const formatTime = (date: Date) => {
        return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    };

    return (
        <div className="flex flex-col h-full bg-slate-900 overflow-hidden">
            <div className="h-16 flex items-center justify-between px-6 bg-slate-800 border-b border-slate-700 shrink-0">
                <div className="flex items-center gap-3 text-white">
                    <ChefHat className="w-6 h-6 text-amber-500" />
                    <h1 className="text-xl font-bold">Kitchen Display</h1>
                </div>
            </div>

            <div className="flex-1 overflow-x-auto overflow-y-hidden p-6">
                <div className="flex gap-6 h-full items-start">
                    {tickets.map(ticket => (
                        <div key={ticket.id} className="w-80 shrink-0 bg-slate-800 rounded-2xl border border-slate-700 flex flex-col h-full max-h-full overflow-hidden shadow-xl">
                            {/* Ticket Header */}
                            <div className={`p-4 border-b ${ticket.type === 'table' ? 'bg-indigo-500/10 border-indigo-500/20' : 'bg-emerald-500/10 border-emerald-500/20'}`}>
                                <div className="flex justify-between items-center mb-1">
                                    <h3 className={`font-bold text-lg ${ticket.type === 'table' ? 'text-indigo-400' : 'text-emerald-400'}`}>
                                        {ticket.title}
                                    </h3>
                                    <span className="text-slate-400 text-sm flex items-center gap-1">
                                        <Clock className="w-4 h-4" />
                                        {formatTime(ticket.timestamp)}
                                    </span>
                                </div>
                                <span className="text-xs text-slate-500 uppercase tracking-widest font-bold">
                                    {ticket.type === 'table' ? 'Dine In' : 'Takeout / Counter'}
                                </span>
                            </div>

                            {/* Ticket Items */}
                            <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar">
                                {ticket.items.map((item, idx) => (
                                    <div key={idx} className="flex gap-3 text-slate-300">
                                        <div className="font-bold text-lg min-w-[2ch]">{item.quantity}x</div>
                                        <div className="flex-1">
                                            <div className="font-medium text-lg leading-tight">{item.name}</div>
                                            {item.notes && (
                                                <div className="text-sm text-amber-400/80 mt-1 italic">
                                                    Note: {item.notes}
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                ))}
                            </div>

                            {/* Ticket Footer (Actions) */}
                            <div className="p-4 border-t border-slate-700 bg-slate-800/50 mt-auto">
                                <button className="w-full flex justify-center items-center gap-2 bg-emerald-500/10 hover:bg-emerald-500/20 text-emerald-400 font-bold py-3 rounded-xl border border-emerald-500/20 transition-colors">
                                    <CheckSquare className="w-5 h-5" />
                                    Mark Done (Local)
                                </button>
                            </div>
                        </div>
                    ))}

                    {tickets.length === 0 && (
                        <div className="flex-1 flex flex-col items-center justify-center text-slate-500 h-full">
                            <ChefHat className="w-16 h-16 mb-4 opacity-50" />
                            <p className="text-2xl font-bold">No Active Orders</p>
                            <p className="text-sm mt-2">Waiting for new tickets...</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { useAuth } from '../../../contexts/useAuth';
import { POSReportsService, type ShiftReport } from '../services/pos-reports.service';
import { POSPrinterService, type PrinterConnectionType } from '../services/pos-printer.service';
import { Printer, RefreshCw, FileText, AlertCircle, Loader2, X } from 'lucide-react';
import { formatCurrency } from '../../../shared/utils/currency';
import { format } from 'date-fns';

interface POSReportsModalProps {
    isOpen: boolean;
    onClose: () => void;
    activeCashierName?: string;
}

export const POSReportsModal: React.FC<POSReportsModalProps> = ({ isOpen, onClose, activeCashierName }) => {
    const { currentUser } = useAuth();
    const [report, setReport] = useState<ShiftReport | null>(null);
    const [isLoading, setIsLoading] = useState(false);
    const [isPrinting, setIsPrinting] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const loadReport = async () => {
        if (!currentUser?.businessId) return;
        setIsLoading(true);
        setError(null);
        try {
            const { start, end } = POSReportsService.getTodayRange();
            const data = await POSReportsService.generateShiftReport(currentUser.businessId, start, end);
            setReport(data);
        } catch (err: any) {
            console.error(err);
            setError('Failed to load shift report.');
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        if (isOpen) {
            loadReport();
        }
    }, [isOpen, currentUser?.businessId]);

    if (!isOpen) return null;

    const handlePrint = async (type: 'X-READING' | 'Z-READING') => {
        if (!report) return;
        setIsPrinting(true);
        setError(null);
        try {
            const savedPrinter = localStorage.getItem('pos_printer_type') as PrinterConnectionType || 'simulator';
            const savedIp = localStorage.getItem('pos_printer_ip') || '';

            if (savedPrinter === 'bluetooth') {
                await POSPrinterService.connectBluetooth();
            }

            let text = `=== ${type} ===\n`;
            text += `Date: ${format(new Date(), 'MM/dd/yyyy HH:mm')}\n`;
            text += `Terminal: POS-01\n`;
            text += `Cashier: ${activeCashierName || currentUser?.name || 'System'}\n`;
            text += `--------------------------------\n`;
            text += `Gross Sales:        ${formatCurrency(report.grossSales)}\n`;
            text += `Net Sales:          ${formatCurrency(report.netSales)}\n`;
            text += `--------------------------------\n`;
            text += `VATable Sales:      ${formatCurrency(report.vatableSales)}\n`;
            text += `VAT Amount (12%):   ${formatCurrency(report.vatAmount)}\n`;
            text += `VAT Exempt Sales:   ${formatCurrency(report.vatExemptSales)}\n`;
            text += `Zero-Rated Sales:   ${formatCurrency(report.zeroRatedSales)}\n`;
            text += `--------------------------------\n`;
            text += `Service Charge:     ${formatCurrency(report.serviceChargeTotal)}\n`;
            text += `SC/PWD Discount:    ${formatCurrency(report.scPwdDiscountTotal)}\n`;
            text += `Manual Discount:    ${formatCurrency(report.manualDiscountTotal)}\n`;
            text += `--------------------------------\n`;
            text += `Cash Total:         ${formatCurrency(report.cashTotal)}\n`;
            text += `Card Total:         ${formatCurrency(report.cardTotal)}\n`;
            text += `E-Wallet Total:     ${formatCurrency(report.eWalletTotal)}\n`;
            text += `--------------------------------\n`;
            text += `Total Transactions: ${report.totalTransactions}\n`;
            text += `\n\n\n`;

            const payload = POSPrinterService.generateReceiptPayload(text);
            await POSPrinterService.print({ type: savedPrinter, ipAddress: savedIp }, payload);

        } catch (err: any) {
            console.error(err);
            setError(err.message || 'Failed to print report.');
        } finally {
            setIsPrinting(false);
        }
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-sm animate-in fade-in duration-200">
            <div className="bg-slate-800 rounded-2xl w-full max-w-4xl shadow-2xl border border-slate-700 flex flex-col max-h-[90vh]">
                <div className="flex items-center justify-between p-6 border-b border-slate-700 shrink-0">
                    <div>
                        <h2 className="text-xl font-bold text-white">Shift & Reports</h2>
                        <p className="text-sm text-slate-400">BIR Mandatory Reporting (End of Day)</p>
                    </div>
                    <div className="flex gap-2">
                        <button
                            onClick={loadReport}
                            disabled={isLoading}
                            className="p-2 text-slate-400 hover:text-white hover:bg-slate-700 rounded-xl transition-colors"
                            title="Refresh"
                        >
                            <RefreshCw size={20} className={isLoading ? "animate-spin" : ""} />
                        </button>
                        <button
                            onClick={onClose}
                            className="p-2 text-slate-400 hover:text-white hover:bg-slate-700 rounded-xl transition-colors"
                        >
                            <X size={20} />
                        </button>
                    </div>
                </div>

                <div className="p-6 overflow-y-auto">
                    {error && (
                        <div className="flex items-center gap-2 p-4 mb-6 text-sm text-red-400 bg-red-500/10 border border-red-500/20 rounded-xl">
                            <AlertCircle size={18} />
                            <p>{error}</p>
                        </div>
                    )}

                    {isLoading && !report ? (
                        <div className="flex items-center justify-center min-h-[300px]">
                            <Loader2 className="w-8 h-8 animate-spin text-indigo-500" />
                        </div>
                    ) : report ? (
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            <div className="space-y-6">
                                <div className="bg-slate-900/50 rounded-2xl border border-slate-700 p-6">
                                    <h3 className="text-sm font-semibold text-slate-400 mb-4 uppercase tracking-wider">Sales Summary</h3>

                                    <div className="space-y-4">
                                        <div className="flex justify-between items-end">
                                            <span className="text-slate-300">Gross Sales</span>
                                            <span className="text-lg font-medium text-white">{formatCurrency(report.grossSales)}</span>
                                        </div>
                                        <div className="flex justify-between items-end">
                                            <span className="text-slate-300">Net Sales</span>
                                            <span className="text-2xl font-bold text-emerald-400">{formatCurrency(report.netSales)}</span>
                                        </div>
                                    </div>
                                </div>

                                <div className="bg-slate-900/50 rounded-2xl border border-slate-700 p-6">
                                    <h3 className="text-sm font-semibold text-slate-400 mb-4 uppercase tracking-wider">VAT Breakdown</h3>

                                    <div className="space-y-3">
                                        <div className="flex justify-between text-sm">
                                            <span className="text-slate-400">VATable Sales</span>
                                            <span className="text-white font-medium">{formatCurrency(report.vatableSales)}</span>
                                        </div>
                                        <div className="flex justify-between text-sm">
                                            <span className="text-slate-400">VAT Amount (12%)</span>
                                            <span className="text-white font-medium">{formatCurrency(report.vatAmount)}</span>
                                        </div>
                                        <div className="flex justify-between text-sm">
                                            <span className="text-slate-400">VAT Exempt Sales</span>
                                            <span className="text-white font-medium">{formatCurrency(report.vatExemptSales)}</span>
                                        </div>
                                        <div className="flex justify-between text-sm">
                                            <span className="text-slate-400">Zero-Rated Sales</span>
                                            <span className="text-white font-medium">{formatCurrency(report.zeroRatedSales)}</span>
                                        </div>
                                    </div>
                                </div>
                            </div>

                            <div className="space-y-6">
                                <div className="bg-slate-900/50 rounded-2xl border border-slate-700 p-6">
                                    <h3 className="text-sm font-semibold text-slate-400 mb-4 uppercase tracking-wider">Tender Breakdown</h3>

                                    <div className="space-y-3 mb-6">
                                        <div className="flex justify-between text-sm">
                                            <span className="text-slate-400">Cash</span>
                                            <span className="text-white font-medium">{formatCurrency(report.cashTotal)}</span>
                                        </div>
                                        <div className="flex justify-between text-sm">
                                            <span className="text-slate-400">Card</span>
                                            <span className="text-white font-medium">{formatCurrency(report.cardTotal)}</span>
                                        </div>
                                        <div className="flex justify-between text-sm">
                                            <span className="text-slate-400">E-Wallet</span>
                                            <span className="text-white font-medium">{formatCurrency(report.eWalletTotal)}</span>
                                        </div>
                                    </div>

                                    <div className="pt-4 border-t border-slate-700 flex justify-between items-center">
                                        <span className="text-sm text-slate-400">Total Transactions</span>
                                        <span className="text-lg font-bold text-white">{report.totalTransactions}</span>
                                    </div>
                                </div>

                                <div className="grid grid-cols-2 gap-4">
                                    <button
                                        onClick={() => handlePrint('X-READING')}
                                        disabled={isPrinting}
                                        className="flex flex-col items-center justify-center p-4 bg-indigo-500/10 hover:bg-indigo-500/20 text-indigo-400 border border-indigo-500/30 rounded-2xl transition-all disabled:opacity-50"
                                    >
                                        <FileText className="w-8 h-8 mb-2" />
                                        <span className="font-semibold">Print X-Reading</span>
                                        <span className="text-xs text-indigo-400/70 mt-1">Mid-day Snapshot</span>
                                    </button>

                                    <button
                                        onClick={() => handlePrint('Z-READING')}
                                        disabled={isPrinting}
                                        className="flex flex-col items-center justify-center p-4 bg-white hover:bg-slate-100 text-slate-900 border border-slate-200 rounded-2xl transition-all disabled:opacity-50"
                                    >
                                        <Printer className="w-8 h-8 mb-2" />
                                        <span className="font-semibold">Print Z-Reading</span>
                                        <span className="text-xs text-slate-500 mt-1">End of Day Close</span>
                                    </button>
                                </div>
                            </div>
                        </div>
                    ) : null}
                </div>
            </div>
        </div>
    );
};
export default POSReportsModal;

import React, { useState, useEffect } from 'react';
import { X, Save, AlertCircle, Loader2, Printer, Wifi, Bluetooth, Monitor } from 'lucide-react';
import { SettingsService } from '../../../shared/services/settings.service';
import { useAuth } from '../../../contexts/useAuth';
import { POSPrinterService, type PrinterConnectionType } from '../services/pos-printer.service';

interface POSSettingsModalProps {
    isOpen: boolean;
    onClose: () => void;
}

const POSSettingsModal: React.FC<POSSettingsModalProps> = ({ isOpen, onClose }) => {
    const { currentUser } = useAuth();
    const [vatRate, setVatRate] = useState<number>(12);
    const [serviceChargeRate, setServiceChargeRate] = useState<number>(0);
    const [printerType, setPrinterType] = useState<PrinterConnectionType>('simulator');
    const [printerIp, setPrinterIp] = useState<string>('192.168.1.100');

    const [isSaving, setIsSaving] = useState(false);
    const [isTestingPrinter, setIsTestingPrinter] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [success, setSuccess] = useState(false);

    useEffect(() => {
        if (isOpen) {
            const loadSettings = async () => {
                const settings = await SettingsService.getPOSSettings();
                if (settings.vatRate !== undefined) {
                    setVatRate(settings.vatRate);
                }
                if (settings.serviceChargeRate !== undefined) {
                    setServiceChargeRate(settings.serviceChargeRate);
                }

                const savedPrinter = localStorage.getItem('pos_printer_type');
                if (savedPrinter) setPrinterType(savedPrinter as PrinterConnectionType);
                const savedIp = localStorage.getItem('pos_printer_ip');
                if (savedIp) setPrinterIp(savedIp);
            };
            loadSettings();
            setSuccess(false);
            setError(null);
        }
    }, [isOpen]);

    if (!isOpen) return null;

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        setError(null);
        setSuccess(false);

        if (vatRate < 0 || vatRate > 100) {
            setError('VAT rate must be between 0 and 100');
            return;
        }

        if (serviceChargeRate < 0 || serviceChargeRate > 100) {
            setError('Service Charge rate must be between 0 and 100');
            return;
        }

        setIsSaving(true);
        try {
            await SettingsService.updatePOSSettings(
                { 
                    vatRate,
                    serviceChargeRate 
                },
                currentUser?.id,
                currentUser?.name
            );

            localStorage.setItem('pos_printer_type', printerType);
            localStorage.setItem('pos_printer_ip', printerIp);

            setSuccess(true);
            setTimeout(() => {
                setSuccess(false);
                onClose();
            }, 1500);
        } catch (err) {
            console.error('Error updating POS Settings:', err);
            setError('Failed to update settings. Please try again.');
        } finally {
            setIsSaving(false);
        }
    };

    const handleTestPrint = async () => {
        setError(null);
        setIsTestingPrinter(true);
        try {
            if (printerType === 'bluetooth') {
                await POSPrinterService.connectBluetooth();
            }
            const payload = POSPrinterService.generateReceiptPayload("=== FUN GUYS POS ===\n\nTest Print Successful!\nThank you.\n\n");
            await POSPrinterService.print({ type: printerType, ipAddress: printerIp }, payload);
        } catch (err: any) {
            setError(err.message || 'Failed to print test receipt.');
        } finally {
            setIsTestingPrinter(false);
        }
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-sm animate-in fade-in duration-200">
            <div className="bg-slate-800 rounded-2xl w-full max-w-2xl shadow-2xl border border-slate-700 flex flex-col max-h-[90vh]">
                <div className="flex items-center justify-between p-6 border-b border-slate-700">
                    <h2 className="text-xl font-bold text-white">POS Configuration</h2>
                    <button
                        onClick={onClose}
                        className="p-2 text-slate-400 hover:text-white hover:bg-slate-700 rounded-xl transition-colors"
                    >
                        <X size={20} />
                    </button>
                </div>

                <div className="p-6 overflow-y-auto">
                    <form onSubmit={handleSave} className="space-y-6">
                        {error && (
                            <div className="flex items-center gap-2 p-3 text-sm text-red-400 bg-red-500/10 border border-red-500/20 rounded-xl">
                                <AlertCircle size={16} />
                                <p>{error}</p>
                            </div>
                        )}

                        {success && (
                            <div className="flex items-center gap-2 p-3 text-sm text-emerald-400 bg-emerald-500/10 border border-emerald-500/20 rounded-xl">
                                <p>Settings saved successfully!</p>
                            </div>
                        )}

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div>
                                <label className="block text-sm font-medium text-slate-300 mb-2">VAT Rate (%)</label>
                                <input
                                    type="number"
                                    value={vatRate}
                                    onChange={(e) => setVatRate(Number(e.target.value))}
                                    className="w-full rounded-xl border border-slate-600 bg-slate-900/50 text-white px-4 py-2.5 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-300 mb-2">Service Charge Rate (%)</label>
                                <input
                                    type="number"
                                    value={serviceChargeRate}
                                    onChange={(e) => setServiceChargeRate(Number(e.target.value))}
                                    className="w-full rounded-xl border border-slate-600 bg-slate-900/50 text-white px-4 py-2.5 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
                                />
                            </div>
                        </div>

                        <div className="pt-6 border-t border-slate-700">
                            <h3 className="text-lg font-semibold text-white mb-4 flex items-center gap-2">
                                <Printer className="w-5 h-5 text-slate-400" />
                                Hardware Configuration (This Device)
                            </h3>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-medium text-slate-300 mb-2">Printer Connection</label>
                                    <div className="grid grid-cols-3 gap-2">
                                        <button
                                            type="button"
                                            onClick={() => setPrinterType('simulator')}
                                            className={`flex flex-col items-center justify-center p-2 rounded-xl border ${printerType === 'simulator' ? 'bg-indigo-500/20 border-indigo-500 text-indigo-300' : 'bg-slate-900/50 border-slate-600 text-slate-400 hover:bg-slate-800'}`}
                                        >
                                            <Monitor className="w-4 h-4 mb-1" />
                                            <span className="text-[10px] font-medium">Simulator</span>
                                        </button>
                                        <button
                                            type="button"
                                            onClick={() => setPrinterType('bluetooth')}
                                            className={`flex flex-col items-center justify-center p-2 rounded-xl border ${printerType === 'bluetooth' ? 'bg-indigo-500/20 border-indigo-500 text-indigo-300' : 'bg-slate-900/50 border-slate-600 text-slate-400 hover:bg-slate-800'}`}
                                        >
                                            <Bluetooth className="w-4 h-4 mb-1" />
                                            <span className="text-[10px] font-medium">Bluetooth</span>
                                        </button>
                                        <button
                                            type="button"
                                            onClick={() => setPrinterType('lan')}
                                            className={`flex flex-col items-center justify-center p-2 rounded-xl border ${printerType === 'lan' ? 'bg-indigo-500/20 border-indigo-500 text-indigo-300' : 'bg-slate-900/50 border-slate-600 text-slate-400 hover:bg-slate-800'}`}
                                        >
                                            <Wifi className="w-4 h-4 mb-1" />
                                            <span className="text-[10px] font-medium">LAN / IP</span>
                                        </button>
                                    </div>
                                </div>

                                {printerType === 'lan' && (
                                    <div>
                                        <label className="block text-sm font-medium text-slate-300 mb-2">Printer IP Address</label>
                                        <input
                                            type="text"
                                            value={printerIp}
                                            onChange={(e) => setPrinterIp(e.target.value)}
                                            placeholder="192.168.1.100"
                                            className="w-full rounded-xl border border-slate-600 bg-slate-900/50 text-white px-4 py-2 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
                                        />
                                    </div>
                                )}
                            </div>

                            <div className="mt-4">
                                <button
                                    type="button"
                                    onClick={handleTestPrint}
                                    disabled={isTestingPrinter}
                                    className="px-4 py-2 bg-slate-700 hover:bg-slate-600 text-white text-sm font-medium rounded-lg transition-colors flex items-center gap-2"
                                >
                                    {isTestingPrinter ? <Loader2 className="w-4 h-4 animate-spin" /> : <Printer className="w-4 h-4" />}
                                    Test Connection
                                </button>
                            </div>
                        </div>

                        <div className="pt-4 flex justify-end gap-3 border-t border-slate-700">
                            <button
                                type="button"
                                onClick={onClose}
                                className="px-5 py-2.5 text-slate-300 hover:text-white font-medium transition-colors"
                            >
                                Cancel
                            </button>
                            <button
                                type="submit"
                                disabled={isSaving}
                                className="flex items-center gap-2 px-6 py-2.5 bg-indigo-500 hover:bg-indigo-600 text-white font-medium rounded-xl transition-all disabled:opacity-50"
                            >
                                {isSaving ? (
                                    <>
                                        <Loader2 className="animate-spin" size={18} />
                                        Saving...
