import React, { useState, useEffect } from 'react';
import type { POSTable, RunningBill } from '../types/pos.types';
import { POSTableService } from '../services/pos-table.service';
import { RunningBillService } from '../services/running-bill.service';
import { TableItem } from './TableItem';
import { RefreshCcw } from 'lucide-react';

interface TableFloorViewProps {
    businessUnitId: string;
    onSelectTable: (table: POSTable, bill: RunningBill | null) => void;
}

export const TableFloorView: React.FC<TableFloorViewProps> = ({ businessUnitId, onSelectTable }) => {
    const [tables, setTables] = useState<POSTable[]>([]);
    const [openBills, setOpenBills] = useState<RunningBill[]>([]);
    const [isLoading, setIsLoading] = useState(true);

    const loadData = async () => {
        setIsLoading(true);
        try {
            const [fetchedTables, fetchedBills] = await Promise.all([
                POSTableService.getTables(businessUnitId),
                RunningBillService.getOpenBills(businessUnitId)
            ]);
            setTables(fetchedTables);
            setOpenBills(fetchedBills);
        } catch (error) {
            console.error("Error loading table floor data:", error);
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        if (businessUnitId) {
            loadData();
        }
    }, [businessUnitId]);

    const handleSelectTable = (table: POSTable) => {
        const bill = openBills.find(b => b.tableId === table.id) || null;
        onSelectTable(table, bill);
    };

    const getBillAmount = (tableId: string): number | undefined => {
        const bill = openBills.find(b => b.tableId === tableId);
        return bill?.totalAmount;
    };

    if (isLoading) {
        return (
            <div className="flex-1 flex items-center justify-center bg-slate-900">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-600"></div>
            </div>
        );
    }

    return (
        <div className="flex-1 flex flex-col bg-slate-900 overflow-hidden relative">
            <div className="absolute top-4 right-4 z-10 flex items-center gap-3">
                <div className="flex gap-4 px-4 py-2 bg-slate-800 rounded-lg shadow-lg border border-slate-700">
                    <div className="flex items-center gap-2">
                        <div className="w-3 h-3 rounded-full bg-slate-600"></div>
                        <span className="text-xs text-slate-300">Available</span>
                    </div>
                    <div className="flex items-center gap-2">
                        <div className="w-3 h-3 rounded-full bg-amber-500"></div>
                        <span className="text-xs text-slate-300">Occupied</span>
                    </div>
                    <div className="flex items-center gap-2">
                        <div className="w-3 h-3 rounded-full bg-sky-500"></div>
                        <span className="text-xs text-slate-300">Reserved</span>
                    </div>
                </div>
                <button 
                    onClick={loadData}
                    className="p-2 bg-slate-800 hover:bg-slate-700 text-slate-300 rounded-lg border border-slate-700 transition-colors shadow-lg"
                    title="Refresh Status"
                >
                    <RefreshCcw className="w-5 h-5" />
                </button>
            </div>

            <div 
                className="flex-1 relative overflow-auto"
                style={{
                    backgroundImage: 'radial-gradient(#334155 1px, transparent 1px)',
                    backgroundSize: '20px 20px',
                    minWidth: '800px',
                    minHeight: '600px'
                }}
            >
                {tables.map(table => (
                    <TableItem
                        key={table.id}
                        table={table}
                        isSelected={false}
                        billAmount={getBillAmount(table.id)}
                        onSelect={() => handleSelectTable(table)}
                        onDragEnd={() => {}} // Disabled dragging in order view
                    />
                ))}

                {tables.length === 0 && (
                    <div className="absolute inset-0 flex items-center justify-center">
                        <div className="text-center text-slate-500">
                            <p className="text-xl mb-2">No Tables Setup</p>
                            <p className="text-sm">Go to POS Settings to configure tables for this branch.</p>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

import React from 'react';
import type { POSTable } from '../types/pos.types';
import { QRCodeSVG } from 'qrcode.react';
import { X, Trash2, QrCode } from 'lucide-react';

interface TableSettingsSidebarProps {
    table: POSTable | null;
    onClose: () => void;
    onUpdate: (updates: Partial<POSTable>) => void;
    onDelete: (tableId: string) => void;
}

export const TableSettingsSidebar: React.FC<TableSettingsSidebarProps> = ({ table, onClose, onUpdate, onDelete }) => {
    if (!table) return null;

    const handleSaveQr = () => {
        const svg = document.getElementById(`qr-${table.id}`);
        if (!svg) return;

        const svgData = new XMLSerializer().serializeToString(svg);
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        const img = new Image();

        img.onload = () => {
            canvas.width = img.width;
            canvas.height = img.height;
            ctx?.drawImage(img, 0, 0);
            const pngFile = canvas.toDataURL('image/png');

            const downloadLink = document.createElement('a');
            downloadLink.download = `Table-${table.name}-QR.png`;
            downloadLink.href = `${pngFile}`;
            downloadLink.click();
        };

        img.src = 'data:image/svg+xml;base64,' + btoa(unescape(encodeURIComponent(svgData)));
    };

    return (
        <div className="w-80 bg-slate-800 border-l border-slate-700 h-full flex flex-col shadow-2xl absolute right-0 top-0 z-20 transition-transform">
            <div className="flex items-center justify-between p-4 border-b border-slate-700 shrink-0">
                <h3 className="font-bold text-white text-lg">Table Settings</h3>
                <button onClick={onClose} className="p-2 text-slate-400 hover:text-white rounded-lg hover:bg-slate-700">
                    <X size={20} />
                </button>
            </div>

            <div className="p-6 flex-1 overflow-y-auto space-y-6">
                <div>
                    <label className="block text-sm font-medium text-slate-400 mb-1">Table Name</label>
                    <input
                        type="text"
                        value={table.name}
                        onChange={(e) => onUpdate({ name: e.target.value })}
                        className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-2.5 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500"
                        placeholder="e.g. Table 1"
                    />
                </div>

                <div>
                    <label className="block text-sm font-medium text-slate-400 mb-1">Seats</label>
                    <input
                        type="number"
                        min="1"
                        value={table.seats}
                        onChange={(e) => onUpdate({ seats: parseInt(e.target.value) || 1 })}
                        className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-2.5 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500"
                    />
                </div>

                <div>
                    <label className="block text-sm font-medium text-slate-400 mb-1">Shape</label>
                    <select
                        value={table.shape}
                        onChange={(e) => onUpdate({ shape: e.target.value as any })}
                        className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-2.5 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500"
                    >
                        <option value="rectangle">Rectangle</option>
                        <option value="circle">Circle</option>
                    </select>
                </div>

                <div className="pt-4 border-t border-slate-700">
                    <div className="flex items-center justify-between mb-4">
                        <label className="text-sm font-medium text-slate-300">Enable QR Ordering</label>
                        <button
                            onClick={() => onUpdate({ qrEnabled: !table.qrEnabled })}
                            className={`w-12 h-6 rounded-full transition-colors relative ${table.qrEnabled ? 'bg-emerald-500' : 'bg-slate-600'}`}
                        >
                            <span className={`absolute top-1 left-1 w-4 h-4 rounded-full bg-white transition-transform ${table.qrEnabled ? 'translate-x-6' : 'translate-x-0'}`} />
                        </button>
                    </div>

                    {table.qrEnabled && (
                        <div className="space-y-4">
                            <div>
                                <label className="block text-xs font-medium text-slate-400 mb-1">QR Destination URL</label>
                                <input
                                    type="text"
                                    value={table.qrUrl || `https://tng-systems.web.app/order?table=${table.id}`}
                                    onChange={(e) => onUpdate({ qrUrl: e.target.value })}
                                    className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-2 text-sm text-white focus:outline-none focus:ring-2 focus:ring-indigo-500"
                                />
                            </div>

                            <div className="bg-white p-4 rounded-2xl flex flex-col items-center justify-center">
                                <QRCodeSVG 
                                    id={`qr-${table.id}`}
                                    value={table.qrUrl || `https://tng-systems.web.app/order?table=${table.id}`} 
                                    size={150} 
                                    level="H"
                                    includeMargin={true}
                                />
                                <button
                                    onClick={handleSaveQr}
                                    className="mt-4 flex items-center gap-2 text-indigo-600 font-semibold hover:text-indigo-700"
                                >
                                    <QrCode size={18} />
                                    Download QR
                                </button>
                            </div>
                        </div>
                    )}
                </div>
            </div>

            <div className="p-4 border-t border-slate-700">
                <button
                    onClick={() => {
                        if (confirm('Are you sure you want to delete this table?')) {
                            onDelete(table.id);
                        }
                    }}
                    className="w-full flex items-center justify-center gap-2 py-3 bg-red-500/10 text-red-500 hover:bg-red-500/20 rounded-xl font-semibold transition-colors"
                >
                    <Trash2 size={18} />
                    Delete Table
                </button>
            </div>
        </div>
    );
};

