import { useState, useMemo, useCallback, useEffect } from 'react';
import type { MenuItem } from '../../menu/types/menu.types';
import type { POSOrderItem } from '../types/pos.types';
import { SettingsService, type POSSettings } from '../../../shared/services/settings.service';

export function useCart() {
    const [cartItems, setCartItems] = useState<POSOrderItem[]>([]);
    const [posSettings, setPosSettings] = useState<POSSettings>({ vatRate: 12, serviceChargeRate: 0 });
    const [globalDiscountRate, setGlobalDiscountRate] = useState<number>(0);

    useEffect(() => {
        SettingsService.getPOSSettings().then(settings => {
            setPosSettings(settings);
        });
    }, []);

    const addToCart = useCallback((menuItem: MenuItem, quantity: number = 1, notes: string = '') => {
        setCartItems(prev => {
            const existingItemIndex = prev.findIndex(item => item.menuItemId === menuItem.id && item.notes === notes);

            if (existingItemIndex >= 0) {
                // Update existing item
                const newItems = [...prev];
                const updatedQty = newItems[existingItemIndex].quantity + quantity;
                newItems[existingItemIndex] = {
                    ...newItems[existingItemIndex],
                    quantity: updatedQty,
                    subtotal: updatedQty * newItems[existingItemIndex].unitPrice
                };
                return newItems;
            }

            // Add new item
            const newItem: POSOrderItem = {
                menuItemId: menuItem.id,
                productName: menuItem.name,
                quantity: quantity,
                unitPrice: menuItem.sellingPrice,
                subtotal: quantity * menuItem.sellingPrice,
                category: menuItem.category,
                notes,
                isDiscounted: false,
                discountType: 'percentage',
                discountRate: 0,
                discountReason: '',
                vatAmount: 0,
                discountAmount: 0,
                vatExemptAmount: 0,
                menuItemData: menuItem
            };
            return [...prev, newItem];
        });
    }, []);

    const toggleDiscount = useCallback((index: number) => {
        setCartItems(prev => {
            const newItems = [...prev];
            newItems[index] = {
                ...newItems[index],
                isDiscounted: !newItems[index].isDiscounted
            };
            return newItems;
        });
    }, []);

    const setItemDiscountRate = useCallback((index: number, rate: number, reason?: string, type?: 'percentage' | 'amount') => {
        setCartItems(prev => {
            const newItems = [...prev];
            newItems[index] = {
                ...newItems[index],
                discountRate: rate,
                discountReason: reason !== undefined ? reason : newItems[index].discountReason,
                discountType: type !== undefined ? type : (newItems[index].discountType || 'percentage')
            };
            return newItems;
        });
    }, []);

    const updateQuantity = useCallback((index: number, quantity: number) => {
        setCartItems(prev => {
            const newItems = [...prev];
            if (quantity <= 0) {
                return newItems.filter((_, i) => i !== index);
            }
            newItems[index] = {
                ...newItems[index],
                quantity,
                subtotal: quantity * newItems[index].unitPrice
            };
            return newItems;
        });
    }, []);

    const removeFromCart = useCallback((index: number) => {
        setCartItems(prev => prev.filter((_, i) => i !== index));
    }, []);

    const clearCart = useCallback(() => {
        setCartItems([]);
        setGlobalDiscountRate(0);
    }, []);

    // Perform Calculations based on Philippine Law
    const calculations = useMemo(() => {
        const vatRate = (posSettings.vatRate || 12) / 100;
        const scRate = (posSettings.serviceChargeRate || 0) / 100;

        let grossSubtotal = 0;
        let totalVatAmount = 0;
        let totalDiscount = 0;
        let totalScPwdDiscount = 0;
        let totalManualDiscount = 0;
        let totalVatableSales = 0;
        let totalVatExemptSales = 0;
        let finalSubtotal = 0; // After discounts, before SC

        // We map and update the cartItems with calculated fields for display/saving
        const computedItems = cartItems.map(item => {
            const rawSubtotal = item.unitPrice * item.quantity;
            grossSubtotal += rawSubtotal;

            let itemVat = 0;
            let itemDiscount = 0;
            let itemVatExempt = 0;
            let itemFinalSubtotal = rawSubtotal;

            if (item.isDiscounted) {
                // Remove VAT for SC/PWD
                itemVatExempt = rawSubtotal / (1 + vatRate);
                itemDiscount = itemVatExempt * 0.20;
                itemFinalSubtotal = itemVatExempt - itemDiscount;
                totalVatExemptSales += itemFinalSubtotal;
                totalScPwdDiscount += itemDiscount;
            } else if ((item.discountRate || 0) > 0) {
                // Apply custom discount on the gross amount
                const isAmount = item.discountType === 'amount';
                itemDiscount = isAmount ? (item.discountRate || 0) : rawSubtotal * ((item.discountRate || 0) / 100);
                const discountedPrice = Math.max(0, rawSubtotal - itemDiscount);
                itemDiscount = rawSubtotal - discountedPrice; // ensure discount doesn't exceed price
                const vatableSales = discountedPrice / (1 + vatRate);
                itemVat = discountedPrice - vatableSales;
                itemFinalSubtotal = discountedPrice;
                totalVatableSales += vatableSales;
                totalManualDiscount += itemDiscount;
            } else {
                // Regular item: VAT is embedded in the price
                // e.g. 112 -> 12 is VAT
                const vatableSales = rawSubtotal / (1 + vatRate);
                itemVat = rawSubtotal - vatableSales;
                itemFinalSubtotal = rawSubtotal;
                totalVatableSales += vatableSales;
            }

            totalVatAmount += itemVat;
            totalDiscount += itemDiscount;
            finalSubtotal += itemFinalSubtotal;

            return {
                ...item,
                subtotal: itemFinalSubtotal,
                vatAmount: itemVat,
                discountAmount: itemDiscount,
                vatExemptAmount: itemVatExempt
            };
        });

        // Apply global custom discount if any
        let globalDiscountAmount = 0;
        if (globalDiscountRate > 0) {
            // Apply custom discount to the final subtotal (before SC)
            globalDiscountAmount = finalSubtotal * (globalDiscountRate / 100);
            finalSubtotal -= globalDiscountAmount;
            totalDiscount += globalDiscountAmount;
        }

        const serviceChargeAmount = finalSubtotal * scRate;
        const total = finalSubtotal + serviceChargeAmount;

        return {
            computedItems,
            grossSubtotal,
            totalDiscount,
            totalScPwdDiscount,
            totalManualDiscount,
            globalDiscountAmount,
            totalVatableSales,
            totalVatExemptSales,
            totalVatAmount,
            finalSubtotal,
            serviceChargeAmount,
            total
        };
    }, [cartItems, posSettings, globalDiscountRate]);

    return {
        cartItems: calculations.computedItems,
        addToCart,
        updateQuantity,
        removeFromCart,
        clearCart,
        toggleDiscount,
        setItemDiscountRate,
        globalDiscountRate,
        setGlobalDiscountRate,
        subtotal: calculations.finalSubtotal,
        grossSubtotal: calculations.grossSubtotal,
        vatableSales: calculations.totalVatableSales,
        vatExemptSales: calculations.totalVatExemptSales,
        taxAmount: calculations.totalVatAmount,
        serviceChargeAmount: calculations.serviceChargeAmount,
        discountAmount: calculations.totalDiscount,
        scPwdDiscountAmount: calculations.totalScPwdDiscount,
        manualItemDiscountAmount: calculations.totalManualDiscount,
        globalDiscountAmount: calculations.globalDiscountAmount,
        total: calculations.total,
        setCartItems
    };
}

export type PrinterConnectionType = 'bluetooth' | 'lan' | 'simulator';

export interface PrinterConfig {
    type: PrinterConnectionType;
    ipAddress?: string; // For LAN
}

export class POSPrinterService {
    private static bluetoothCharacteristic: BluetoothRemoteGATTCharacteristic | null = null;

    /**
     * Tries to connect to a Bluetooth printer using Web Bluetooth API.
     */
    static async connectBluetooth(): Promise<boolean> {
        try {
            if (!navigator.bluetooth) {
                throw new Error('Web Bluetooth is not supported in this browser.');
            }

            // Standard ESC/POS Bluetooth Service UUIDs (often generic serial port profile)
            // Some common printer UUIDs: 000018f0-0000-1000-8000-00805f9b34fb or 0000e781-0000-1000-8000-00805f9b34fb
            const device = await navigator.bluetooth.requestDevice({
                acceptAllDevices: true,
                optionalServices: ['000018f0-0000-1000-8000-00805f9b34fb', '0000e781-0000-1000-8000-00805f9b34fb']
            });

            const server = await device.gatt?.connect();
            if (!server) throw new Error('Could not connect to GATT server.');

            // We attempt to find the primary service for writing.
            // In a real production setup, we need the exact UUID of the printer's write characteristic.
            const services = await server.getPrimaryServices();
            if (services.length === 0) throw new Error('No services found on this device.');

            const service = services[0];
            const characteristics = await service.getCharacteristics();
            const writeCharacteristic = characteristics.find((c: any) => c.properties.write || c.properties.writeWithoutResponse);

            if (!writeCharacteristic) throw new Error('No writable characteristic found.');

            this.bluetoothCharacteristic = writeCharacteristic;

            return true;
        } catch (error) {
            console.error('Bluetooth connection failed:', error);
            throw error;
        }
    }

    /**
     * Send raw ESC/POS bytes to the configured printer.
     */
    static async print(config: PrinterConfig, data: Uint8Array): Promise<void> {
        if (config.type === 'simulator') {
            console.log('🖨️ [SIMULATOR PRINTER] Printing Receipt Data...');
            console.log(new TextDecoder().decode(data));
            return;
        }

        if (config.type === 'bluetooth') {
            if (!this.bluetoothCharacteristic) {
                // If not connected, attempt to reconnect or prompt
                throw new Error('Bluetooth printer not connected. Please connect first.');
            }
            try {
                // Web Bluetooth requires sending in small chunks (e.g., 512 bytes)
                const CHUNK_SIZE = 512;
                for (let i = 0; i < data.length; i += CHUNK_SIZE) {
                    const chunk = data.slice(i, i + CHUNK_SIZE);
                    await this.bluetoothCharacteristic.writeValue(chunk);
                }
            } catch (error) {
                console.error('Failed to print via Bluetooth:', error);
                throw new Error('Failed to print via Bluetooth.');
            }
            return;
        }

        if (config.type === 'lan') {
            if (!config.ipAddress) {
                throw new Error('LAN IP Address is required.');
            }
            // Real LAN printing requires a proxy (like QZ Tray) because browsers block raw TCP sockets.
            // For now, we simulate a fetch request to a generic local print spooler/proxy.
            try {
                console.log(`🖨️ [LAN PRINTER] Sending print job to proxy for IP: ${config.ipAddress}`);
                // const response = await fetch('http://localhost:8080/print', {
                //     method: 'POST',
                //     headers: { 'Content-Type': 'application/octet-stream' },
                //     body: data
                // });
                // if (!response.ok) throw new Error('Proxy print failed');
                console.warn('LAN Printing requires a local proxy (like QZ Tray) due to browser TCP restrictions. Simulated success.');
            } catch (error) {
                console.error('LAN print failed:', error);
                throw error;
            }
            return;
        }
    }

    /**
     * Generates a basic ESC/POS receipt payload.
     */
    static generateReceiptPayload(text: string): Uint8Array {
        const encoder = new TextEncoder();

        // Basic ESC/POS commands
        const ESC = 0x1B;
        const INIT = [ESC, 0x40]; // Initialize printer
        const ALIGN_CENTER = [ESC, 0x61, 0x01];
        const CUT_PAPER = [0x1D, 0x56, 0x41, 0x00]; // Cut paper command

        const data = [
            ...INIT,
            ...ALIGN_CENTER,
            ...Array.from(encoder.encode(text)),
            0x0A, 0x0A, 0x0A, // Feed 3 lines
            ...CUT_PAPER
        ];

        return new Uint8Array(data);
    }
}

import { collection, query, where, getDocs, Timestamp } from 'firebase/firestore';
import { db } from '../../../config/firebase';
import type { POSOrder } from '../types/pos.types';

export interface ShiftReport {
    businessUnitId: string;
    shiftStart: Date;
    shiftEnd: Date;

    totalTransactions: number;

    // Sales Totals
    grossSales: number; // Subtotal before any discounts/taxes
    netSales: number;   // Total collected after everything

    // Taxes & Exemptions
    vatableSales: number;
    vatAmount: number;
    vatExemptSales: number;
    zeroRatedSales: number; // Usually 0 for this type of business, but needed for BIR

    // Service Charge
    serviceChargeTotal: number;

    // Discounts
    scPwdDiscountTotal: number;
    manualDiscountTotal: number;
    totalDiscounts: number;

    // Tender Breakdown
    cashTotal: number;
    cardTotal: number;
    eWalletTotal: number;

    // Voids / Refunds (Placeholder for future)
    voidedTransactions: number;
    voidedAmount: number;
}

export class POSReportsService {
    /**
     * Generates a shift report (X-Reading or Z-Reading) based on a date range.
     * X-Reading is usually generated for the current day up to NOW.
     * Z-Reading is generated at end of day and usually triggers a shift reset in backend.
     */
    static async generateShiftReport(businessUnitId: string, startDate: Date, endDate: Date): Promise<ShiftReport> {
        const q = query(
            collection(db, 'pos_orders'),
            where('businessUnitId', '==', businessUnitId)
        );

        const snapshot = await getDocs(q);

        let grossSales = 0;
        let netSales = 0;
        let vatableSales = 0;
        let vatAmount = 0;
        let vatExemptSales = 0;
        let zeroRatedSales = 0;
        let serviceChargeTotal = 0;
        let scPwdDiscountTotal = 0;
        let manualDiscountTotal = 0;
        let totalDiscounts = 0;
        let cashTotal = 0;
        let cardTotal = 0;
        let eWalletTotal = 0;
        let totalTransactions = 0;

        snapshot.docs.forEach(doc => {
            const order = doc.data() as POSOrder;
            if (order.status !== 'COMPLETED') return;

            const orderDate = order.createdAt instanceof Timestamp ? order.createdAt.toDate() : new Date(order.createdAt);
            if (orderDate < startDate || orderDate > endDate) return;

            totalTransactions++;
            grossSales += order.subtotal || 0;
            netSales += order.totalAmount || 0;

            vatableSales += order.vatableSales || 0;
            vatAmount += order.taxAmount || 0;
            vatExemptSales += order.vatExemptSales || 0;

            serviceChargeTotal += order.serviceChargeAmount || 0;

            scPwdDiscountTotal += order.scPwdDiscountAmount || 0;
            manualDiscountTotal += order.manualItemDiscountAmount || 0;
            totalDiscounts += order.discountAmount || 0;

            if (order.paymentMethod === 'CASH') {
                cashTotal += order.totalAmount || 0;
            } else if (order.paymentMethod === 'CARD') {
                cardTotal += order.totalAmount || 0;
            } else if (order.paymentMethod === 'E_WALLET') {
                eWalletTotal += order.totalAmount || 0;
            }
        });

        return {
            businessUnitId,
            shiftStart: startDate,
            shiftEnd: endDate,
            totalTransactions,

            grossSales,
            netSales,

            vatableSales,
            vatAmount,
            vatExemptSales,
            zeroRatedSales,

            serviceChargeTotal,

            scPwdDiscountTotal,
            manualDiscountTotal,
            totalDiscounts,

            cashTotal,
            cardTotal,
            eWalletTotal,

            voidedTransactions: 0,
            voidedAmount: 0
        };
    }

    /**
     * Helper to get today's start and end dates
     */
    static getTodayRange(): { start: Date, end: Date } {
        const start = new Date();
        start.setHours(0, 0, 0, 0);

        const end = new Date();
        end.setHours(23, 59, 59, 999);

        return { start, end };
    }
}

import { collection, doc, getDocs, setDoc, updateDoc, deleteDoc, query, where, serverTimestamp } from 'firebase/firestore';
import { db } from '../../../config/firebase';
import type { POSTable } from '../types/pos.types';
import { v4 as uuidv4 } from 'uuid';

export class POSTableService {
    private static COLLECTION = 'pos_tables';

    static async getTables(businessUnitId: string): Promise<POSTable[]> {
        const q = query(
            collection(db, this.COLLECTION),
            where('businessUnitId', '==', businessUnitId)
        );

        const snapshot = await getDocs(q);
        return snapshot.docs.map(doc => ({
            id: doc.id,
            ...doc.data()
        })) as POSTable[];
    }

    static async addTable(businessUnitId: string, tableData: Partial<POSTable>): Promise<POSTable> {
        const tableId = uuidv4();
        const docRef = doc(db, this.COLLECTION, tableId);

        const newTable: POSTable = {
            id: tableId,
            businessUnitId,
            name: tableData.name || 'New Table',
            position: tableData.position || { x: 50, y: 50 },
            shape: tableData.shape || 'rectangle',
            seats: tableData.seats || 4,
            status: 'available',
            qrEnabled: tableData.qrEnabled || false,
            qrUrl: tableData.qrUrl || '',
            createdAt: serverTimestamp() as any,
            updatedAt: serverTimestamp() as any
        };

        await setDoc(docRef, newTable);
        return newTable;
    }

    static async updateTable(tableId: string, updates: Partial<POSTable>): Promise<void> {
        const docRef = doc(db, this.COLLECTION, tableId);
        await updateDoc(docRef, {
            ...updates,
            updatedAt: serverTimestamp()
        });
    }

    static async updateTableStatus(tableId: string, status: 'available' | 'occupied' | 'reserved'): Promise<void> {
        const docRef = doc(db, this.COLLECTION, tableId);
        await updateDoc(docRef, {
            status,
            updatedAt: serverTimestamp()
        });
    }

    static async deleteTable(tableId: string): Promise<void> {
        const docRef = doc(db, this.COLLECTION, tableId);
        await deleteDoc(docRef);
    }
}

