  /**
   * Add a history entry to a requisition
   */
  static async addHistoryEntry(
    requisitionId: string,
    actorId: string,
    actorName: string,
    action: string,
    stage: RequisitionStatus,
    comments?: string
  ): Promise<void> {
    const currentRequisition = await this.getRequisitionById(requisitionId);
    if (!currentRequisition) throw new Error('Requisition not found');

    const nowISO = new Date().toISOString();
    const newHistoryEntry: RequisitionHistory = {
      date: nowISO.split('T')[0], // Legacy: date only (YYYY-MM-DD)
      timestamp: nowISO, // New: Full ISO timestamp with time
      actorId,
      actorName,
      action,
      stage,
      ...(comments !== undefined && { comments }),
    };

    const updatedHistory = [newHistoryEntry, ...(currentRequisition.history || [])];

    return this.updateRequisition(requisitionId, { history: updatedHistory });
  }

  /**
   * Approve a requisition (Manager, CIC, etc.)
   * Updated for 7-stage PRF workflow with conditional 50k logic
   * FIX H2: Uses transaction to prevent race conditions when multiple approvers click simultaneously
   */
  static async approveRequisition(
    requisitionId: string,
    userId: string,
    userName: string,
    comments?: string,
    signatureUrl?: string
  ): Promise<void> {
    const docRef = doc(db, REQUISITIONS_COLLECTION, requisitionId);

    // Fetch approver assignments for currentApproverId routing
    const approverAssignments = await SettingsService.getApproverAssignments();

    // FIX H2: Use transaction for atomic read-modify-write (was separate read/write causing race conditions)
    const transactionResult = await runTransaction(db, async (transaction) => {
      const snap = await transaction.get(docRef);
      if (!snap.exists()) throw new Error('Requisition not found');

      const requisition = { id: snap.id, ...snap.data() } as Requisition;
      let nextStatus: RequisitionStatus | null = null;
      let currentApproverId: string | undefined = undefined;
      const approvalAction = 'Approved';

      // Determine next status based on current status
      switch (requisition.status) {
        // BURF Workflow (unchanged)
        case RequisitionStatus.BURF_PENDING_MANAGER:
          nextStatus = RequisitionStatus.BURF_PENDING_CIC;
          break;
        case RequisitionStatus.BURF_PENDING_CIC:
          nextStatus = RequisitionStatus.READY_FOR_PRF;
          break;

        // PRF 8-Stage Workflow - use helper function
        case RequisitionStatus.PRF_PENDING_MANAGER:
        case RequisitionStatus.PENDING_GM_PRF_APPROVAL:
        case RequisitionStatus.PENDING_FINANCE_HEAD_BR_APPROVAL:
        case RequisitionStatus.PENDING_GM_BR_APPROVAL:
        case RequisitionStatus.PENDING_BOD_APPROVAL:
        case RequisitionStatus.FOR_CHECK_PREPARATION:
        case RequisitionStatus.PENDING_CHECK_AUTH_BOD:
        case RequisitionStatus.FOR_FUND_RELEASE:
        case RequisitionStatus.PENDING_CFO_APPROVAL: // Legacy support
        case RequisitionStatus.APPROVED_FOR_PAYMENT: // Legacy support
          nextStatus = determineNextPrfStatus(requisition.status, requisition.totalAmount);
          break;

        default:
          throw new Error(`Cannot approve requisition in status: ${requisition.status}`);
      }

      if (nextStatus) {
        // Get the currentApproverId for the next status (for dashboard filtering)
        // Pass businessId for BU-specific Finance Head lookup
        currentApproverId = getApproverIdForStatus(nextStatus, approverAssignments, requisition.businessId);

        // Create history entry inline (can't call async methods in transaction)
        const approveNowISO = new Date().toISOString();
        const historyEntry: RequisitionHistory = {
          date: approveNowISO.split('T')[0], // Legacy: date only
          timestamp: approveNowISO, // Full ISO timestamp with time
          actorId: userId,
          actorName: userName,
          action: approvalAction,
          stage: nextStatus,
          ...(comments !== undefined && { comments }),
          ...(signatureUrl && { signatureUrl }),
        };

        const updatedHistory = [historyEntry, ...(requisition.history || [])];

        // Build update object
        const updateData: Record<string, unknown> = {
          status: nextStatus,
          history: updatedHistory,
          updatedAt: serverTimestamp(),
        };

        // Set currentApproverId if we have one (for dashboard filtering)
        if (currentApproverId) {
          updateData.currentApproverId = currentApproverId;
        } else {
          // Clear it for permission-based stages
          updateData.currentApproverId = null;
        }

        // Atomic update within transaction
        transaction.update(docRef, updateData);

        // Return data needed for notification and budget reservation (can't call async inside transaction)
        return {
          nextStatus,
          currentApproverId,
          requisitionId,
          description: requisition.description || requisition.projectName || 'Requisition',
          totalAmount: requisition.totalAmount,
          // Budget reservation data
          businessId: requisition.businessId,
          coaCode: requisition.coaCode, // PRF-level COA for budget
          items: requisition.items, // Items for budget reservation
          // For Filer Notification
          requesterId: requisition.requesterId,
          requesterName: requisition.requesterName,
          // For CC Notification
          fullRequisition: { ...requisition, status: nextStatus } as Requisition
        };
      }
      return null;
    });

    // Create notification AFTER transaction completes (for next approver)
    if (transactionResult) {
      const { nextStatus: newStatus, requisitionId: reqId, totalAmount: amount, currentApproverId: approverId } = transactionResult;

      // 1. BURF: Helper Variables
      // Check if newStatus is NOT null
      const isBurf = newStatus && (newStatus.startsWith('BURF_') || newStatus === 'READY_FOR_PRF');

      // 2. Main Approver Notification Logic
      if (approverId && newStatus) {
        const statusLabels: Record<RequisitionStatus, string> = {
          [RequisitionStatus.BURF_PENDING_CIC]: 'CIC Review',
          [RequisitionStatus.PENDING_GM_PRF_APPROVAL]: 'GM PRF Review (≥₱50k)',
          [RequisitionStatus.PENDING_FINANCE_HEAD_BR_APPROVAL]: 'Finance Head Budget Review',
          [RequisitionStatus.PENDING_GM_BR_APPROVAL]: 'GM Budget Approval',
          [RequisitionStatus.PENDING_CFO_APPROVAL]: 'CFO Approval',
          [RequisitionStatus.PENDING_BOD_APPROVAL]: 'BOD Approval',
          [RequisitionStatus.PENDING_CHECK_AUTH_BOD]: 'Check Authorization',
        } as Record<RequisitionStatus, string>;

        const label = statusLabels[newStatus] || newStatus.replace(/_/g, ' ');

        try {
          await NotificationsService.createNotification({
            type: isBurf ? 'BURF' : 'PRF',
            message: `${reqId} requires your ${label}. Amount: ₱${amount?.toLocaleString()}`,
            requisitionId: reqId,
            targetRoles: [approverId],
            actionUrl: isBurf
              ? `/?tab=${newStatus === 'BURF_PENDING_CIC' ? 'cic' : 'burf'}&id=${reqId}`
              : `/?tab=prf&id=${reqId}`
          });
        } catch (notificationError) {
          console.error('Failed to create approver notification:', notificationError);
        }
      }

      // 3. Special Role Notifications (No specific approver ID)

      // Notify Purchasing Officer when READY_FOR_PRF
      if (newStatus === RequisitionStatus.READY_FOR_PRF) {
        try {
          await NotificationsService.createNotification({
            type: 'BURF',
            message: `BURF Approved: ${reqId} is ready for PRF preparation.`,
            requisitionId: reqId,
            targetRoles: ['PURCHASING_OFFICER'],
            actionUrl: `/?action=prepare-prf&id=${reqId}`
          });
        } catch (e) { console.error('Failed to notify Purchasing Officer:', e); }
      }

      // Notify Finance when FOR_CHECK_PREPARATION
      if (newStatus === RequisitionStatus.FOR_CHECK_PREPARATION) {
        try {
          await NotificationsService.createNotification({
            type: 'PRF',
            message: `Approved: ${reqId} is ready for Check Preparation.`,
            requisitionId: reqId,
            targetRoles: ['FINANCE'],
            actionUrl: `/finance/check-preparation`
          });
        } catch (e) { console.error('Failed to notify Finance:', e); }
      }

      // 4. CC Notification: Notify Purchasing Officer (preparedBy) on ALL PRF status changes
      if (!isBurf && transactionResult.fullRequisition) {
        await NotificationsService.notifyPurchasingOfficer(
          transactionResult.fullRequisition,
          `PRF ${reqId} updated to ${newStatus}`
        );
      }
    }

    // BUDGET RESERVATION: When PRF reaches FOR_CHECK_PREPARATION, reserve the budget
    if (transactionResult && transactionResult.nextStatus === RequisitionStatus.FOR_CHECK_PREPARATION) {
      try {
        // Reserve budget if PRF has COA assigned or items with COAs
        const items = transactionResult.items || [];
        const prfCoaCode = transactionResult.coaCode;

        // Build items array for budget reservation
        // Use PRF-level COA if present, otherwise use item-level COAs
        const budgetItems = prfCoaCode
          ? [{ coaCode: prfCoaCode, amount: transactionResult.totalAmount }]
          : items.map(item => ({
            coaCode: item.coaCode,
            amount: (item.price || 0) * (item.quantity || 1)
          }));

        if (budgetItems.some(item => item.coaCode)) {
          const reservationId = await BudgetService.reserveBudget(
            transactionResult.requisitionId,
            transactionResult.businessId,
            budgetItems,
            userId
          );

          if (reservationId) {
            // Update PRF with budget reservation status
            await FirestoreService.updateDocument(REQUISITIONS_COLLECTION, transactionResult.requisitionId, {
              budgetStatus: 'RESERVED',
              reservedBudgetId: reservationId,
              reservedBudgetAmount: transactionResult.totalAmount,
            });
            console.log(`✅ Budget reserved for PRF ${transactionResult.requisitionId}: ${reservationId}`);
          }
        }
      } catch (budgetError) {
        console.error('⚠️ Budget reservation failed (PRF approval succeeded):', budgetError);
        // Don't throw - approval succeeded, budget reservation failed is non-critical
        // The budget will need to be manually adjusted if needed
      }
    }

    // BUDGET COMMIT: When PRF is FUNDS_RELEASED, commit the budget (move reserved → spent)
    if (transactionResult && transactionResult.nextStatus === RequisitionStatus.FUNDS_RELEASED) {
      try {
        await BudgetService.commitBudget(
          transactionResult.requisitionId,
          transactionResult.totalAmount // Actual amount (in case it differs from reserved)
        );

        // Update PRF budget status to COMMITTED
        await FirestoreService.updateDocument(REQUISITIONS_COLLECTION, transactionResult.requisitionId, {
          budgetStatus: 'COMMITTED',
        });
        console.log(`✅ Budget committed for PRF ${transactionResult.requisitionId}`);
      } catch (budgetError) {
        console.error('⚠️ Budget commit failed (Fund Release succeeded):', budgetError);
        // Don't throw - fund release succeeded, budget commit failed is non-critical
      }
    }

    // NOTIFICATION: Notify Filer on Status Change (Approval)
    if (transactionResult) {
      try {
        const partialReq = {
          id: transactionResult.requisitionId,
          requesterId: transactionResult.requesterId,
          requesterName: transactionResult.requesterName,
          totalAmount: transactionResult.totalAmount,
          status: transactionResult.nextStatus
        } as Requisition;

        await NotificationsService.notifyFilerOnStatusChange(
          partialReq,
          transactionResult.nextStatus,
          userName,
          true
        );
      } catch (error) {
        console.error('Failed to notify filer on status change:', error);
      }
    }
  }

  /**
   * Reject a requisition
   * FIX C5: Now uses transaction to prevent race conditions (matching approveRequisition pattern)
   * Previously used separate update + addHistoryEntry calls which could cause data inconsistency
   */
  static async rejectRequisition(
    requisitionId: string,
    userId: string,
    userName: string,
    comments: string
  ): Promise<void> {
    const docRef = doc(db, REQUISITIONS_COLLECTION, requisitionId);

    // FIX C5: Use transaction for atomic read-modify-write (was separate operations)
    await runTransaction(db, async (transaction) => {
      const snap = await transaction.get(docRef);
      if (!snap.exists()) throw new Error('Requisition not found');

      const requisition = { id: snap.id, ...snap.data() } as Requisition;

      // Create history entry inline (can't call async methods in transaction)
      const nowISO = new Date().toISOString();
      const historyEntry: RequisitionHistory = {
        date: nowISO.split('T')[0], // Legacy: date only
        timestamp: nowISO, // Full ISO timestamp with time
        actorId: userId,
        actorName: userName,
        action: 'Rejected',
        stage: RequisitionStatus.REJECTED,
        comments: comments,
      };

      const updatedHistory = [historyEntry, ...(requisition.history || [])];

      // Atomic update within transaction - status + history together
      const updateData: Record<string, unknown> = {
        status: RequisitionStatus.REJECTED,
        rejectedAtStage: requisition.status,
        history: updatedHistory,
        updatedAt: serverTimestamp(),
      };

      // Only update budgetStatus if it exists and was RESERVED
      if (requisition.budgetStatus === 'RESERVED') {
        updateData.budgetStatus = 'RELEASED';
      }

      transaction.update(docRef, updateData);

      // Return requisition ID for budget release
      return requisitionId;
    });

    // BUDGET RELEASE: When PRF is rejected, release any reserved budget
    try {
      await BudgetService.releaseBudget(requisitionId, `Rejected: ${comments}`);
      console.log(`✅ Budget released for rejected PRF ${requisitionId}`);
    } catch (budgetError) {
      console.error('⚠️ Budget release failed (rejection succeeded):', budgetError);
      // Don't throw - rejection succeeded, budget release failed is non-critical
    }

    // NOTIFICATION: Notify the filer that their request was rejected
    try {
      const requisition = await this.getRequisitionById(requisitionId);
      if (requisition) {
        await NotificationsService.notifyFilerOnStatusChange(
          requisition,
          RequisitionStatus.REJECTED,
          userName,
          false // isApproval = false for rejection
        );
      }
    } catch (notificationError) {
      console.error('Failed to create rejection notification:', notificationError);
      // Don't throw - rejection succeeded, notification failed is non-critical
    }

    // PCF LIQUIDATION INTEGRATION: If PRF is rejected, reject its associated PCF Liquidation
    try {
      const requisition = await this.getRequisitionById(requisitionId);
      if (requisition?.linkedPcfId) {
         // Dynamically import to avoid circular dependency
         const { PCFService } = await import('../../finance/services/pcf.service');
         await PCFService.rejectLiquidation(requisition.linkedPcfId, userId, userName, `Rejected in BR Flow: ${comments}`);
      }
    } catch (err) {
      console.error('⚠️ Failed to reject linked PCF Liquidation:', err);
    }
  }


  /**
   * Re-file a rejected requisition
   * FIX: Now uses transaction to prevent data inconsistency (matching approve/reject pattern)
   * Previously used separate update + addHistoryEntry calls
   */
  static async reFileRequisition(
    requisitionId: string,
    userId: string,
    userName: string,
    updates: Partial<Requisition>
  ): Promise<void> {
    const docRef = doc(db, REQUISITIONS_COLLECTION, requisitionId);

    await runTransaction(db, async (transaction) => {
      const snap = await transaction.get(docRef);
      if (!snap.exists()) throw new Error('Requisition not found');

      const requisition = { id: snap.id, ...snap.data() } as Requisition;

      // If it was rejected from a specific stage, return it directly to that stage
      // Otherwise, PRF returns to PRF_PENDING_MANAGER, BURF returns to BURF_PENDING_MANAGER
      const nextStatus = requisition.rejectedAtStage || (requisition.prfDetails || updates.prfDetails
        ? RequisitionStatus.PRF_PENDING_MANAGER
        : RequisitionStatus.BURF_PENDING_MANAGER);

      // Create history entry inline (can't call async methods in transaction)
      const refileNowISO = new Date().toISOString();
      const historyEntry: RequisitionHistory = {
        date: refileNowISO.split('T')[0], // Legacy: date only
        timestamp: refileNowISO, // Full ISO timestamp with time
        actorId: userId,
        actorName: userName,
        action: 'Re-filed',
        stage: nextStatus,
        comments: 'Requisition has been updated and re-filed for approval.',
      };

      const updatedHistory = [historyEntry, ...(requisition.history || [])];

      // Atomic update within transaction - status + history + updates together
      transaction.update(docRef, {
        ...removeUndefinedFields(updates),
        status: nextStatus,
        rejectedAtStage: null, // Clear this out since it's been refiled
        history: updatedHistory,
        updatedAt: serverTimestamp(),
      });
    });
  }

  /**
   * Submit liquidation for a requisition
   * @param requisitionId - The PRF ID
   * @param userId - Current user ID
   * @param userName - Current user name
   * @param payload - Liquidation data including item actuals and summary
   * 
   * NOTE: The items array accepts the new LiquidationItemRow format from LiquidationForm:
   * { id, date, vendorId, vendorName, tin, orNo, address, coa, description, vat, ewt, amount, buId, buName }
   * OR the legacy format:
   * { itemId, name, quantity, estimatedCost, actualCost, receiptRef }
   */
  static async submitLiquidation(
    requisitionId: string,
    userId: string,
    userName: string,
    payload: {
      items: any[]; // Accepts both LiquidationItemRow and legacy formats
      totalBudget: number;
      totalActual: number;
      variance: number; // positive = surplus (to return), negative = deficit (to reimburse)
      receiptsLink?: string;
      remarks?: string;
    }
  ): Promise<void> {
    const docRef = doc(db, REQUISITIONS_COLLECTION, requisitionId);

    // Helper function to deeply sanitize any value (removes undefined from objects and arrays)
    const deepSanitize = (value: any): any => {
      if (value === undefined) return null; // Convert undefined to null (Firestore-safe)
      if (value === null) return null;
      if (Array.isArray(value)) {
        return value.map(item => deepSanitize(item));
      }
      if (typeof value === 'object' && value !== null) {
        const cleaned: Record<string, any> = {};
        for (const [key, val] of Object.entries(value)) {
          if (val !== undefined) {
            cleaned[key] = deepSanitize(val);
          }
        }
        return cleaned;
      }
      return value;
    };

    await runTransaction(db, async (transaction) => {
      const snap = await transaction.get(docRef);
      if (!snap.exists()) throw new Error('Requisition not found');

      const requisition = { id: snap.id, ...snap.data() } as Requisition;

      // Verify status allows liquidation
      if (requisition.status !== RequisitionStatus.FUNDS_RELEASED) {
        throw new Error(`Cannot submit liquidation for requisition in status: ${requisition.status}. Expected FUNDS_RELEASED.`);
      }

      // Create history entry
      const liquidationNowISO = new Date().toISOString();
      const historyEntry: RequisitionHistory = {
        date: liquidationNowISO.split('T')[0], // Legacy: date only
        timestamp: liquidationNowISO, // Full ISO timestamp with time
        actorId: userId,
        actorName: userName,
        action: 'Liquidation Filed',
        stage: RequisitionStatus.LIQUIDATION_FILED,
        comments: payload.remarks || 'Liquidation documents submitted',
      };

      // Sanitize existing history entries (may have undefined comments from legacy data)
      const sanitizedHistory = deepSanitize([historyEntry, ...(requisition.history || [])]);

      // Sanitize items array
      const sanitizedItems = deepSanitize(payload.items);

      // Build the update object
      const updateData = {
        status: RequisitionStatus.LIQUIDATION_FILED,
        history: sanitizedHistory,
        liquidationDetails: {
          submittedBy: userId,
          submittedByName: userName,
          submittedAt: new Date().toISOString(),
          items: sanitizedItems,
          expenses: sanitizedItems, // Store as 'expenses' for the new format (LiquidationForm uses this key)
          totalBudget: payload.totalBudget ?? 0,
          totalActual: payload.totalActual ?? 0,
          variance: payload.variance ?? 0,
          receiptsLink: payload.receiptsLink ?? '',
          remarks: payload.remarks ?? '',
          status: 'PENDING' as const, // Pending audit
        },
        updatedAt: serverTimestamp(),
      };

      // Final sanitization of the entire update object
      const sanitizedUpdateData = deepSanitize(updateData);
      // Re-add serverTimestamp as it gets stripped by deepSanitize
      sanitizedUpdateData.updatedAt = serverTimestamp();

      transaction.update(docRef, sanitizedUpdateData);

      // Return data for notification
      return { requisitionId, totalActual: payload.totalActual };
    });

    // NOTIFICATION: Notify auditors that a new liquidation needs review
    try {
      await NotificationsService.notifyAuditorOnNewItem(
        'LIQUIDATION',
        requisitionId,
        userName,
        payload.totalActual
      );
    } catch (notificationError) {
      console.error('Failed to create auditor notification:', notificationError);
      // Don't throw - liquidation succeeded, notification failed is non-critical
    }
  }

  /**
   * Audit a liquidation (Approve or Reject)
   * Updates status and liquidationDetails, adds history entry, and notifies filer
   */
  static async auditLiquidation(
    requisitionId: string,
    userId: string,
    userName: string,
    status: RequisitionStatus.AUDITED_CLEARED | RequisitionStatus.LIQUIDATION_REJECTED,
    notes: string
  ): Promise<void> {
    const docRef = doc(db, REQUISITIONS_COLLECTION, requisitionId);

    // FIX L1: Use transaction for atomic read-modify-write
    // Previously used generic updateRequisition which had risk of race conditions
    await runTransaction(db, async (transaction) => {
      const snap = await transaction.get(docRef);
      if (!snap.exists()) throw new Error('Requisition not found');

      const requisition = { id: snap.id, ...snap.data() } as Requisition;

      // Verify status allows auditing
      if (requisition.status !== RequisitionStatus.LIQUIDATION_FILED) {
        throw new Error(`Cannot audit liquidation in status: ${requisition.status}. Expected LIQUIDATION_FILED.`);
      }

      const auditNowISO = new Date().toISOString();

      // Create history entry inline (can't call async methods in transaction)
      const historyEntry: RequisitionHistory = {
        date: auditNowISO.split('T')[0], // Legacy: date only
        timestamp: auditNowISO, // Full ISO timestamp
        actorId: userId,
        actorName: userName,
        action: status === RequisitionStatus.AUDITED_CLEARED ? 'Audited Cleared' : 'Liquidation Rejected',
        stage: status,
        comments: notes,
      };

      const updatedHistory = [historyEntry, ...(requisition.history || [])];

      // Update Liquidation Details
      const liquidationUpdate = {
        ...requisition.liquidationDetails,
        auditedBy: userId,
        auditDate: auditNowISO,
        auditNotes: notes,
        status: status === RequisitionStatus.AUDITED_CLEARED ? 'APPROVED' : 'REJECTED' as any,
        ...(status === RequisitionStatus.LIQUIDATION_REJECTED && { rejectionReason: notes })
      };

      // Atomic update
      transaction.update(docRef, {
        status: status,
        history: updatedHistory,
        liquidationDetails: liquidationUpdate,
        updatedAt: serverTimestamp(),
      });
    });

    // NOTIFICATION: Notify Filer on Status Change
    try {
      const updatedReq = await this.getRequisitionById(requisitionId);
      if (updatedReq) {
        // Use generic status change logic which handles REJECTED/CLEARED appropriately
        // Or create specific notifications if needed
        await NotificationsService.notifyFilerOnLiquidationResult(
          updatedReq,
          status === RequisitionStatus.AUDITED_CLEARED,
          userName,
          notes
        );
      }
    } catch (e) {
      console.error('Failed to notify filer on liquidation audit:', e);
    }
  }



  /**
   * Release funds for a requisition and automatically update linked PCF status
   * If the PRF has a linkedPcfId (PCF Replenishment), also update the PCF to REPLENISHED
   * 
   * PCF Replenishment Lifecycle:
   * - PCF Replenishments do NOT need liquidation (receipts already submitted)
   * - When funds are released, PCF Replenishments go directly to COMPLETED status
   */
  static async releaseFundsWithPcfUpdate(
    requisitionId: string,
    checkVoucherNumber: string,
    checkVoucherLink?: string,
    userId?: string,
    userName?: string,
    coaCode?: string
  ): Promise<void> {
    const docRef = doc(db, REQUISITIONS_COLLECTION, requisitionId);
    const pcfCollectionName = 'pcf_liquidations';

    await runTransaction(db, async (transaction) => {
      const snap = await transaction.get(docRef);
      if (!snap.exists()) {
        throw new Error('Requisition not found');
      }

      const requisition = { id: snap.id, ...snap.data() } as Requisition;

      // Verify status allows fund release (Check this BEFORE determining final status)
      if (requisition.status !== RequisitionStatus.FOR_FUND_RELEASE &&
        requisition.status !== RequisitionStatus.APPROVED_FOR_PAYMENT) {
        throw new Error(`Cannot release funds for requisition in status: ${requisition.status}. Expected FOR_FUND_RELEASE.`);
      }

      // Determine final status based on requisition type
      // PCF Replenishments (have linkedPcfId): AUDITED_CLEARED (no liquidation needed)
      // Standard PRFs: FUNDS_RELEASED (needs liquidation)
      const isPcfReplenishment = !!requisition.linkedPcfId;
      const finalStatus = isPcfReplenishment
        ? RequisitionStatus.AUDITED_CLEARED
        : RequisitionStatus.FUNDS_RELEASED;

      // Build history entry
      const fundReleaseNowISO = new Date().toISOString();
      let comments = isPcfReplenishment
        ? `Voucher #${checkVoucherNumber} released - PCF Replenishment complete (no liquidation required)`
        : `Voucher #${checkVoucherNumber} released`;
      if (coaCode) {
        comments += ` (COA: ${coaCode})`;
      }

      const historyEntry: RequisitionHistory = {
        date: fundReleaseNowISO.split('T')[0], // Legacy: date only
        timestamp: fundReleaseNowISO, // Full ISO timestamp with time
        actorId: userId || 'system',
        actorName: userName || 'Finance',
        action: isPcfReplenishment ? 'AUDITED_CLEARED' : 'FUNDS_RELEASED',
        stage: finalStatus,
        comments,
      };

      const updatedHistory = [historyEntry, ...(requisition.history || [])];

      // Step 1: Update the PRF status
      // Save to new fields (checkVoucherNumber/checkVoucherLink) and legacy fields for compatibility
      const updateData: Record<string, any> = {
        status: finalStatus,
        // New fields
        checkVoucherNumber: checkVoucherNumber,
        checkVoucherLink: checkVoucherLink || '',
        // Legacy fields (for backward compatibility with existing views)
        chequeNumber: checkVoucherNumber,
        chequeImageUrl: checkVoucherLink || '',
        fundReleaseDate: new Date().toISOString(),
        history: updatedHistory,
        updatedAt: serverTimestamp(),
      };

      if (coaCode) {
        updateData.coaCode = coaCode;
      }

      transaction.update(docRef, updateData);

      // Step 2: If this is a PCF Replenishment PRF, update the linked PCF to REPLENISHED
      if (requisition.linkedPcfId) {
        const pcfRef = doc(db, pcfCollectionName, requisition.linkedPcfId);
        transaction.update(pcfRef, {
          status: 'REPLENISHED',
          dateReplenished: new Date().toISOString(),
        });
      }

      // Return requisition for notification
      return requisition;
    });

    // NOTIFICATION: Notify the filer that funds have been released
    try {
      const updatedReq = await this.getRequisitionById(requisitionId);
      if (updatedReq) {
        await NotificationsService.notifyFilerOnFundRelease(
          updatedReq,
          userName || 'Finance'
        );
      }
    } catch (notificationError) {
      console.error('Failed to create fund release notification:', notificationError);
      // Don't throw - fund release succeeded, notification failed is non-critical
    }

    // CC NOTIFICATION: Notify Purchasing Officer
    try {
      const fullReq = await this.getRequisitionById(requisitionId);
      if (fullReq) {
        await NotificationsService.notifyPurchasingOfficer(
          fullReq,
          `Funds Released: Check/Voucher #${checkVoucherNumber} for ${requisitionId}`
        );
      }
    } catch (e) { console.error('Failed to notify Purchasing Officer on fund release:', e); }
  }

  /**
   * Upload check details for Check Preparation step (Step 6)
   * Finance uploads check number and Google Drive link
   * Advances workflow to PENDING_CHECK_AUTH_BOD
   */
  static async uploadCheckForPreparation(
    requisitionId: string,
    chequeNumber: string,
    chequeImageUrl: string,
    userId: string,
    userName: string
  ): Promise<void> {
    const docRef = doc(db, REQUISITIONS_COLLECTION, requisitionId);

    // Fetch approver assignments for routing to BOD
    const approverAssignments = await SettingsService.getApproverAssignments();

    await runTransaction(db, async (transaction) => {
      const snap = await transaction.get(docRef);
      if (!snap.exists()) throw new Error('Requisition not found');

      const requisition = { id: snap.id, ...snap.data() } as Requisition;

      // Verify status is FOR_CHECK_PREPARATION
      if (requisition.status !== RequisitionStatus.FOR_CHECK_PREPARATION) {
        throw new Error(`Cannot upload check for requisition in status: ${requisition.status}. Expected FOR_CHECK_PREPARATION.`);
      }

      const nextStatus = RequisitionStatus.PENDING_CHECK_AUTH_BOD;

      // Get BOD approver for routing
      const currentApproverId = getApproverIdForStatus(nextStatus, approverAssignments, requisition.businessId);

      // Create history entry
      const checkUploadNowISO = new Date().toISOString();
      const historyEntry: RequisitionHistory = {
        date: checkUploadNowISO.split('T')[0], // Legacy: date only
        timestamp: checkUploadNowISO, // Full ISO timestamp with time
        actorId: userId,
        actorName: userName,
        action: 'Bank Reference Added',
        stage: nextStatus,
        comments: `Bank Ref #${chequeNumber} added for authorization`,
      };

      const updatedHistory = [historyEntry, ...(requisition.history || [])];

      // Update requisition with bank ref details and advance status
      // Save to both new fields (bankRefNumber/bankRefLink) and legacy fields (chequeNumber/chequeImageUrl) for compatibility
      const updateData: Record<string, unknown> = {
        status: nextStatus,
        // New fields
        bankRefNumber: chequeNumber,
        bankRefLink: chequeImageUrl,
        // Legacy fields (for backward compatibility with existing views)
        chequeNumber: chequeNumber,
        chequeImageUrl: chequeImageUrl,
        history: updatedHistory,
        updatedAt: serverTimestamp(),
      };

      if (currentApproverId) {
        updateData.currentApproverId = currentApproverId;
      }

      transaction.update(docRef, updateData);
    });

    // CC NOTIFICATION: Notify Purchasing Officer
    try {
      const fullReq = await this.getRequisitionById(requisitionId);
      if (fullReq) {
        await NotificationsService.notifyPurchasingOfficer(
          fullReq,
          `Check Prepared: Bank Ref #${chequeNumber} uploaded for ${requisitionId}`
        );
      }
    } catch (e) { console.error('Failed to notify Purchasing Officer on check upload:', e); }
  }
}

