import { db } from '../../../config/firebase';
import { doc, runTransaction, serverTimestamp, arrayUnion } from 'firebase/firestore';
import { RequisitionStatus } from '../../procurement/types';
import type { RequisitionHistory, Requisition } from '../../procurement/types';
import { COLLECTIONS } from '../../../shared/types/firebase.types';
import { NotificationsService } from '../../../shared/services/notifications.service';

export type WorkflowAction = 'APPROVE' | 'REJECT' | 'CANCEL' | 'REFILE';

interface ActionParams {
  requisitionId: string;
  action: WorkflowAction;
  user: { uid: string; displayName: string; email: string };
  reason?: string; // Required for Reject
}

/**
 * Executes workflow actions using Firestore transactions.
 * Issue #7 Fix: Uses serverTimestamp() for audit trail integrity
 * Issue #8 Fix: Uses runTransaction() to prevent race conditions
 */
export const executeWorkflowAction = async ({
  requisitionId,
  action,
  user,
  reason = ''
}: ActionParams): Promise<void> => {
  const ref = doc(db, COLLECTIONS.REQUISITIONS, requisitionId);

  // Use transaction to prevent race conditions (Issue #8)
  const transactionResult = await runTransaction(db, async (transaction) => {
    // Fetch current doc within transaction
    const snap = await transaction.get(ref);
    if (!snap.exists()) throw new Error("Requisition not found");

    const data = snap.data();
    const currentStatus = data.status as RequisitionStatus;

    // =====================================================
    // FIX BUG 6: Audit History Timestamp Strategy
    // =====================================================
    // PROBLEM: Firestore's arrayUnion() doesn't support serverTimestamp() inside arrays.
    // SOLUTION: We use a hybrid approach:
    //   1. Client ISO timestamp in array for immediate display (date field)
    //   2. Server timestamp on main document (lastModified) for authoritative audit
    //   3. A sequential actionIndex to correlate history entries with server timestamps
    // 
    // For forensic auditing, cross-reference:
    //   history[n].actionIndex === n means history[n] was created when lastModified was set
    // =====================================================

    const currentHistoryLength = Array.isArray(data.history) ? data.history.length : 0;

    const nowISO = new Date().toISOString();

    const auditEntry: RequisitionHistory = {
      action,
      actorId: user.uid,
      actorName: user.displayName,
      date: nowISO.split('T')[0], // Legacy: date only (YYYY-MM-DD)
      timestamp: nowISO, // New: Full ISO timestamp with time
      stage: currentStatus,
      comments: reason || undefined,
      actionIndex: currentHistoryLength // FIX BUG 6: Sequential index for server timestamp correlation
    };

    // FIX: Use const instead of let (prefer-const)
    const updates: Record<string, unknown> = {
      history: arrayUnion(auditEntry),
      lastModified: serverTimestamp(), // Server timestamp - authoritative audit trail
      lastModifiedBy: user.uid,
      lastActionIndex: currentHistoryLength // FIX BUG 6: Track which history entry triggered this update
    };

    switch (action) {
      case 'APPROVE': {
        let nextStatus: RequisitionStatus | null = null;
        const totalAmount = (data.totalAmount as number) || 0;
        const GM_PRF_THRESHOLD = 50000;

        // =====================================================
        // FIX: Full 8-Stage PRF Workflow (synced with requisitions.service.ts)
        // =====================================================
        // BURF Workflow:
        //   BURF_PENDING_MANAGER → BURF_PENDING_CIC → READY_FOR_PRF
        //
        // PRF 8-Stage Workflow:
        //   Step 1: PRF_PENDING_MANAGER → Step 2 (if >=50k) or Step 3 (if <50k)
        //   Step 2: PENDING_GM_PRF_APPROVAL → Step 3
        //   Step 3: PENDING_FINANCE_HEAD_BR_APPROVAL → Step 4
        //   Step 4: PENDING_GM_BR_APPROVAL → Step 5
        //   Step 5: PENDING_BOD_APPROVAL → Step 6
        //   Step 6: FOR_CHECK_PREPARATION → Step 7
        //   Step 7: PENDING_CHECK_AUTH_BOD → Step 8
        //   Step 8: FOR_FUND_RELEASE → FUNDS_RELEASED
        // =====================================================

        // BURF Workflow (unchanged)
        if (currentStatus === RequisitionStatus.BURF_PENDING_MANAGER) {
          nextStatus = RequisitionStatus.BURF_PENDING_CIC;
        } else if (currentStatus === RequisitionStatus.BURF_PENDING_CIC) {
          nextStatus = RequisitionStatus.READY_FOR_PRF;
        }
        // PRF Step 1: BUM Approval → Step 2 (if >=50k) or Step 3 (if <50k)
        else if (currentStatus === RequisitionStatus.PRF_PENDING_MANAGER) {
          nextStatus = totalAmount >= GM_PRF_THRESHOLD
            ? RequisitionStatus.PENDING_GM_PRF_APPROVAL
            : RequisitionStatus.PENDING_FINANCE_HEAD_BR_APPROVAL;
        }
        // PRF Step 2: GM PRF Review → Step 3
        else if (currentStatus === RequisitionStatus.PENDING_GM_PRF_APPROVAL) {
          nextStatus = RequisitionStatus.PENDING_FINANCE_HEAD_BR_APPROVAL;
        }
        // PRF Step 3: Finance Head Budget Review → Step 4
        else if (currentStatus === RequisitionStatus.PENDING_FINANCE_HEAD_BR_APPROVAL) {
          nextStatus = RequisitionStatus.PENDING_GM_BR_APPROVAL;
        }
        // PRF Step 4: GM Budget Approval → Step 5
        else if (currentStatus === RequisitionStatus.PENDING_GM_BR_APPROVAL) {
          nextStatus = RequisitionStatus.PENDING_BOD_APPROVAL;
        }
        // PRF Step 5: BOD Approval → Step 6 (Check Prep)
        else if (currentStatus === RequisitionStatus.PENDING_BOD_APPROVAL) {
          nextStatus = RequisitionStatus.FOR_CHECK_PREPARATION;
        }
        // PRF Step 6: Check Preparation → Step 7 (BOD Check Auth)
        else if (currentStatus === RequisitionStatus.FOR_CHECK_PREPARATION) {
          nextStatus = RequisitionStatus.PENDING_CHECK_AUTH_BOD;
        }
        // PRF Step 7: BOD Check Authorization → Step 8 (Fund Release)
        else if (currentStatus === RequisitionStatus.PENDING_CHECK_AUTH_BOD) {
          nextStatus = RequisitionStatus.FOR_FUND_RELEASE;
        }
        // PRF Step 8: Fund Release → Complete
        else if (currentStatus === RequisitionStatus.FOR_FUND_RELEASE) {
          nextStatus = RequisitionStatus.FUNDS_RELEASED;
        }
        // Legacy status support
        else if (currentStatus === RequisitionStatus.APPROVED_FOR_PAYMENT) {
          nextStatus = RequisitionStatus.FUNDS_RELEASED;
        }
        else if (currentStatus === RequisitionStatus.PENDING_CFO_APPROVAL) {
          nextStatus = RequisitionStatus.PENDING_BOD_APPROVAL; // Legacy: skip to BOD
        }
        else {
          throw new Error(`Cannot approve from status: ${currentStatus}. Status may have changed.`);
        }

        updates.status = nextStatus;

        // Record specific approval timestamps with server time
        if (currentStatus === RequisitionStatus.BURF_PENDING_MANAGER) {
          updates['approvals.manager'] = {
            approved: true,
            approverId: user.uid,
            date: serverTimestamp()
          };
        } else if (currentStatus === RequisitionStatus.BURF_PENDING_CIC) {
          updates['approvals.cic'] = {
            approved: true,
            approverId: user.uid,
            date: serverTimestamp()
          };
        } else if (currentStatus === RequisitionStatus.PRF_PENDING_MANAGER) {
          updates['approvals.prfManager'] = {
            approved: true,
            approverId: user.uid,
            date: serverTimestamp()
          };
        } else if (currentStatus === RequisitionStatus.PENDING_GM_PRF_APPROVAL) {
          updates['approvals.gmPrf'] = {
            approved: true,
            approverId: user.uid,
            date: serverTimestamp()
          };
        } else if (currentStatus === RequisitionStatus.PENDING_FINANCE_HEAD_BR_APPROVAL) {
          updates['approvals.financeHeadBr'] = {
            approved: true,
            approverId: user.uid,
            date: serverTimestamp()
          };
        } else if (currentStatus === RequisitionStatus.PENDING_GM_BR_APPROVAL) {
          updates['approvals.gmBr'] = {
            approved: true,
            approverId: user.uid,
            date: serverTimestamp()
          };
        } else if (currentStatus === RequisitionStatus.PENDING_BOD_APPROVAL) {
          updates['approvals.bod'] = {
            approved: true,
            approverId: user.uid,
            date: serverTimestamp()
          };
        } else if (currentStatus === RequisitionStatus.PENDING_CHECK_AUTH_BOD) {
          updates['approvals.checkAuthBod'] = {
            approved: true,
            approverId: user.uid,
            date: serverTimestamp()
          };
        }
        break;
      }

      case 'REJECT':
        if (!reason) throw new Error("Rejection reason is required.");
        updates.status = RequisitionStatus.REJECTED;
        updates.rejectionReason = reason;
        updates.rejectedAt = serverTimestamp();
        updates.rejectedBy = user.uid;
        break;

      case 'CANCEL': {
        // Validate cancellation is allowed from current status
        const nonCancellableStatuses = [
          RequisitionStatus.FUNDS_RELEASED,
          RequisitionStatus.LIQUIDATION_FILED,
          RequisitionStatus.AUDITED_CLEARED
        ];
        if (nonCancellableStatuses.includes(currentStatus)) {
          throw new Error("Cannot cancel a requisition that has already processed funds.");
        }
        updates.status = RequisitionStatus.CANCELLED;
        updates.cancelledAt = serverTimestamp();
        updates.cancelledBy = user.uid;
        break;
      }

      case 'REFILE':
        if (currentStatus !== RequisitionStatus.REJECTED) {
          throw new Error("Can only refile rejected requisitions.");
        }
        // Reset to initial pending state based on type (BURF vs PRF)
        // FIX #5: Changed from data.prfIdentifier (doesn't exist) to data.prfDetails (actual schema field)
        const isPrf = !!data.prfDetails;
        updates.status = isPrf ? RequisitionStatus.PRF_PENDING_MANAGER : RequisitionStatus.BURF_PENDING_MANAGER;
        updates.rejectionReason = null;
        updates.refiledAt = serverTimestamp();
        updates.refiledBy = user.uid;
        break;

      default:
        throw new Error("Invalid Action");
    }

    // Atomic update within transaction
    transaction.update(ref, updates);

    // Return data needed for notifications (can't call async inside transaction)
    return {
      action,
      nextStatus: updates.status as RequisitionStatus | undefined,
      requesterId: data.requesterId as string,
      requesterName: data.requesterName as string,
      requisitionId,
      totalAmount: data.totalAmount as number,
    };
  });

  // NOTIFICATIONS: After transaction completes, notify the requester
  // This is done outside the transaction because Firestore transactions can't call external services
  if (transactionResult) {
    try {
      if (action === 'APPROVE' && transactionResult.nextStatus) {
        // Notify the filer that their request was approved and moved forward
        await NotificationsService.notifyFilerOnStatusChange(
          {
            id: requisitionId,
            requesterId: transactionResult.requesterId,
            requesterName: transactionResult.requesterName,
            totalAmount: transactionResult.totalAmount,
          } as Requisition,
          transactionResult.nextStatus,
          user.displayName,
          true // isApproval = true
        );
      } else if (action === 'REJECT') {
        // Notify the filer that their request was rejected
        await NotificationsService.notifyFilerOnStatusChange(
          {
            id: requisitionId,
            requesterId: transactionResult.requesterId,
            requesterName: transactionResult.requesterName,
            totalAmount: transactionResult.totalAmount,
          } as Requisition,
          RequisitionStatus.REJECTED,
          user.displayName,
          false // isApproval = false for rejection
        );
      }
    } catch (notificationError) {
      console.error('[workflowService] Failed to create notification:', notificationError);
      // Don't throw - the workflow action succeeded, notification is non-critical
    }
  }
};

import React, { useState, useMemo } from 'react';
import { Search, Filter } from 'lucide-react';
import type { Requisition, Business, User } from '../../../shared/types';
import { RequisitionStatus } from '../types';
import { usePermissions } from '../../../hooks/usePermissions';
import Card from '../../../shared/components/Card';
import { useBusinessUnit } from '../../../contexts/BusinessUnitContext';

interface ApprovedViewProps {
    currentUser: User;
    requisitions: Requisition[];
    allUsers: User[];
    businesses: Business[];
    getStatusBadge: (status: RequisitionStatus) => React.ReactNode;
}

export const ApprovedView: React.FC<ApprovedViewProps> = ({
    currentUser,
    requisitions,
    allUsers,
    businesses,
    getStatusBadge
}) => {
    const { hasPermission } = usePermissions();
    const [searchTerm, setSearchTerm] = useState('');
    const { selectedBusinessUnit } = useBusinessUnit();
    const [typeFilter, setTypeFilter] = useState<string>('all'); // all, burf, prf

    // Approved statuses to show
    const approvedStatuses = [
        RequisitionStatus.READY_FOR_PRF,
        RequisitionStatus.APPROVED_FOR_PAYMENT,
        RequisitionStatus.FUNDS_RELEASED,
        RequisitionStatus.LIQUIDATION_FILED,
        RequisitionStatus.AUDITED_CLEARED
    ];

    // Use permission instead of role-based check
    const hasGlobalAccess = hasPermission('procurement:burf:view:all');

    const filteredRequisitions = useMemo(() => {
        return requisitions.filter(req => {
            // 1. Filter by Approved Statuses
            if (!approvedStatuses.includes(req.status)) return false;

            // 2. Filter by Type (BURF or PRF)
            if (typeFilter === 'burf' && (req.id.startsWith('PRF') || req.status === RequisitionStatus.PRF_PENDING_MANAGER)) return false;
            if (typeFilter === 'prf' && !req.id.startsWith('PRF') && req.status !== RequisitionStatus.PRF_PENDING_MANAGER) return false;

            // 3. Filter by Business Unit
            if (hasGlobalAccess) {
                if (selectedBusinessUnit !== 'all' && req.businessId !== selectedBusinessUnit) return false;
            } else {
                if (req.businessId !== currentUser.businessId) return false;
            }

            // 4. Search Filter
            if (searchTerm) {
                const term = searchTerm.toLowerCase();
                const requester = allUsers.find(u => u.id === req.requesterId)?.name.toLowerCase() || '';
                const business = businesses.find(b => b.id === req.businessId)?.name.toLowerCase() || '';

                return (
                    req.id.toLowerCase().includes(term) ||
                    req.description.toLowerCase().includes(term) ||
                    requester.includes(term) ||
                    business.includes(term)
                );
            }

            return true;
        }).sort((a, b) => new Date(b.dateCreated).getTime() - new Date(a.dateCreated).getTime());
    }, [requisitions, approvedStatuses, typeFilter, selectedBusinessUnit, searchTerm, currentUser, allUsers, businesses, hasGlobalAccess]);

    return (
        <div className="space-y-6 text-white animate-in fade-in slide-in-from-bottom-4">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                    <h1 className="text-2xl font-bold">Approved Requisitions</h1>
                    <p className="text-slate-400 text-sm">View all approved PRF and BURF requisitions.</p>
                </div>

                <div className="flex flex-wrap gap-3 items-center">
                    {/* Type Filter */}
                    <div className="relative">
                        <select
                            value={typeFilter}
                            onChange={(e) => setTypeFilter(e.target.value)}
                            className="appearance-none pl-4 pr-10 py-2 bg-slate-800 border border-slate-700 rounded-lg text-sm focus:ring-2 focus:ring-purple-500 focus:outline-none"
                        >
                            <option value="all">All Types</option>
                            <option value="burf">BURF Only</option>
                            <option value="prf">PRF Only</option>
                        </select>
                        <Filter className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={16} />
                    </div>

                    {/* Search */}
                    <div className="relative">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                        <input
                            type="text"
                            placeholder="Search ID, Desc, User..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="pl-10 pr-4 py-2 bg-slate-800 border border-slate-700 rounded-lg text-sm w-64 focus:ring-2 focus:ring-purple-500 focus:outline-none placeholder-slate-500"
                        />
                    </div>
                </div>
            </div>

            <Card className="overflow-hidden !p-0">
                <div className="max-h-[600px] overflow-y-auto">
                    <table className="w-full text-left text-sm">
                        <thead className="bg-slate-900/80 text-xs uppercase font-semibold text-slate-400 border-b border-slate-700 sticky top-0 z-20 backdrop-blur-sm">
                            <tr>
                                <th className="px-6 py-4">ID</th>
                                <th className="px-6 py-4">Type</th>
                                <th className="px-6 py-4">Description</th>
                                <th className="px-6 py-4">Business Unit</th>
                                <th className="px-6 py-4">Requester</th>
                                <th className="px-6 py-4">Amount</th>
                                <th className="px-6 py-4">Date</th>
                                <th className="px-6 py-4">Status</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-700">
                            {filteredRequisitions.map(req => {
                                const requester = allUsers.find(u => u.id === req.requesterId);
                                const business = businesses.find(b => b.id === req.businessId);
                                const isPrf = req.id.startsWith('PRF') || req.status === RequisitionStatus.PRF_PENDING_MANAGER;

                                return (
                                    <tr key={req.id} className="hover:bg-slate-800/60 transition-colors">
                                        <td className="px-6 py-4 font-medium text-white">{req.id}</td>
                                        <td className="px-6 py-4">
                                            <span className={`px-2 py-1 rounded text-[10px] font-bold ${isPrf ? 'bg-purple-500/20 text-purple-300' : 'bg-orange-500/20 text-orange-300'}`}>
                                                {isPrf ? 'PRF' : 'BURF'}
                                            </span>
                                        </td>
                                        <td className="px-6 py-4 text-slate-300">
                                            <div className="truncate max-w-[200px]" title={req.description}>{req.description}</div>
                                        </td>
                                        <td className="px-6 py-4 text-slate-400 text-xs">{business?.name || 'N/A'}</td>
                                        <td className="px-6 py-4">
                                            <div className="flex items-center gap-2">
                                                <div className="w-6 h-6 rounded-full bg-slate-700 flex items-center justify-center text-xs font-bold text-slate-300">
                                                    {(requester?.name || '?').charAt(0)}
                                                </div>
                                                <span className="text-slate-300">{requester?.name || 'Unknown'}</span>
                                            </div>
                                        </td>
                                        <td className="px-6 py-4 text-emerald-400 font-semibold">
                                            ₱{req.totalAmount?.toLocaleString()}
                                        </td>
                                        <td className="px-6 py-4 text-slate-400 text-xs">
                                            {new Date(req.dateCreated).toLocaleDateString()}
                                        </td>
                                        <td className="px-6 py-4">
                                            {getStatusBadge(req.status)}
                                        </td>
                                    </tr>
                                );
                            })}
                            {filteredRequisitions.length === 0 && (
                                <tr>
                                    <td colSpan={8} className="px-6 py-12 text-center text-slate-500 italic">
                                        No approved requisitions found matching your filters.
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </Card>
        </div>
    );
};

export default ApprovedView;

import React, { useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { Plus, Trash2, Check, Save, Link as LinkIcon, Search, AlertTriangle, Printer, Edit, RefreshCw, ArrowUpDown, ArrowUp, ArrowDown, Paperclip, Loader2, ArrowRightCircle } from 'lucide-react';
import type { Requisition, RequisitionItem } from '../types';
import { RequisitionStatus, isSuperAdmin } from '../types';
import type { User, Business } from '../../../shared/types';
import { usePermissions } from '../../../hooks/usePermissions';
import Card from '../../../shared/components/Card';
import BURFPrintModal from '../components/BURFPrintModal';
import RequisitionDrawer from '../../../shared/components/RequisitionDrawer';
import { DateRangeFilter } from '../../../shared/components/DateRangeFilter';
import { CounterService } from '../../../shared/services/counter.service';
import { executeWorkflowAction } from '../services/workflowService';
// FIX C6: Import sanitization utility to prevent XSS/injection
import { sanitizeText, sanitizeItems } from '../../../shared/utils/sanitize';
// FIX: Import URL validation utility
import { isValidUrl } from '../../../shared/utils/validation';
import { UI_CONSTANTS } from '../../../config/constants';
import { useBusinessUnit } from '../../../contexts/BusinessUnitContext';

interface BurfViewProps {
    currentUser: User;
    visibleRequisitions: Requisition[];
    allUsers: User[];
    getStatusBadge: (status: RequisitionStatus) => React.ReactNode;
    onCreateRequisition: (req: Omit<Requisition, 'id'>) => void;
    onUpdateRequisition: (req: Requisition) => void;
    businesses: Business[];
    uomOptions: string[];
}

type SortField = 'id' | 'description' | 'businessId' | 'requesterId' | 'dateNeeded' | 'status';
type SortDirection = 'asc' | 'desc';

export const BurfView: React.FC<BurfViewProps> = ({
    currentUser,
    visibleRequisitions,
    allUsers,
    getStatusBadge,
    onCreateRequisition,
    onUpdateRequisition,
    businesses,
    uomOptions
}) => {
    const navigate = useNavigate();
    const [isCreating, setIsCreating] = useState(false);
    const [editingId, setEditingId] = useState<string | null>(null);
    const [printReq, setPrintReq] = useState<Requisition | null>(null);

    const [searchTerm, setSearchTerm] = useState('');
    const { selectedBusinessUnit } = useBusinessUnit();
    const [dateRange, setDateRange] = useState<{ start: string | null; end: string | null }>({ start: null, end: null });
    const { hasPermission } = usePermissions();

    // Sorting state
    const [sortField, setSortField] = useState<SortField>('id');
    const [sortDirection, setSortDirection] = useState<SortDirection>('desc');

    const [description, setDescription] = useState('');
    const [remarks, setRemarks] = useState('');
    const [dateNeeded, setDateNeeded] = useState('');
    const [attachmentLink, setAttachmentLink] = useState('');
    const [newItems, setNewItems] = useState<RequisitionItem[]>([]);
    const [tempItem, setTempItem] = useState<Partial<RequisitionItem>>({ name: '', quantity: 1, uom: 'pcs', remarks: '' });

    const [selectedBurf, setSelectedBurf] = useState<Requisition | null>(null);
    // FIX L2: Added error state to replace browser alert() with inline messages
    const [saveError, setSaveError] = useState<string | null>(null);
    // Submission loading state to prevent double-clicks
    const [isSubmitting, setIsSubmitting] = useState(false);

    // Tab state for Active vs Completed
    const [activeTab, setActiveTab] = useState<'active' | 'completed'>('active');

    const isUrgent = useMemo(() => {
        if (!dateNeeded) return false;
        const today = new Date();
        const needed = new Date(dateNeeded);
        const diffTime = needed.getTime() - today.getTime();
        const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
        return diffDays < 5;
    }, [dateNeeded]);

    const handleSort = (field: SortField) => {
        if (sortField === field) {
            setSortDirection(sortDirection === 'asc' ? 'desc' : 'asc');
        } else {
            setSortField(field);
            setSortDirection('asc');
        }
    };

    const renderSortIcon = (field: SortField) => {
        if (sortField !== field) return <ArrowUpDown size={14} className="text-slate-600 ml-1" />;
        return sortDirection === 'asc'
            ? <ArrowUp size={14} className="text-purple-400 ml-1" />
            : <ArrowDown size={14} className="text-purple-400 ml-1" />;
    };

    const filteredRequisitions = useMemo(() => {
        const userHasGlobalAccess = hasPermission('procurement:burf:view:all');

        const filtered = visibleRequisitions
            .filter(req => {
                // FIX: Only show root BURF records in BURF view
                // - ID must start with "BURF-" (excludes PRF-xxxx, etc.)
                // - ID must NOT contain "-Batch" (excludes child batch records like BURF-0019-Batch01)
                if (!req.id.startsWith('BURF-') || req.id.includes('-Batch')) {
                    return false;
                }

                // Filter out specific statuses as requested
                if ([
                    RequisitionStatus.FUNDS_RELEASED,
                    RequisitionStatus.LIQUIDATION_FILED,
                    RequisitionStatus.LIQUIDATION_REJECTED,
                    RequisitionStatus.AUDITED_CLEARED
                ].includes(req.status)) {
                    return false;
                }

                if (userHasGlobalAccess) {
                    if (selectedBusinessUnit !== 'all' && req.businessId !== selectedBusinessUnit) {
                        return false;
                    }
                } else {
                    // Multi-BU support: check all BUs the user belongs to
                    const userBuIds = currentUser.businessUnitIds?.length
                        ? currentUser.businessUnitIds
                        : [currentUser.businessId];
                    if (!userBuIds.includes(req.businessId)) {
                        return false;
                    }
                }
                if (searchTerm) {
                    const searchLower = searchTerm.toLowerCase();
                    const requester = allUsers.find(u => u.id === req.requesterId);
                    const business = businesses.find(b => b.id === req.businessId);
                    if (!(
                        (req.id || '').toLowerCase().includes(searchLower) ||
                        (req.description || '').toLowerCase().includes(searchLower) ||
                        (requester?.name || '').toLowerCase().includes(searchLower) ||
                        (business?.name || '').toLowerCase().includes(searchLower)
                    )) {
                        return false;
                    }
                }

                // Date Filter
                if (dateRange.start && dateRange.end) {
                    const reqDate = new Date(req.dateCreated);
                    const start = new Date(dateRange.start);
                    const end = new Date(dateRange.end);
                    // Set end date to end of day
                    end.setHours(23, 59, 59, 999);

                    if (reqDate < start || reqDate > end) {
                        return false;
                    }
                }

                return true;
            });

        // Secondary sort: prioritize URGENT items first, then apply user-selected sort
        return filtered.sort((a, b) => {
            // First, prioritize urgent items at the top
            const aIsUrgent = a.priority === 'URGENT' ? 1 : 0;
            const bIsUrgent = b.priority === 'URGENT' ? 1 : 0;
            if (bIsUrgent !== aIsUrgent) {
                return bIsUrgent - aIsUrgent; // Urgent items first
            }

            // Then apply user-selected sort
            let aValue: any = a[sortField];
            let bValue: any = b[sortField];

            if (sortField === 'businessId') {
                aValue = businesses.find(biz => biz.id === a.businessId)?.name || '';
                bValue = businesses.find(biz => biz.id === b.businessId)?.name || '';
            } else if (sortField === 'requesterId') {
                aValue = allUsers.find(u => u.id === a.requesterId)?.name || '';
                bValue = allUsers.find(u => u.id === b.requesterId)?.name || '';
            }

            if (aValue < bValue) return sortDirection === 'asc' ? -1 : 1;
            if (aValue > bValue) return sortDirection === 'asc' ? 1 : -1;
            return 0;
        });

    }, [visibleRequisitions, searchTerm, allUsers, businesses, currentUser.role, currentUser.businessId, selectedBusinessUnit, sortField, sortDirection, hasPermission, dateRange]);

    // Tab-based filtering: Active vs Completed
    const tabbedRequisitions = useMemo(() => {
        return filteredRequisitions.filter(req => {
            if (activeTab === 'active') {
                return req.status !== RequisitionStatus.BURF_COMPLETED;
            }
            if (activeTab === 'completed') {
                return req.status === RequisitionStatus.BURF_COMPLETED;
            }
            return true;
        });
    }, [filteredRequisitions, activeTab]);

    // Count for badge display
    const activeCount = filteredRequisitions.filter(r => r.status !== RequisitionStatus.BURF_COMPLETED).length;
    const completedCount = filteredRequisitions.filter(r => r.status === RequisitionStatus.BURF_COMPLETED).length;

    const openDrawer = (req: Requisition) => {
        setSelectedBurf(req);
    };

    const resetForm = () => {
        setDescription('');
        setRemarks('');
        setDateNeeded('');
        setAttachmentLink('');
        setNewItems([]);
        setTempItem({ name: '', quantity: 1, uom: 'pcs', remarks: '' });
        setEditingId(null);
        setIsCreating(false);
    };

    const editRequisition = (req: Requisition) => {
        // Navigate to full-screen BURF edit page
        navigate(`/burf/edit/${req.id}`);
    };

    const addItem = () => {
        if (tempItem.name && tempItem.quantity) {
            setNewItems([...newItems, { ...tempItem, itemId: `temp-${Date.now()}` } as RequisitionItem]);
            setTempItem({ name: '', quantity: 1, uom: 'pcs', remarks: '' });
        }
    };

    const removeItem = (idx: number) => {
        setNewItems(newItems.filter((_, i) => i !== idx));
    };

    const saveRequisition = async (isFinalSubmission: boolean) => {
        // Prevent duplicate submissions
        if (isSubmitting) return;
        setIsSubmitting(true);

        try {
            const status = isFinalSubmission ? RequisitionStatus.BURF_PENDING_MANAGER : RequisitionStatus.DRAFT;
            const attachments = attachmentLink ? [attachmentLink] : [];

            let reqId = editingId;
            if (!reqId) {
                reqId = await CounterService.generateBURFId();
            }

            // FIX C6: Sanitize all user-generated content before saving to Firestore
            const nowISO = new Date().toISOString();
            const baseReq: any = {
                id: reqId,
                requesterId: currentUser.id,
                // Denormalized user info - stored directly for fast reading without lookups
                requesterName: currentUser.name,
                requesterPhotoUrl: currentUser.avatar || '',
                businessId: currentUser.businessId,
                // FIX: Only store externalLink if it's a valid URL (use spread to avoid undefined)
                ...(attachmentLink && isValidUrl(attachmentLink) ? { externalLink: attachmentLink } : {}),
                items: sanitizeItems(newItems), // Sanitize item names and remarks
                totalAmount: 0,
                status: status,
                dateCreated: nowISO.split('T')[0],
                description: sanitizeText(description), // Sanitize user input
                remarks: sanitizeText(remarks), // Sanitize user input
                dateNeeded,
                isUrgent, // Persist urgency flag for querying/filtering
                priority: isUrgent ? 'URGENT' : 'NORMAL',
                attachments,
                timestamp: nowISO,
                // Add initial history entry for creation
                history: [{
                    date: nowISO.split('T')[0],
                    timestamp: nowISO,
                    actorId: currentUser.id,
                    actorName: currentUser.name,
                    action: isFinalSubmission ? 'BURF Created & Submitted' : 'BURF Draft Created',
                    stage: status,
                    comments: `Created by ${currentUser.name}`
                }]
            };

            if (editingId) {
                const original = visibleRequisitions.find(r => r.id === editingId);
                onUpdateRequisition({ ...original, ...baseReq, id: editingId });
            } else {
                onCreateRequisition(baseReq);
            }
            resetForm();
        } catch (error) {
            console.error("Error saving requisition:", error);
            // FIX L2: Replaced browser alert() with error state for better UX
            setSaveError("Failed to save requisition. Please try again.");
            // Clear error after 5 seconds
            setTimeout(() => setSaveError(null), UI_CONSTANTS.TOAST_DURATION);
        } finally {
            setIsSubmitting(false);
        }
    };

    // Redirect to full-screen BURFPage when creating/editing
    // This replaces the old inline form rendering
    React.useEffect(() => {
        if (isCreating) {
            if (editingId) {
                navigate(`/burf/edit/${editingId}`);
            } else {
                navigate('/burf/new');
            }
            setIsCreating(false);
            setEditingId(null);
        }
    }, [isCreating, editingId, navigate]);

    // OLD INLINE FORM REMOVED - Now using full-screen BURFPage
    // The following block was removed and replaced with the useEffect above
    const _REMOVED_INLINE_FORM = false;
    if (_REMOVED_INLINE_FORM) {
        return (
            <div className="max-w-4xl mx-auto space-y-6 animate-in fade-in slide-in-from-bottom-4 text-white">
                <div className="flex items-center gap-4">
                    <button onClick={resetForm} className="text-slate-300 hover:text-white text-sm font-medium">Cancel</button>
                    <h1 className="text-2xl font-bold">
                        {editingId ? 'Edit Requisition' : 'New Requisition (BURF)'}
                    </h1>
                </div>

                <Card className="!p-6 space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div className="col-span-1">
                            <label className="block text-sm font-medium text-slate-300 mb-1">Description / Purpose</label>
                            <input className="w-full p-2 border border-slate-700 bg-slate-800 rounded-md" value={description} onChange={e => setDescription(e.target.value)} placeholder="e.g. Monthly Office Supplies" />
                        </div>
                        <div className="col-span-1">
                            <label className="block text-sm font-medium text-slate-300 mb-1">Date Needed</label>
                            <input
                                type="date"
                                className={`w-full p-2 border ${isUrgent ? 'border-orange-500' : 'border-slate-700'} bg-slate-800 rounded-md`}
                                value={dateNeeded}
                                onChange={e => setDateNeeded(e.target.value)}
                            />
                            {isUrgent && (
                                <div className="flex items-center gap-1 text-orange-400 text-xs mt-1">
                                    <AlertTriangle size={12} />
                                    <span>Date is less than 5 days. Marked as URGENT.</span>
                                </div>
                            )}
                        </div>
                        <div className="col-span-2">
