                                                href={req.externalLink || req.attachments?.[0]}
                                                target="_blank"
                                                rel="noopener noreferrer"
                                                className="text-blue-500 dark:text-blue-400 flex items-center gap-1 text-xs hover:underline"
                                                onClick={(e) => e.stopPropagation()}
                                            >
                                                <Paperclip size={12} /> View Link
                                            </a>
                                        </div>
                                    )}
                                </div>

                                <div className="flex items-center justify-between pt-3 border-t border-slate-200 dark:border-slate-700">
                                    <div className="flex items-center gap-2">
                                        <div className="w-6 h-6 rounded-full bg-slate-200 dark:bg-slate-700 flex items-center justify-center text-xs font-bold text-slate-600 dark:text-slate-300 overflow-hidden">
                                            {req.requesterPhotoUrl ? (
                                                <img src={req.requesterPhotoUrl} alt={requesterName} className="w-full h-full object-cover" />
                                            ) : (
                                                requesterName.charAt(0).toUpperCase()
                                            )}
                                        </div>
                                        <span className="text-xs text-slate-600 dark:text-slate-400 truncate max-w-[100px]">{requesterName}</span>
                                    </div>

                                    <div className="flex gap-3" onClick={e => e.stopPropagation()}>
                                        <button onClick={() => setPrintReq(req)} className="text-slate-500 dark:text-slate-400 hover:text-purple-600 dark:hover:text-white p-2 bg-slate-100 dark:bg-slate-700/50 rounded-full transition-colors">
                                            <Printer size={16} />
                                        </button>
                                        {canEdit && (
                                            <button
                                                onClick={() => editRequisition(req)}
                                                className="text-blue-500 dark:text-blue-400 hover:text-blue-700 dark:hover:text-blue-300 p-2 bg-blue-500/10 rounded-full transition-colors"
                                            >
                                                {req.status === RequisitionStatus.REJECTED ? <RefreshCw size={16} /> : <Edit size={16} />}
                                            </button>
                                        )}
                                    </div>
                                </div>
                            </div>
                        );
                    })
                )}
            </div>

            {printReq && <BURFPrintModal req={printReq} onClose={() => setPrintReq(null)} business={businesses.find(b => b.id === printReq.businessId)} requester={allUsers.find(u => u.id === printReq.requesterId)} />}

            {/* Quick Peek Drawer */}
            <RequisitionDrawer
                requisition={selectedBurf}
                isOpen={!!selectedBurf}
                onClose={() => setSelectedBurf(null)}
                variant="BURF"
                businesses={businesses}
                allUsers={allUsers}
                getStatusBadge={getStatusBadge}
                onCancel={async () => {
                    if (selectedBurf && confirm(`Are you sure you want to CANCEL ${selectedBurf.id}? This action cannot be undone.`)) {
                        try {
                            await executeWorkflowAction({
                                requisitionId: selectedBurf.id,
                                action: 'CANCEL',
                                user: {
                                    uid: currentUser.id,
                                    displayName: currentUser.name,
                                    email: currentUser.email
                                },
                                reason: 'Cancelled by SuperAdmin'
                            });
                            setSelectedBurf(null);
                        } catch (error: any) {
                            console.error('Error cancelling:', error);
                            alert(`Failed to cancel: ${error.message || 'Unknown error'}`);
                        }
                    }
                }}
                canCancel={!!selectedBurf && isSuperAdmin(currentUser.role) && selectedBurf.status !== RequisitionStatus.CANCELLED}
            />
        </div>
    );
};

export default BurfView;

import React, { useState } from 'react';
import { ArrowRight, CheckCircle } from 'lucide-react';
import type { Requisition, RequisitionItem, SupplierDetails } from '../types';

interface PRFFormViewProps {
    requisitionId: string;
    onCancel: () => void;
    requisitions: Requisition[];
    handleSubmitPRF: (id: string, details: SupplierDetails, updatedItems: RequisitionItem[]) => void;
}

export const PRFFormView: React.FC<PRFFormViewProps> = ({ requisitionId, onCancel, requisitions, handleSubmitPRF }) => {
    // FIX: Find requisition first (used for initialization, but hooks MUST come before returns)
    const req = requisitions.find(r => r.id === requisitionId);

    // FIX: All useState hooks MUST be called before any conditional returns (React Rules of Hooks)
    // Use useMemo-style inline defaults that handle undefined req gracefully
    const [supplier, setSupplier] = useState<SupplierDetails>(() => 
        req?.prfDetails?.supplier || { name: '', tin: '', address: '', paymentMode: '', terms: '' }
    );

    // Initialize items with lazy initializer to handle undefined req
    const [items, setItems] = useState<RequisitionItem[]>(() => 
        req?.items.map(i => ({ ...i, price: i.price || 0 })) || []
    );

    // Selection State: Default all selected
    const [selectedItemIds, setSelectedItemIds] = useState<string[]>(() => 
        req?.items.map(i => i.itemId) || []
    );

    // Confirmation Modal State
    const [showConfirmModal, setShowConfirmModal] = useState(false);

    // FIX: NOW we can safely do the conditional return AFTER all hooks are declared
    if (!req) {
        return (
            <div className="p-8 text-center">
                <div className="text-red-500 font-medium">Requisition not found</div>
                <button 
                    onClick={onCancel} 
                    className="mt-4 px-4 py-2 bg-slate-200 rounded-lg hover:bg-slate-300"
                >
                    Go Back
                </button>
            </div>
        );
    }

    const handleItemChange = (index: number, field: keyof RequisitionItem, value: any) => {
        const newItems = [...items];
        newItems[index] = { ...newItems[index], [field]: value };
        setItems(newItems);
    };

    const toggleSelection = (itemId: string) => {
        setSelectedItemIds(prev =>
            prev.includes(itemId)
                ? prev.filter(id => id !== itemId)
                : [...prev, itemId]
        );
    };

    const toggleSelectAll = () => {
        if (selectedItemIds.length === items.length) {
            setSelectedItemIds([]);
        } else {
            setSelectedItemIds(items.map(i => i.itemId));
        }
    };

    // Derived state for selected items
    const selectedItems = items.filter(i => selectedItemIds.includes(i.itemId));
    const totalAmount = selectedItems.reduce((sum, item) => sum + (item.quantity * item.price), 0);

    const handlePreSubmit = () => {
        if (selectedItems.length === 0) {
            alert("Please select at least one item.");
            return;
        }

        if (selectedItems.length < items.length) {
            setShowConfirmModal(true);
            return;
        }

        handleSubmitPRF(requisitionId, supplier, selectedItems);
    };

    const confirmSplitSubmit = () => {
        handleSubmitPRF(requisitionId, supplier, selectedItems);
        setShowConfirmModal(false);
    }

    return (
        <div className="space-y-6 animate-in fade-in slide-in-from-top-4 relative">
            {/* Custom Confirmation Modal */}
            {showConfirmModal && (
                <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
                    <div className="bg-slate-900 text-white rounded-xl shadow-2xl max-w-md w-full p-6 border border-slate-700 animate-in zoom-in-95 duration-200">
                        <div className="flex items-start gap-4">
                            <div className="flex-1">
                                <h3 className="text-lg font-bold mb-2 flex items-center gap-2">
                                    Confirm Split Requisition
                                </h3>
                                <p className="text-slate-300 text-sm mb-4">
                                    You have selected <span className="font-bold text-white">{selectedItems.length}</span> out of {items.length} items.
                                </p>
                                <p className="text-slate-300 text-sm mb-6">
                                    A new requisition will be created for the remaining <span className="font-bold text-white">{items.length - selectedItems.length}</span> items.
                                    <br /><br />
                                    Proceed with splitting this request?
                                </p>
                                <div className="flex justify-end gap-3">
                                    <button
                                        onClick={() => setShowConfirmModal(false)}
                                        className="px-4 py-2 rounded-lg bg-slate-800 hover:bg-slate-700 text-slate-300 text-sm font-medium transition-colors"
                                    >
                                        Cancel
                                    </button>
                                    <button
                                        onClick={confirmSplitSubmit}
                                        className="px-4 py-2 rounded-lg bg-green-600 hover:bg-green-700 text-white text-sm font-bold transition-colors shadow-lg shadow-green-900/20"
                                    >
                                        OK
                                    </button>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            )}

            <div className="flex items-center gap-4">
                <button onClick={onCancel} className="text-slate-500 hover:text-slate-800 flex items-center gap-1">
                    <ArrowRight size={16} className="rotate-180" /> Back
                </button>
                <h1 className="text-2xl font-bold text-slate-900">Prepare Purchase Requisition (PRF)</h1>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                <div className="lg:col-span-2 space-y-6">
                    {/* Items Table */}
                    <div className="bg-white rounded-xl border border-slate-200 shadow-sm p-6">
                        <h3 className="text-lg font-bold text-slate-900 mb-4">Item Specification & Costing</h3>
                        <div className="overflow-x-auto">
                            <table className="w-full text-sm text-left">
                                <thead className="bg-slate-50 text-xs uppercase font-medium text-slate-500">
                                    <tr>
                                        <th className="px-4 py-2 w-10">
                                            <input
                                                type="checkbox"
                                                checked={selectedItemIds.length === items.length && items.length > 0}
                                                onChange={toggleSelectAll}
                                                className="rounded border-slate-300"
                                            />
                                        </th>
                                        <th className="px-4 py-2">Item</th>
                                        <th className="px-4 py-2">Qty / UOM</th>
                                        <th className="px-4 py-2">Remarks</th>
                                        <th className="px-4 py-2 w-32">Unit Price</th>
                                        <th className="px-4 py-2 text-right">Total</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-100">
                                    {items.map((item, idx) => (
                                        <tr key={item.itemId} className={!selectedItemIds.includes(item.itemId) ? 'opacity-50 bg-slate-50' : ''}>
                                            <td className="px-4 py-3">
                                                <input
                                                    type="checkbox"
                                                    checked={selectedItemIds.includes(item.itemId)}
                                                    onChange={() => toggleSelection(item.itemId)}
                                                    className="rounded border-slate-300"
                                                />
                                            </td>
                                            <td className="px-4 py-3 font-medium">{item.name}</td>
                                            <td className="px-4 py-3">{item.quantity} <span className="text-slate-500 text-xs">{item.uom}</span></td>
                                            <td className="px-4 py-3 text-slate-500 text-xs">{item.remarks}</td>
                                            <td className="px-4 py-3">
                                                <input
                                                    type="number"
                                                    disabled={!selectedItemIds.includes(item.itemId)}
                                                    className="w-full p-1 border border-slate-300 rounded text-right text-sm disabled:bg-slate-100"
                                                    value={item.price}
                                                    onChange={(e) => handleItemChange(idx, 'price', parseFloat(e.target.value) || 0)}
                                                />
                                            </td>
                                            <td className="px-4 py-3 text-right font-medium">
                                                ₱{(item.quantity * item.price)?.toLocaleString()}
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                                <tfoot className="bg-slate-50 font-bold">
                                    <tr>
                                        <td colSpan={5} className="px-4 py-3 text-right">Total Amount (Selected)</td>
                                        <td className="px-4 py-3 text-right">₱{totalAmount?.toLocaleString()}</td>
                                    </tr>
                                </tfoot>
                            </table>
                        </div>
                    </div>

                    <div className="bg-white rounded-xl border border-slate-200 shadow-sm p-6">
                        <h3 className="text-lg font-bold text-slate-900 mb-4">Supplier Information</h3>
                        <div className="grid grid-cols-2 gap-4">
                            <div className="col-span-2">
                                <label className="block text-xs font-medium text-slate-500 mb-1">Supplier Name</label>
                                <input className="w-full p-2 border border-slate-300 rounded-md text-sm" value={supplier.name} onChange={e => setSupplier({ ...supplier, name: e.target.value })} placeholder="Official Business Name" />
                            </div>
                            <div>
                                <label className="block text-xs font-medium text-slate-500 mb-1">TIN</label>
                                <input className="w-full p-2 border border-slate-300 rounded-md text-sm" value={supplier.tin} onChange={e => setSupplier({ ...supplier, tin: e.target.value })} placeholder="000-000-000" />
                            </div>
                            <div>
                                <label className="block text-xs font-medium text-slate-500 mb-1">Payment Mode</label>
                                <select className="w-full p-2 border border-slate-300 rounded-md text-sm" value={supplier.paymentMode} onChange={e => setSupplier({ ...supplier, paymentMode: e.target.value })}>
                                    <option value="">Select Mode</option>
                                    <option value="Cash">Cash</option>
                                    <option value="Check">Check</option>
                                    <option value="Bank Transfer">Bank Transfer</option>
                                </select>
                            </div>
                            <div className="col-span-2">
                                <label className="block text-xs font-medium text-slate-500 mb-1">Address</label>
                                <input className="w-full p-2 border border-slate-300 rounded-md text-sm" value={supplier.address} onChange={e => setSupplier({ ...supplier, address: e.target.value })} placeholder="Registered Address" />
                            </div>
                            <div className="col-span-2">
                                <label className="block text-xs font-medium text-slate-500 mb-1">Terms</label>
                                <input className="w-full p-2 border border-slate-300 rounded-md text-sm" value={supplier.terms} onChange={e => setSupplier({ ...supplier, terms: e.target.value })} placeholder="e.g. 30 Days, COD" />
                            </div>
                        </div>
                    </div>
                </div>

                <div className="space-y-6">
                    <div className="bg-indigo-50 p-6 rounded-xl border border-indigo-100">
                        <h4 className="text-indigo-900 font-bold mb-2">Ready to Submit?</h4>
                        <p className="text-sm text-indigo-700 mb-4">
                            {selectedItems.length < items.length
                                ? `Note: You are creating a PRF for ${selectedItems.length} item(s). The remaining items will be moved to a new requisition.`
                                : "Please ensure all costs are final and supplier details are verified. This will be sent to the Business Unit Manager for final approval."
                            }
                        </p>
                        <button
                            onClick={handlePreSubmit}
                            disabled={!supplier.name || totalAmount === 0 || selectedItems.length === 0}
                            className="w-full py-2 bg-indigo-600 text-white rounded-lg font-medium hover:bg-indigo-700 disabled:opacity-50 flex justify-center items-center gap-2"
                        >
                            <CheckCircle size={18} /> Submit PRF
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
};

import React, { useState, useMemo, useEffect } from 'react';
import { useSearchParams } from 'react-router-dom';
import { Search, CheckCircle, XCircle, Printer } from 'lucide-react';
import type { Requisition, Business, User } from '../../../shared/types';
import { RequisitionStatus, isSuperAdmin } from '../types';
import { RequisitionService } from '../services/requisitions.service';
import { executeWorkflowAction } from '../services/workflowService';
import { usePermissions } from '../../../hooks/usePermissions';
import { SettingsService, type ApproverAssignments } from '../../../shared/services/settings.service';
import Card from '../../../shared/components/Card';
import RequisitionDrawer from '../../../shared/components/RequisitionDrawer';
import RejectionModal from '../../../shared/components/RejectionModal';
import BURFPrintModal from '../components/BURFPrintModal';
import PRFPrintModal from '../components/PRFPrintModal';
import SignatureModal from '../../../shared/components/SignatureModal';
import { SignatureService } from '../../../shared/services/signature.service';
import { DateRangeFilter } from '../../../shared/components/DateRangeFilter';
import { useBusinessUnit } from '../../../contexts/BusinessUnitContext';

interface ProcurementApprovalsViewProps {
    currentUser: User;
    requisitions: Requisition[];
    allUsers: User[];
    businesses: Business[];
    onUpdateRequisition: (req: Requisition) => void;
    getStatusBadge: (status: RequisitionStatus) => React.ReactNode;
}

// Valid sub-tab values
type PendingSubTab = 'burf' | 'cic' | 'prf' | 'gmprf';

export const ProcurementApprovalsView: React.FC<ProcurementApprovalsViewProps> = ({
    currentUser,
    requisitions,
    allUsers,
    businesses,
    getStatusBadge
}) => {
    const [searchParams] = useSearchParams();
    const initialTab = (searchParams.get('tab') as PendingSubTab) || 'burf';

    const [searchTerm, setSearchTerm] = useState('');
    const { selectedBusinessUnit } = useBusinessUnit();
    const [dateRange, setDateRange] = useState<{ start: string | null; end: string | null }>({ start: null, end: null });
    const [rejectingReq, setRejectingReq] = useState<Requisition | null>(null);
    const [printingReq, setPrintingReq] = useState<Requisition | null>(null);
    const [drawerReq, setDrawerReq] = useState<Requisition | null>(null); // Quick Peek drawer
    const [drawerLoading, setDrawerLoading] = useState(false);
    const [activeTab, setActiveTab] = useState<'pending' | 'history'>('pending');
    const [pendingSubTab, setPendingSubTab] = useState<PendingSubTab>(initialTab);
    const [signingReq, setSigningReq] = useState<Requisition | null>(null);
    const [signatureLoading, setSignatureLoading] = useState(false);
    const { hasPermission } = usePermissions();

    // Workflow Approver Assignments for GM PRF filtering
    const [approverAssignments, setApproverAssignments] = useState<ApproverAssignments>({});

    // Load approver assignments on mount
    useEffect(() => {
        SettingsService.getApproverAssignments().then(setApproverAssignments);
    }, []);

    // Sync active tab with URL parameters & Deep Linking
    useEffect(() => {
        const tabParam = searchParams.get('tab') as PendingSubTab;
        if (tabParam && ['burf', 'cic', 'prf', 'gmprf'].includes(tabParam)) {
            setPendingSubTab(tabParam);
        }

        // Deep Linking: Check for 'id' parameter
        const idParam = searchParams.get('id');
        if (idParam && !drawerReq) {
            const foundReq = requisitions.find(r => r.id === idParam);
            if (foundReq) {
                setDrawerReq(foundReq);
            }
        }
    }, [searchParams, requisitions, drawerReq]);

    // Check if current user is the assigned GM
    const isAssignedGM = currentUser.id === approverAssignments.gmUid;

    // Determine which statuses the current user is allowed to approve
    const userApprovalStatuses = useMemo(() => {
        const statuses: RequisitionStatus[] = [];

        if (hasPermission('procurement:burf:approve:manager')) {
            statuses.push(RequisitionStatus.BURF_PENDING_MANAGER);
        }
        if (hasPermission('procurement:burf:approve:cic')) {
            statuses.push(RequisitionStatus.BURF_PENDING_CIC);
        }
        // PRF_PENDING_MANAGER now uses designatedApproverId - include for all users who might be designated
        statuses.push(RequisitionStatus.PRF_PENDING_MANAGER);

        // GM PRF Approval (Step 2 for items >= 50k) - only include if user is the assigned GM
        if (isAssignedGM || hasPermission('procurement:burf:view:all')) {
            statuses.push(RequisitionStatus.PENDING_GM_PRF_APPROVAL);
        }

        return statuses;
    }, [hasPermission, isAssignedGM]);

    // Determine approved/history statuses
    const approvedStatuses = [
        RequisitionStatus.READY_FOR_PRF,
        RequisitionStatus.APPROVED_FOR_PAYMENT,
        RequisitionStatus.FUNDS_RELEASED,
        RequisitionStatus.LIQUIDATION_FILED,
        RequisitionStatus.AUDITED_CLEARED
    ];

    const filteredRequisitions = useMemo(() => {
        return requisitions.filter(req => {
            // Filter based on active tab
            if (activeTab === 'pending') {
                // Pending tab: show only pending statuses relevant to user
                if (!userApprovalStatuses.includes(req.status)) return false;

                // Note: Sub-tab filtering (BURF/CIC/PRF) is applied after this via displayRequisitions

                // PRF_PENDING_MANAGER: Must be the designated approver, manager for BURF-sourced, or have global access
                if (req.status === RequisitionStatus.PRF_PENDING_MANAGER) {
                    const isDesignated = req.prfDetails?.designatedApproverId === currentUser.id;
                    const isManagerForBurf = !!req.parentBurfId && hasPermission('procurement:prf:approve:manager');
                    const hasGlobalAccess = hasPermission('procurement:burf:view:all');
                    const isSuperAdminUser = isSuperAdmin(currentUser.role);
                    if (!isDesignated && !isManagerForBurf && !hasGlobalAccess && !isSuperAdminUser) {
                        return false;
                    }
                }
            } else {
                // History tab: show only approved statuses
                if (!approvedStatuses.includes(req.status)) return false;
            }

            // Filter by Business Unit
            const hasGlobal = hasPermission('procurement:burf:view:all');
            if (hasGlobal) {
                if (selectedBusinessUnit !== 'all' && req.businessId !== selectedBusinessUnit) return false;
            } else {
                // Multi-BU support: check all BUs the user belongs to
                const userBuIds = currentUser.businessUnitIds?.length
                    ? currentUser.businessUnitIds
                    : [currentUser.businessId];
                if (!userBuIds.includes(req.businessId)) return false;
            }

            // Search Filter
            if (searchTerm) {
                const term = searchTerm.toLowerCase();
                const requester = allUsers.find(u => u.id === req.requesterId)?.name.toLowerCase() || '';
                const business = businesses.find(b => b.id === req.businessId)?.name.toLowerCase() || '';

                const matchesSearch = (
                    req.id.toLowerCase().includes(term) ||
                    req.description.toLowerCase().includes(term) ||
                    requester.includes(term) ||
                    business.includes(term)
                );

                if (!matchesSearch) return false;
            }

            // Date Filter
            if (dateRange.start && dateRange.end) {
                const reqDate = new Date(req.dateCreated);
                const start = new Date(dateRange.start);
                const end = new Date(dateRange.end);
                // Set end date to end of day
                end.setHours(23, 59, 59, 999);

                if (reqDate < start || reqDate > end) {
                    return false;
                }
            }

            return true;
        }).sort((a, b) => {
            // Sort history by date descending
            if (activeTab === 'history') {
                return new Date(b.dateCreated).getTime() - new Date(a.dateCreated).getTime();
            }
            return new Date(b.dateCreated).getTime() - new Date(a.dateCreated).getTime();
        });
    }, [requisitions, activeTab, userApprovalStatuses, approvedStatuses, selectedBusinessUnit, searchTerm, currentUser, allUsers, businesses, hasPermission, dateRange]);

    // === SECONDARY TABS: Split pending requisitions into categories ===
    // Tab 1: BURF Approvals (BURF_PENDING_MANAGER only)
    const burfApprovals = useMemo(() =>
        filteredRequisitions.filter(req =>
            req.status === RequisitionStatus.BURF_PENDING_MANAGER &&
            activeTab === 'pending'
        ), [filteredRequisitions, activeTab]);

    // Tab 2: CIC Reviews (Check Prep tasks)
    const cicReviews = useMemo(() =>
        filteredRequisitions.filter(req =>
            req.status === RequisitionStatus.BURF_PENDING_CIC &&
            activeTab === 'pending'
        ), [filteredRequisitions, activeTab]);

    // Tab 3: PRF Approvals (PRF Step 1 - Manager/Designated Approver ONLY)
    const prfApprovals = useMemo(() =>
        filteredRequisitions.filter(req =>
            req.status === RequisitionStatus.PRF_PENDING_MANAGER &&
            activeTab === 'pending'
        ), [filteredRequisitions, activeTab]);

    // Tab 4: GM PRF Approvals (Step 2 - General Manager for items >= 50k)
    const gmPrfApprovals = useMemo(() =>
        filteredRequisitions.filter(req =>
            req.status === RequisitionStatus.PENDING_GM_PRF_APPROVAL &&
            activeTab === 'pending'
        ), [filteredRequisitions, activeTab]);

    // Get current sub-tab's data
    const getActiveSubTabItems = () => {
        switch (pendingSubTab) {
            case 'burf': return burfApprovals;
            case 'cic': return cicReviews;
            case 'prf': return prfApprovals;
            case 'gmprf': return gmPrfApprovals;
            default: return burfApprovals;
        }
    };

    // For display: use filtered items based on sub-tab when in pending mode
    const displayRequisitions = activeTab === 'pending'
        ? getActiveSubTabItems()
        : filteredRequisitions;

    const handleApprove = async (req: Requisition, e: React.MouseEvent) => {
        e.stopPropagation();
        // BOD users skip signature modal — approve directly
        if (hasPermission('procurement:approval:approve:skip_signature')) {
            try {
                await RequisitionService.approveRequisition(
                    req.id, currentUser.id, currentUser.name, undefined, undefined
                );
            } catch (error: any) {
                console.error('Error approving:', error);
                alert(`Failed to approve: ${error.message}`);
            }
            return;
        }
        setSigningReq(req);
    };

    const handleSignatureConfirm = async (signatureBlob: Blob) => {
        if (!signingReq) return;
        setSignatureLoading(true);
        try {
            const signatureUrl = await SignatureService.uploadSignature(
                signingReq.id,
                currentUser.id,
                signatureBlob
            );
            await RequisitionService.approveRequisition(
                signingReq.id,
                currentUser.id,
                currentUser.name,
                undefined,
                signatureUrl
            );
            setSigningReq(null);
            if (drawerReq?.id === signingReq.id) {
                setDrawerReq(null);
            }
        } catch (error: any) {
            console.error('Error approving requisition:', error);
            alert(`Failed to approve requisition: ${error.message || 'Unknown error'}`);
        } finally {
            setSignatureLoading(false);
        }
    };

    const handleRejectClick = (req: Requisition, e: React.MouseEvent) => {
        e.stopPropagation();
        setRejectingReq(req);
    };

    const handleRejectConfirm = async (reason: string) => {
        if (rejectingReq) {
            try {
                await RequisitionService.rejectRequisition(
                    rejectingReq.id,
                    currentUser.id,
                    currentUser.name,
                    reason
                );
                setRejectingReq(null);
            } catch (error: any) {
                console.error('Error rejecting requisition:', error);
                alert(`Failed to reject requisition: ${error.message || 'Unknown error'}`);
            }
        }
    };

    const handlePrintClick = (req: Requisition, e: React.MouseEvent) => {
        e.stopPropagation();
        setPrintingReq(req);
    };

    // Drawer approve/reject handlers
    const handleDrawerApprove = async () => {
        if (!drawerReq) return;
        // BOD users skip signature modal — approve directly
        if (hasPermission('procurement:approval:approve:skip_signature')) {
            setDrawerLoading(true);
            try {
                await RequisitionService.approveRequisition(
                    drawerReq.id, currentUser.id, currentUser.name, undefined, undefined
                );
                setDrawerReq(null);
            } catch (error: any) {
                console.error('Error approving:', error);
                alert(`Failed to approve: ${error.message}`);
            } finally {
                setDrawerLoading(false);
            }
            return;
        }
        setSigningReq(drawerReq);
    };

    const handleDrawerReject = async () => {
        if (!drawerReq) return;
        const reason = prompt('Please enter a reason for rejection:');
        if (!reason) return;

        setDrawerLoading(true);
        try {
            await RequisitionService.rejectRequisition(
                drawerReq.id,
                currentUser.id,
                currentUser.name,
                reason
            );
            setDrawerReq(null);
        } catch (error: any) {
            console.error("Error rejecting requisition:", error);
            alert(`Failed to reject requisition: ${error.message || 'Unknown error'}`);
        } finally {
            setDrawerLoading(false);
        }
    };

    // SuperAdmin Cancel Handler
    const handleDrawerCancel = async () => {
        if (!drawerReq) return;
        if (!confirm(`Are you sure you want to CANCEL ${drawerReq.id}? This action cannot be undone.`)) return;

        setDrawerLoading(true);
        try {
            await executeWorkflowAction({
                requisitionId: drawerReq.id,
                action: 'CANCEL',
                user: {
                    uid: currentUser.id,
                    displayName: currentUser.name,
                    email: currentUser.email
                },
                reason: 'Cancelled by SuperAdmin'
            });
            setDrawerReq(null);
        } catch (error: any) {
            console.error("Error cancelling requisition:", error);
            alert(`Failed to cancel: ${error.message || 'Unknown error'}`);
        } finally {
            setDrawerLoading(false);
        }
    };

    return (
        <div className="space-y-6 text-white animate-in fade-in slide-in-from-bottom-4">
            <div className="flex flex-col gap-4">
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                    <div>
                        <h1 className="text-2xl font-bold text-slate-900 dark:text-white">Action Center</h1>
                        <p className="text-slate-600 dark:text-slate-400 text-sm">Review pending requests and approval history.</p>
                    </div>

                    {/* Tabs */}
                    <div className="flex gap-2 bg-slate-100 dark:bg-slate-800/50 p-1 rounded-lg border border-slate-200 dark:border-slate-700">
                        <button
                            onClick={() => setActiveTab('pending')}
                            className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${activeTab === 'pending'
                                ? 'bg-white dark:bg-purple-600 text-purple-600 dark:text-white shadow-sm'
                                : 'text-slate-500 dark:text-slate-400 hover:text-slate-800 dark:hover:text-white hover:bg-white/50 dark:hover:bg-slate-700'
                                }`}
                        >
                            Pending Approvals
                        </button>
                        {hasPermission('procurement:approval:view:history') && (
                            <button
