const BURFPage: React.FC = () => {
    const { burfId } = useParams<Record<BURFPageParamKey, string | undefined>>();
    const navigate = useNavigate();
    const { currentUser } = useAuth();

    const isEditMode = !!burfId;

    // ========== STATE ==========
    const [loading, setLoading] = useState(isEditMode);
    const [error, setError] = useState<string | null>(null);
    const [businesses, setBusinesses] = useState<Business[]>([]);
    const { uomOptions } = useUOM();

    // Form state
    const [description, setDescription] = useState('');
    const [remarks, setRemarks] = useState('');
    const [dateNeeded, setDateNeeded] = useState('');
    const [attachmentLink, setAttachmentLink] = useState('');
    const [purchaseType, setPurchaseType] = useState<PurchaseType>('EVENT');
    const [items, setItems] = useState<RequisitionItem[]>([]);
    const [tempItem, setTempItem] = useState<Partial<RequisitionItem>>({
        name: '', quantity: 1, uom: 'pcs', remarks: '', coaCode: '', coaName: ''
    });

    // Original data for edit mode
    const [originalRequisition, setOriginalRequisition] = useState<Requisition | null>(null);

    // Submission states
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [isSavingDraft, setIsSavingDraft] = useState(false);
    const [statusMessage, setStatusMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);

    // Track dirty state
    const [isDirty, setIsDirty] = useState(false);
    const [showUnsavedModal, setShowUnsavedModal] = useState(false);
    const [pendingNavigation, setPendingNavigation] = useState<(() => void) | null>(null);

    // Track which items are in edit mode
    const [editingItems, setEditingItems] = useState<Set<string>>(new Set());

    // ========== COMPUTED VALUES ==========
    const isUrgent = useMemo(() => {
        if (!dateNeeded) return false;
        const today = new Date();
        const needed = new Date(dateNeeded);
        const diffDays = Math.ceil((needed.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
        return diffDays < 5;
    }, [dateNeeded]);

    const businessName = useMemo(() => {
        if (!currentUser) return '';
        return businesses.find(b => b.id === currentUser.businessId)?.name || currentUser.businessId;
    }, [businesses, currentUser]);

    // ========== BROWSER CLOSE WARNING ==========
    // Note: In-app navigation blocking disabled for BrowserRouter compatibility
    // useBlocker requires createBrowserRouter data router pattern

    // Browser back/close warning
    useEffect(() => {
        const handleBeforeUnload = (e: BeforeUnloadEvent) => {
            if (isDirty) {
                e.preventDefault();
                e.returnValue = '';
            }
        };
        window.addEventListener('beforeunload', handleBeforeUnload);
        return () => window.removeEventListener('beforeunload', handleBeforeUnload);
    }, [isDirty]);

    // ========== DATA FETCHING ==========
    useEffect(() => {
        const fetchData = async () => {
            if (!currentUser) {
                setError('Authentication required');
                setLoading(false);
                return;
            }

            try {
                // Fetch businesses
                const businessesSnapshot = await getDocs(collection(db, COLLECTIONS.BUSINESSES));
                const businessesList = businessesSnapshot.docs.map(d => ({ id: d.id, ...d.data() } as Business));
                setBusinesses(businessesList);

                // If editing, fetch the existing requisition
                if (burfId) {
                    const reqDoc = await getDoc(doc(db, COLLECTIONS.REQUISITIONS, burfId));
                    if (!reqDoc.exists()) {
                        setError('BURF not found');
                        setLoading(false);
                        return;
                    }

                    const reqData = { id: reqDoc.id, ...reqDoc.data() } as Requisition;
                    setOriginalRequisition(reqData);

                    // Populate form
                    setDescription(reqData.description || '');
                    setRemarks(reqData.remarks || '');
                    setDateNeeded(reqData.dateNeeded || '');
                    setAttachmentLink(reqData.externalLink || reqData.attachments?.[0] || '');
                    setPurchaseType((reqData as Requisition & { purchaseType?: PurchaseType }).purchaseType || 'EVENT');
                    setItems(reqData.items || []);
                }

                setLoading(false);
            } catch (err) {
                console.error('Error fetching BURF data:', err);
                setError(err instanceof Error ? err.message : 'Failed to load data');
                setLoading(false);
            }
        };

        fetchData();
    }, [burfId, currentUser]);

    // ========== VALIDATION ==========
    const isValid = useMemo(() => {
        return description.trim() !== '' && dateNeeded !== '' && items.length > 0;
    }, [description, dateNeeded, items]);

    // ========== HANDLERS ==========
    const markDirty = useCallback(() => setIsDirty(true), []);

    const handleAddItem = useCallback(() => {
        if (!tempItem.name || !tempItem.quantity) return;

        const newItem: RequisitionItem = {
            itemId: `temp-${Date.now()}`,
            name: tempItem.name || '',
            quantity: tempItem.quantity || 1,
            uom: tempItem.uom || 'pcs',
            stockOnHand: 0,
            price: 0,
            remarks: tempItem.remarks,
            coaCode: tempItem.coaCode,
            coaName: tempItem.coaName
        };

        setItems(prev => [...prev, newItem]);
        setTempItem({ name: '', quantity: 1, uom: 'pcs', remarks: '', coaCode: '', coaName: '' });
        markDirty();
    }, [tempItem, markDirty]);

    const handleUpdateItem = useCallback((idx: number, field: keyof RequisitionItem, value: unknown) => {
        setItems(prev => {
            const updated = [...prev];
            updated[idx] = { ...updated[idx], [field]: value };
            return updated;
        });
        markDirty();
    }, [markDirty]);

    const handleRemoveItem = useCallback((idx: number) => {
        setItems(prev => prev.filter((_, i) => i !== idx));
        markDirty();
    }, [markDirty]);

    const handleSave = async (isFinalSubmission: boolean) => {
        if (isSubmitting || isSavingDraft || !currentUser) return;

        isFinalSubmission ? setIsSubmitting(true) : setIsSavingDraft(true);

        try {
            const status = isFinalSubmission ? RequisitionStatus.BURF_PENDING_MANAGER : RequisitionStatus.DRAFT;
            const nowISO = new Date().toISOString();

            let reqId = burfId;
            if (!reqId) {
                reqId = await CounterService.generateBURFId();
            }

            const baseReq: Omit<Requisition, 'id'> & { id: string; purchaseType: PurchaseType } = {
                id: reqId,
                requesterId: currentUser.id,
                requesterName: currentUser.name,
                requesterPhotoUrl: currentUser.avatar || '',
                businessId: currentUser.businessId,
                ...(attachmentLink && isValidUrl(attachmentLink) ? { externalLink: attachmentLink } : {}),
                items: sanitizeItems(items) as RequisitionItem[],
                totalAmount: 0,
                status,
                dateCreated: originalRequisition?.dateCreated || nowISO.split('T')[0],
                description: sanitizeText(description),
                remarks: sanitizeText(remarks),
                dateNeeded,
                isUrgent,
                priority: isUrgent ? 'URGENT' : 'NORMAL',
                attachments: attachmentLink ? [attachmentLink] : [],
                timestamp: nowISO,
                purchaseType, // NEW: Purchase type
                history: [
                    ...(originalRequisition?.history || []),
                    {
                        date: nowISO.split('T')[0],
                        timestamp: nowISO,
                        actorId: currentUser.id,
                        actorName: currentUser.name,
                        action: isEditMode
                            ? (isFinalSubmission ? 'BURF Re-Submitted' : 'BURF Draft Updated')
                            : (isFinalSubmission ? 'BURF Created & Submitted' : 'BURF Draft Created'),
                        stage: status,
                        comments: `${isEditMode ? 'Updated' : 'Created'} by ${currentUser.name}`
                    }
                ]
            };

            if (isEditMode && originalRequisition) {
                await RequisitionService.updateRequisition(reqId, baseReq);
            } else {
                await RequisitionService.createRequisition(baseReq);
            }

            setIsDirty(false);

            if (isFinalSubmission) {
                navigate('/burf');
            } else {
                setStatusMessage({ type: 'success', text: '✅ Draft saved successfully!' });
                setTimeout(() => setStatusMessage(null), UI_CONSTANTS.TOAST_DURATION_SHORT);
            }
        } catch (error) {
            const msg = error instanceof Error ? error.message : 'Unknown error';
            console.error('BURF save error:', error);
            setStatusMessage({ type: 'error', text: `Failed to save: ${msg}` });
            setTimeout(() => setStatusMessage(null), UI_CONSTANTS.TOAST_DURATION);
        } finally {
            setIsSubmitting(false);
            setIsSavingDraft(false);
        }
    };

    const handleBack = () => {
        if (isDirty) {
            setShowUnsavedModal(true);
            setPendingNavigation(() => () => navigate(-1));
        } else {
            navigate(-1);
        }
    };

    // ========== RENDER ==========
    if (loading) {
        return (
            <div className="min-h-screen bg-white dark:bg-slate-900 flex items-center justify-center">
                <div className="flex flex-col items-center gap-4">
                    <Loader2 size={48} className="text-purple-600 dark:text-purple-500 animate-spin" />
                    <p className="text-slate-500 dark:text-slate-400">Loading BURF...</p>
                </div>
            </div>
        );
    }

    if (error) {
        return (
            <div className="min-h-screen bg-white dark:bg-slate-900 flex items-center justify-center">
                <div className="bg-red-50 dark:bg-red-500/10 backdrop-blur-sm border border-red-200 dark:border-red-500/30 rounded-xl p-6 max-w-md text-center shadow-lg">
                    <AlertTriangle size={48} className="text-red-500 dark:text-red-400 mx-auto mb-4" />
                    <h2 className="text-xl font-bold text-red-700 dark:text-white mb-2">Error</h2>
                    <p className="text-red-600 dark:text-red-300">{error}</p>
                    <button
                        onClick={() => navigate(-1)}
                        className="mt-4 px-4 py-2 bg-slate-200 dark:bg-slate-700 text-slate-700 dark:text-white rounded-lg hover:bg-slate-300 dark:hover:bg-slate-600"
                    >
                        Go Back
                    </button>
                </div>
            </div>
        );
    }

    return (
        <div>
            {/* Unsaved Changes Modal */}
            <UnsavedChangesModal
                isOpen={showUnsavedModal}
                onConfirmLeave={() => {
                    setShowUnsavedModal(false);
                    pendingNavigation?.();
                }}
                onStay={() => {
                    setShowUnsavedModal(false);
                    setPendingNavigation(null);
                }}
            />

            {/* Simple inline header - no box */}
            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 pt-6 pb-2">
                <div className="flex items-center justify-between">
                    <div className="flex items-center gap-4">
                        <button
                            onClick={handleBack}
                            className="text-slate-500 dark:text-slate-400 hover:text-slate-800 dark:hover:text-white flex items-center gap-2 transition-colors p-2 rounded-lg hover:bg-slate-200 dark:hover:bg-slate-700/50"
                        >
                            <ArrowLeft size={20} />
                        </button>
                        <div>
                            <h1 className="text-xl font-bold text-slate-800 dark:text-white tracking-tight">
                                {isEditMode ? 'Edit BURF' : 'New Budget Request'}
                            </h1>
                            <p className="text-sm text-slate-500 dark:text-slate-400">
                                {businessName} {description && `• ${description}`}
                            </p>
                        </div>
                    </div>
                    <div className="flex items-center gap-3">
                        {isDirty && (
                            <span className="text-amber-500 dark:text-amber-400 text-xs flex items-center gap-1.5">
                                <span className="w-1.5 h-1.5 bg-amber-500 dark:bg-amber-400 rounded-full animate-pulse" />
                                Unsaved
                            </span>
                        )}
                        <button
                            onClick={() => handleSave(false)}
                            disabled={isSavingDraft || isSubmitting}
                            className="flex items-center gap-2 px-4 py-2 bg-white dark:bg-slate-700 hover:bg-slate-50 dark:hover:bg-slate-600 text-slate-700 dark:text-white rounded-lg text-sm font-medium disabled:opacity-50 transition-all border border-slate-200 dark:border-slate-600 shadow-sm"
                        >
                            {isSavingDraft ? <Loader2 size={14} className="animate-spin" /> : <Save size={14} />}
                            Save Draft
                        </button>
                        <button
                            onClick={() => handleSave(true)}
                            disabled={!isValid || isSubmitting || isSavingDraft}
                            className="flex items-center gap-2 px-5 py-2 bg-purple-600 hover:bg-purple-500 text-white rounded-lg text-sm font-medium disabled:opacity-50 transition-all shadow-md active:scale-95"
                        >
                            {isSubmitting ? <Loader2 size={14} className="animate-spin" /> : <Check size={14} />}
                            {isEditMode ? 'Re-Submit' : 'Submit'}
                        </button>
                    </div>
                </div>
            </div>

            {/* Main Content - Liquidation Style Layout */}
            <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6 space-y-4">
                {/* Status Message */}
                {statusMessage && (
                    <div className={`p-4 rounded-lg ${statusMessage.type === 'success'
                        ? 'bg-emerald-500/20 border border-emerald-500/40 text-emerald-300'
                        : 'bg-red-500/20 border border-red-500/40 text-red-300'}`}>
                        {statusMessage.text}
                    </div>
                )}

                {/* Section 1: BURF Summary Card */}
                <div className="bg-white dark:bg-slate-800/50 rounded-xl border border-slate-200 dark:border-slate-700 p-5 shadow-sm dark:shadow-none">
                    <div className="flex items-center gap-2 mb-4">
                        <ShoppingCart size={18} className="text-purple-600 dark:text-purple-400" />
                        <h3 className="text-sm font-semibold text-slate-700 dark:text-slate-300 uppercase tracking-wider">BURF Summary</h3>
                    </div>
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-5">
                        <div>
                            <span className="text-xs text-slate-500 dark:text-slate-500 uppercase">Business Unit</span>
                            <p className="text-slate-800 dark:text-white font-semibold mt-1">{businessName}</p>
                        </div>
                        <div>
                            <span className="text-xs text-slate-500 dark:text-slate-500 uppercase">Description</span>
                            <input
                                type="text"
                                value={description}
                                onChange={(e) => { setDescription(e.target.value); markDirty(); }}
                                placeholder="e.g. Monthly Office Supplies"
                                className="w-full mt-1 px-3 py-2 bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-600 rounded-lg text-slate-800 dark:text-white text-sm placeholder-slate-400 dark:placeholder-slate-500 focus:border-purple-500 focus:outline-none focus:ring-1 focus:ring-purple-500 transition-colors"
                            />
                        </div>
                        <div>
                            <span className="text-xs text-slate-500 dark:text-slate-500 uppercase">Purchase Type</span>
                            <div className="flex gap-2 mt-1">
                                <button
                                    type="button"
                                    onClick={() => { setPurchaseType('EVENT'); markDirty(); }}
                                    className={`flex-1 px-3 py-2 text-xs font-medium rounded-lg border transition-all ${purchaseType === 'EVENT'
                                        ? 'bg-purple-600 border-purple-500 text-white'
                                        : 'bg-white dark:bg-slate-800 border-slate-300 dark:border-slate-600 text-slate-600 dark:text-slate-400 hover:border-purple-500 hover:text-purple-600 dark:hover:text-purple-400'
                                        }`}
                                >
                                    Event
                                </button>
                                <button
                                    type="button"
                                    onClick={() => { setPurchaseType('PAR_STOCKING'); markDirty(); }}
                                    className={`flex-1 px-3 py-2 text-xs font-medium rounded-lg border transition-all ${purchaseType === 'PAR_STOCKING'
                                        ? 'bg-cyan-600 border-cyan-500 text-white'
                                        : 'bg-white dark:bg-slate-800 border-slate-300 dark:border-slate-600 text-slate-600 dark:text-slate-400 hover:border-cyan-500 hover:text-cyan-600 dark:hover:text-cyan-400'
                                        }`}
                                >
                                    Par Stock
                                </button>
                            </div>
                        </div>
                        <div>
                            <span className="text-xs text-slate-500 dark:text-slate-500 uppercase">Date Needed</span>
                            <input
                                type="date"
                                value={dateNeeded}
                                onChange={(e) => { setDateNeeded(e.target.value); markDirty(); }}
                                className={`w-full mt-1 px-3 py-2 bg-slate-50 dark:bg-slate-900/50 border rounded-lg text-slate-800 dark:text-white text-sm focus:outline-none transition-colors ${isUrgent ? 'border-orange-500 focus:border-orange-400' : 'border-slate-200 dark:border-slate-600 focus:border-purple-500'}`}
                            />
                            {isUrgent && (
                                <p className="text-orange-500 dark:text-orange-400 text-xs mt-1 flex items-center gap-1 font-medium">
                                    <AlertTriangle size={10} /> URGENT
                                </p>
                            )}
                        </div>
                    </div>
                </div>

                {/* Section 2: Items Table */}
                <div className="bg-white dark:bg-slate-800/50 rounded-xl border border-slate-200 dark:border-slate-700 p-5 shadow-sm dark:shadow-none">
                    <div className="flex items-center justify-between mb-4">
                        <div className="flex items-center gap-2">
                            <Package size={18} className="text-purple-600 dark:text-purple-400" />
                            <h3 className="text-sm font-semibold text-slate-700 dark:text-slate-300 uppercase tracking-wider">Items Required</h3>
                        </div>
                        <span className="text-sm text-slate-500 dark:text-slate-400">{items.length} item(s)</span>
                    </div>

                    {/* Desktop: Full-width Table */}
                    <div className="hidden lg:block overflow-x-auto">
                        <table className="w-full text-sm">
                            <thead>
                                <tr className="border-b border-slate-200 dark:border-slate-600">
                                    <th className="text-left py-3 px-3 text-slate-500 dark:text-slate-400 font-medium">ITEM NAME</th>
                                    <th className="text-center py-3 px-3 text-slate-500 dark:text-slate-400 font-medium w-20">QTY</th>
                                    <th className="text-center py-3 px-3 text-slate-500 dark:text-slate-400 font-medium w-24">UOM</th>
                                    <th className="text-left py-3 px-3 text-slate-500 dark:text-slate-400 font-medium">REMARKS</th>
                                    <th className="w-24"></th>
                                </tr>
                            </thead>
                            <tbody>
                                {items.map((item, idx) => {
                                    const isEditing = editingItems.has(item.itemId);
                                    return (
                                        <tr key={item.itemId} className="border-b border-slate-100 dark:border-slate-700/50 hover:bg-slate-50 dark:hover:bg-slate-700/30 transition-colors">
                                            <td className="py-3 px-3">
                                                {isEditing ? (
                                                    <input
                                                        type="text"
                                                        value={item.name}
                                                        onChange={(e) => handleUpdateItem(idx, 'name', e.target.value)}
                                                        className="w-full px-3 py-1.5 bg-white dark:bg-slate-900/50 border border-slate-300 dark:border-slate-600 rounded-lg text-slate-900 dark:text-white text-sm focus:border-purple-500 focus:outline-none"
                                                    />
                                                ) : (
                                                    <span className="text-slate-700 dark:text-white text-sm">{item.name}</span>
                                                )}
                                            </td>
                                            <td className="py-3 px-3 text-center">
                                                {isEditing ? (
                                                    <input
                                                        type="number"
                                                        value={item.quantity}
                                                        onChange={(e) => handleUpdateItem(idx, 'quantity', parseFloat(e.target.value) || 1)}
                                                        min="1"
                                                        className="w-full px-3 py-1.5 bg-white dark:bg-slate-900/50 border border-slate-300 dark:border-slate-600 rounded-lg text-slate-900 dark:text-white text-sm text-center focus:border-purple-500 focus:outline-none"
                                                    />
                                                ) : (
                                                    <span className="text-slate-700 dark:text-white text-sm">{item.quantity}</span>
                                                )}
                                            </td>
                                            <td className="py-3 px-3 text-center">
                                                {isEditing ? (
                                                    <select
                                                        value={item.uom}
                                                        onChange={(e) => handleUpdateItem(idx, 'uom', e.target.value)}
                                                        className="w-full px-3 py-1.5 bg-white dark:bg-slate-900/50 border border-slate-300 dark:border-slate-600 rounded-lg text-slate-900 dark:text-white text-sm focus:border-purple-500 focus:outline-none"
                                                    >
                                                        {uomOptions.map(u => <option key={u} value={u}>{u}</option>)}
                                                    </select>
                                                ) : (
                                                    <span className="text-slate-700 dark:text-white text-sm">{item.uom}</span>
                                                )}
                                            </td>
                                            <td className="py-3 px-3">
                                                {isEditing ? (
                                                    <input
                                                        type="text"
                                                        value={item.remarks || ''}
                                                        onChange={(e) => handleUpdateItem(idx, 'remarks', e.target.value)}
                                                        placeholder="Notes..."
                                                        className="w-full px-3 py-1.5 bg-white dark:bg-slate-900/50 border border-slate-300 dark:border-slate-600 rounded-lg text-slate-900 dark:text-white text-sm focus:border-purple-500 focus:outline-none"
                                                    />
                                                ) : (
                                                    <span className="text-slate-500 dark:text-slate-400 text-sm">{item.remarks || '-'}</span>
                                                )}
                                            </td>
                                            <td className="py-3 px-3">
                                                <div className="flex items-center justify-center gap-2">
                                                    <button
                                                        onClick={() => {
                                                            const newSet = new Set(editingItems);
                                                            if (isEditing) {
                                                                newSet.delete(item.itemId);
                                                            } else {
                                                                newSet.add(item.itemId);
                                                            }
                                                            setEditingItems(newSet);
                                                        }}
                                                        className={`p-1.5 rounded-lg transition-all ${isEditing ? 'text-emerald-600 dark:text-emerald-400 bg-emerald-100 dark:bg-emerald-500/20 hover:bg-emerald-200 dark:hover:bg-emerald-500/30' : 'text-slate-400 hover:text-purple-600 dark:hover:text-white hover:bg-slate-100 dark:hover:bg-slate-700'}`}
                                                        title={isEditing ? 'Done editing' : 'Edit item'}
                                                    >
                                                        {isEditing ? <Check size={14} /> : <Pencil size={14} />}
                                                    </button>
                                                    <button
                                                        onClick={() => handleRemoveItem(idx)}
                                                        className="p-1.5 text-red-500 dark:text-red-400 hover:text-red-700 dark:hover:text-red-300 hover:bg-red-50 dark:hover:bg-red-500/20 rounded-lg transition-all"
                                                        title="Remove item"
                                                    >
                                                        <Trash2 size={14} />
                                                    </button>
                                                </div>
                                            </td>
                                        </tr>
                                    );
                                })}
                            </tbody>
                        </table>
                    </div>

                    {/* Mobile: Card View */}
                    <div className="lg:hidden space-y-3">
                        {items.map((item, idx) => (
                            <ItemCard
                                key={item.itemId}
                                item={item}
                                index={idx}
                                onUpdate={handleUpdateItem}
                                onRemove={handleRemoveItem}
                                uomOptions={uomOptions}
                            />
                        ))}
                    </div>

                    {items.length === 0 && (
                        <p className="text-slate-500 text-center py-8 text-sm">No items added yet. Add your first item below.</p>
                    )}

                    {/* Add Item Form */}
                    <div className="bg-slate-50 dark:bg-slate-900/50 rounded-xl p-4 border border-slate-200 dark:border-slate-600 mt-4">
                        <div className="grid grid-cols-12 gap-3 items-end">
                            <div className="col-span-12 lg:col-span-4">
                                <label className="text-xs text-slate-500 dark:text-slate-400 mb-1 block">Item Name</label>
                                <input
                                    type="text"
                                    value={tempItem.name || ''}
                                    onChange={(e) => setTempItem({ ...tempItem, name: e.target.value })}
                                    placeholder="Item description"
                                    className="w-full px-3 py-2 bg-white dark:bg-slate-800 border border-slate-300 dark:border-slate-600 rounded-lg text-slate-900 dark:text-white text-sm placeholder-slate-400 dark:placeholder-slate-500 focus:border-purple-500 focus:outline-none focus:ring-1 focus:ring-purple-500"
                                />
                            </div>
                            <div className="col-span-4 lg:col-span-2">
                                <label className="text-xs text-slate-500 dark:text-slate-400 mb-1 block">Qty</label>
                                <input
                                    type="number"
                                    value={tempItem.quantity || ''}
                                    onChange={(e) => setTempItem({ ...tempItem, quantity: parseFloat(e.target.value) })}
                                    min="1"
                                    className="w-full px-3 py-2 bg-white dark:bg-slate-800 border border-slate-300 dark:border-slate-600 rounded-lg text-slate-900 dark:text-white text-sm focus:border-purple-500 focus:outline-none focus:ring-1 focus:ring-purple-500"
                                />
                            </div>
                            <div className="col-span-4 lg:col-span-2">
                                <label className="text-xs text-slate-500 dark:text-slate-400 mb-1 block">UOM</label>
                                <select
                                    value={tempItem.uom || 'pcs'}
                                    onChange={(e) => setTempItem({ ...tempItem, uom: e.target.value })}
                                    className="w-full px-3 py-2 bg-white dark:bg-slate-800 border border-slate-300 dark:border-slate-600 rounded-lg text-slate-900 dark:text-white text-sm focus:border-purple-500 focus:outline-none focus:ring-1 focus:ring-purple-500"
                                >
                                    {uomOptions.map(u => <option key={u} value={u}>{u}</option>)}
                                </select>
                            </div>
                            <div className="col-span-12 lg:col-span-3">
                                <label className="text-xs text-slate-500 dark:text-slate-400 mb-1 block">Remarks</label>
                                <input
                                    type="text"
                                    value={tempItem.remarks || ''}
                                    onChange={(e) => setTempItem({ ...tempItem, remarks: e.target.value })}
                                    placeholder="Item notes..."
                                    className="w-full px-3 py-2 bg-white dark:bg-slate-800 border border-slate-300 dark:border-slate-600 rounded-lg text-slate-900 dark:text-white text-sm placeholder-slate-400 dark:placeholder-slate-500 focus:border-purple-500 focus:outline-none focus:ring-1 focus:ring-purple-500"
                                />
                            </div>
                            <div className="col-span-12 lg:col-span-1">
                                <button
                                    onClick={handleAddItem}
                                    disabled={!tempItem.name}
                                    className="w-full py-2 px-4 bg-purple-600 hover:bg-purple-500 text-white rounded-lg disabled:opacity-50 flex items-center justify-center gap-2 text-sm font-medium transition-all"
                                >
                                    <Plus size={16} />
                                </button>
                            </div>
                        </div>
                    </div>
                </div>

                {/* Section 3: Two-Column Footer - Summary & Attachments */}
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
                    {/* Left: Validation Summary */}
                    <div className="bg-white dark:bg-slate-800/50 rounded-xl border border-slate-200 dark:border-slate-700 p-5 shadow-sm dark:shadow-none">
                        <h4 className="font-semibold text-slate-800 dark:text-slate-300 mb-4">Validation Summary</h4>
                        <div className="space-y-3 text-sm">
