/**
 * Migration Script: Seed Business Roles into Firestore
 * 
 * This script migrates the old hardcoded roles (MANAGER, EMPLOYEE, CIC, etc.)
 * into the Firestore `config/permissions` document so they become dynamic business roles.
 * 
 * Run this once via the browser console or as a one-time initialization.
 */

import { doc, getDoc, setDoc } from 'firebase/firestore';
import { db } from '../config/firebase';
import { ROLES_TO_PERMISSIONS } from '../config/permissions';

// These are the business roles that should be seeded into Firestore
// SUPER_ADMIN and ADMIN are system roles and remain hardcoded
const BUSINESS_ROLES_TO_SEED = [
    'MANAGER',
    'EMPLOYEE',
    'CIC',
    'PURCHASING_OFFICER',
    'FINANCE',
    'AUDITOR',
    'GENERAL_MANAGER',
    'BOARD_OF_DIRECTOR'
] as const;

/**
 * Seeds the default business roles and their permissions into Firestore.
 * This ensures the `config/permissions` document contains all necessary roles
 * for the permission matrix to function correctly.
 * 
 * @param overwrite - If true, completely overwrites existing roles with defaults. If false (default), safely merges missing default permissions.
 */
export const seedBusinessRoles = async (overwrite: boolean = false): Promise<void> => {
    try {
        const docRef = doc(db, 'config', 'permissions');
        const docSnap = await getDoc(docRef);

        let existingRoles: string[] = [];
        let existingPermissions: Record<string, string[]> = {};

        if (docSnap.exists()) {
            const data = docSnap.data();
            existingRoles = data.roles || [];
            existingPermissions = data.roles_permissions || data.permissions || {};
        }

        // Merge roles: keep existing + add missing business roles
        const allRoles = new Set([...existingRoles, ...BUSINESS_ROLES_TO_SEED]);

        // Build permissions map: use existing or fall back to defaults from config
        const mergedPermissions: Record<string, string[]> = { ...existingPermissions };

        for (const role of BUSINESS_ROLES_TO_SEED) {
            const defaultPerms = ROLES_TO_PERMISSIONS[role as keyof typeof ROLES_TO_PERMISSIONS];
            if (defaultPerms) {
                if (!mergedPermissions[role] || overwrite) {
                    // Use the default permissions from the hardcoded config or overwrite
                    mergedPermissions[role] = [...defaultPerms];
                } else {
                    // Safely merge missing default permissions into existing role
                    const existingSet = new Set(mergedPermissions[role]);
                    for (const perm of defaultPerms) {
                        existingSet.add(perm);
                    }
                    mergedPermissions[role] = Array.from(existingSet);
                }
            }
        }

        // Also ensure SUPER_ADMIN and ADMIN have their permissions
        const systemRoles = ['SUPER_ADMIN', 'ADMIN'];
        for (const role of systemRoles) {
            const defaultPerms = ROLES_TO_PERMISSIONS[role as keyof typeof ROLES_TO_PERMISSIONS];
            if (defaultPerms) {
                if (!mergedPermissions[role] || overwrite) {
                    mergedPermissions[role] = [...defaultPerms];
                } else {
                    const existingSet = new Set(mergedPermissions[role]);
                    for (const perm of defaultPerms) {
                        existingSet.add(perm);
                    }
                    mergedPermissions[role] = Array.from(existingSet);
                }
            }
        }

        // Save to Firestore
        await setDoc(docRef, {
            roles: Array.from(allRoles),
            permissions: mergedPermissions
        }, { merge: true });

        console.log('✅ Business roles seeded successfully!');
        console.log('Roles:', Array.from(allRoles));

    } catch (error) {
        console.error('❌ Error seeding business roles:', error);
        throw error;
    }
};

/**
 * Utility function to run the migration from browser console.
 * Usage: Import this file and call `window.seedBusinessRoles()` in console.
 */
if (typeof window !== 'undefined') {
    (window as any).seedBusinessRoles = seedBusinessRoles;
}

export default seedBusinessRoles;

import React, { useState, useEffect } from 'react';
import { Calendar, X } from 'lucide-react';

interface DateRangeFilterProps {
    onFilterChange: (startDate: string | null, endDate: string | null) => void;
    className?: string;
}

export const DateRangeFilter: React.FC<DateRangeFilterProps> = ({ onFilterChange, className = '' }) => {
    const [startDate, setStartDate] = useState('');
    const [endDate, setEndDate] = useState('');
    const [isExpanded, setIsExpanded] = useState(false);

    useEffect(() => {
        // Debounce notify parent
        const timer = setTimeout(() => {
            onFilterChange(startDate || null, endDate || null);
        }, 300);
        return () => clearTimeout(timer);
    }, [startDate, endDate]);

    const handleQuickSelect = (type: 'today' | 'this_month' | 'last_month' | 'this_year') => {
        const now = new Date();
        let start = new Date();
        let end = new Date();

        switch (type) {
            case 'today':
                start = now;
                end = now;
                break;
            case 'this_month':
                start = new Date(now.getFullYear(), now.getMonth(), 1);
                end = new Date(now.getFullYear(), now.getMonth() + 1, 0);
                break;
            case 'last_month':
                start = new Date(now.getFullYear(), now.getMonth() - 1, 1);
                end = new Date(now.getFullYear(), now.getMonth(), 0);
                break;
            case 'this_year':
                start = new Date(now.getFullYear(), 0, 1);
                end = new Date(now.getFullYear(), 11, 31);
                break;
        }

        setStartDate(start.toISOString().split('T')[0]);
        setEndDate(end.toISOString().split('T')[0]);
    };

    const clearFilter = () => {
        setStartDate('');
        setEndDate('');
        onFilterChange(null, null);
    };

    const hasFilter = startDate || endDate;

    return (
        <div className={`relative ${className}`}>
            <div className="flex items-center gap-2">
                <button
                    onClick={() => setIsExpanded(!isExpanded)}
                    className={`flex items-center gap-2 px-3 py-2 rounded-lg border text-sm transition-colors ${hasFilter
                        ? 'bg-cyan-50 dark:bg-cyan-900/30 border-cyan-200 dark:border-cyan-500/50 text-cyan-700 dark:text-cyan-400'
                        : 'bg-white dark:bg-slate-800 border-slate-300 dark:border-slate-700 text-slate-600 dark:text-slate-400 hover:text-slate-900 dark:hover:text-slate-300'
                        }`}
                >
                    <Calendar size={16} />
                    <span>
                        {hasFilter ? `${startDate} - ${endDate}` : 'Filter by Date'}
                    </span>
                    {hasFilter && (
                        <div
                            onClick={(e) => {
                                e.stopPropagation();
                                clearFilter();
                            }}
                            className="ml-1 p-0.5 hover:bg-cyan-100 dark:hover:bg-slate-700 rounded-full"
                        >
                            <X size={14} />
                        </div>
                    )}
                </button>
            </div>

            {isExpanded && (
                <>
                    <div
                        className="fixed inset-0 z-40"
                        onClick={() => setIsExpanded(false)}
                    ></div>
                    <div className="absolute top-full left-0 mt-2 z-50 w-72 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg shadow-xl p-4">
                        <div className="space-y-4">
                            <div className="space-y-2">
                                <label className="text-xs text-slate-500 dark:text-slate-400 font-medium uppercase">Date Range</label>
                                <div className="grid grid-cols-2 gap-2">
                                    <input
                                        type="date"
                                        value={startDate}
                                        onChange={(e) => setStartDate(e.target.value)}
                                        className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-700 rounded px-2 py-1.5 text-sm text-slate-900 dark:text-white focus:ring-1 focus:ring-cyan-500 outline-none"
                                        placeholder="Start"
                                    />
                                    <input
                                        type="date"
                                        value={endDate}
                                        onChange={(e) => setEndDate(e.target.value)}
                                        className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-700 rounded px-2 py-1.5 text-sm text-slate-900 dark:text-white focus:ring-1 focus:ring-cyan-500 outline-none"
                                        placeholder="End"
                                    />
                                </div>
                            </div>

                            <div className="space-y-2">
                                <label className="text-xs text-slate-500 dark:text-slate-400 font-medium uppercase">Quick Select</label>
                                <div className="grid grid-cols-2 gap-2">
                                    <button
                                        onClick={() => handleQuickSelect('today')}
                                        className="px-2 py-1.5 text-xs bg-slate-100 dark:bg-slate-700 hover:bg-slate-200 dark:hover:bg-slate-600 rounded text-slate-600 dark:text-slate-300 transition-colors"
                                    >
                                        Today
                                    </button>
                                    <button
                                        onClick={() => handleQuickSelect('this_month')}
                                        className="px-2 py-1.5 text-xs bg-slate-100 dark:bg-slate-700 hover:bg-slate-200 dark:hover:bg-slate-600 rounded text-slate-600 dark:text-slate-300 transition-colors"
                                    >
                                        This Month
                                    </button>
                                    <button
                                        onClick={() => handleQuickSelect('last_month')}
                                        className="px-2 py-1.5 text-xs bg-slate-100 dark:bg-slate-700 hover:bg-slate-200 dark:hover:bg-slate-600 rounded text-slate-600 dark:text-slate-300 transition-colors"
                                    >
                                        Last Month
                                    </button>
                                    <button
                                        onClick={() => handleQuickSelect('this_year')}
                                        className="px-2 py-1.5 text-xs bg-slate-100 dark:bg-slate-700 hover:bg-slate-200 dark:hover:bg-slate-600 rounded text-slate-600 dark:text-slate-300 transition-colors"
                                    >
                                        This Year
                                    </button>
                                </div>
                            </div>
                        </div>
                    </div>
                </>
            )}
        </div>
    );
};

import React from 'react';

/**
 * Feature Flag Component
 * FIX M4 & M5: Replaces "Not Implemented" alerts with proper feature gating
 * 
 * Usage:
 * <FeatureFlag feature="notifications" fallback={<ComingSoonBadge />}>
 *   <NotificationsPanel />
 * </FeatureFlag>
 */

interface FeatureFlagProps {
    /** Feature key to check */
    feature: string;
    /** Content to render when feature is enabled */
    children: React.ReactNode;
    /** Content to render when feature is disabled (defaults to null) */
    fallback?: React.ReactNode;
    /** If true, shows "Coming Soon" badge when disabled */
    showComingSoon?: boolean;
}

/**
 * Feature flags configuration
 * Set to true to enable a feature
 */
const FEATURE_FLAGS: Record<string, boolean> = {
    // Core features - enabled
    requisitions: true,
    users: true,
    businesses: true,
    suppliers: true,
    permissions: true,

    // Features in development - disabled
    notifications: true,
    emailIntegration: false,
    advancedReports: false,
    bulkImport: false,
    apiIntegration: false,
    auditLogs: false,
};

/**
 * Check if a feature is enabled
 */
export const isFeatureEnabled = (feature: string): boolean => {
    // In development, can enable all features via env var
    if (import.meta.env.DEV && import.meta.env.VITE_ENABLE_ALL_FEATURES === 'true') {
        return true;
    }
    return FEATURE_FLAGS[feature] ?? false;
};

/**
 * Coming Soon Badge Component
 */
export const ComingSoonBadge: React.FC<{ label?: string }> = ({ label = 'Coming Soon' }) => (
    <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-amber-100 text-amber-800">
        {label}
    </span>
);

/**
 * Disabled Button with Coming Soon tooltip
 */
export const ComingSoonButton: React.FC<{
    children: React.ReactNode;
    className?: string;
}> = ({ children, className = '' }) => (
    <button
        disabled
        className={`opacity-50 cursor-not-allowed relative group ${className}`}
        title="This feature is coming soon"
    >
        {children}
        <span className="absolute -top-8 left-1/2 -translate-x-1/2 px-2 py-1 bg-slate-800 
                     text-white text-xs rounded opacity-0 group-hover:opacity-100 
                     transition-opacity whitespace-nowrap pointer-events-none">
            Coming Soon
        </span>
    </button>
);

/**
 * Main Feature Flag Component
 */
export const FeatureFlag: React.FC<FeatureFlagProps> = ({
    feature,
    children,
    fallback = null,
    showComingSoon = false,
}) => {
    if (isFeatureEnabled(feature)) {
        return <>{children}</>;
    }

    if (showComingSoon) {
        return <ComingSoonBadge />;
    }

    return <>{fallback}</>;
};

/**
 * Higher-Order Component for feature-gated components
 * 
 * @example
 * const NotificationsPanel = withFeatureFlag('notifications', () => <div>...</div>);
 */
export function withFeatureFlag<P extends object>(
    feature: string,
    Component: React.ComponentType<P>,
    FallbackComponent?: React.ComponentType<P>
): React.FC<P> {
    return (props: P) => {
        if (isFeatureEnabled(feature)) {
            return <Component {...props} />;
        }
        if (FallbackComponent) {
            return <FallbackComponent {...props} />;
        }
        return null;
    };
}

export default FeatureFlag;

