import React, { createContext, useContext, useState, useEffect, type ReactNode } from 'react';
import type { Unsubscribe } from 'firebase/firestore';
import { useAuth } from '../../contexts/useAuth';
import { RequisitionService } from '../../features/procurement/services/requisitions.service';
import { FirestoreService, where } from '../services/firestore.service';
import { NotificationsService } from '../services/notifications.service';
import { COLLECTIONS } from '../types/firebase.types';
import type {
    FirestoreRequisition,
    FirestoreBusiness,
    FirestoreSupplier,
    FirestoreNotification,
    FirestoreUser
} from '../types/firebase.types';
import type { Requisition, Business, NotificationItem, User } from '../types';
import type { Supplier, RequisitionStatus } from '../../features/procurement/types';
import { UserRole } from '../types/firebase.types';
import { getUserVisibleBuIds } from '../utils/tenantFilters';

interface DataContextType {
    // Data
    requisitions: Requisition[];
    businesses: Business[];
    suppliers: Supplier[];
    notifications: NotificationItem[];
    allUsers: User[];

    // Loading states
    loadingRequisitions: boolean;
    loadingBusinesses: boolean;
    loadingSuppliers: boolean;
    loadingNotifications: boolean;

    // Error states
    error: string | null;

    // Requisition operations
    createRequisition: (data: Omit<Requisition, 'id' | 'dateCreated' | 'timestamp'>) => Promise<string>;
    updateRequisition: (id: string, data: Partial<Requisition>) => Promise<void>;
    updateRequisitionStatus: (id: string, status: RequisitionStatus, comment?: string) => Promise<void>;
    deleteRequisition: (id: string) => Promise<void>;

    // Supplier operations
    createSupplier: (data: Omit<Supplier, 'id'>) => Promise<void>;
    updateSupplier: (id: string, data: Partial<Supplier>) => Promise<void>;
    deleteSupplier: (id: string) => Promise<void>;

    // Business operations
    getUsersByBusiness: (businessId: string) => Promise<User[]>;
}

const DataContext = createContext<DataContextType | undefined>(undefined);

export const useData = () => {
    const context = useContext(DataContext);
    if (!context) {
        throw new Error('useData must be used within a DataProvider');
    }
    return context;
};

interface DataProviderProps {
    children: ReactNode;
}

export const DataProvider: React.FC<DataProviderProps> = ({ children }) => {
    const { currentUser } = useAuth();

    const [requisitions, setRequisitions] = useState<Requisition[]>([]);
    const [businesses, setBusinesses] = useState<Business[]>([]);
    const [suppliers, setSuppliers] = useState<Supplier[]>([]);
    const [notifications, setNotifications] = useState<NotificationItem[]>([]);
    const [userNotifications, setUserNotifications] = useState<NotificationItem[]>([]);
    const [allUsers, setAllUsers] = useState<User[]>([]);

    const [loadingRequisitions, setLoadingRequisitions] = useState(true);
    const [loadingBusinesses, setLoadingBusinesses] = useState(true);
    const [loadingSuppliers, setLoadingSuppliers] = useState(true);
    const [loadingNotifications, setLoadingNotifications] = useState(true);

    const [error, setError] = useState<string | null>(null);

    // Convert Firestore data to app format
    const convertRequisition = (firestoreReq: FirestoreRequisition & { id: string }): Requisition => ({
        ...firestoreReq,
        id: firestoreReq.id,
        timestamp: firestoreReq.createdAt && typeof firestoreReq.createdAt.toDate === 'function'
            ? firestoreReq.createdAt.toDate().toISOString()
            : new Date().toISOString(),
    });

    const convertBusiness = (firestoreBiz: FirestoreBusiness & { id: string }): Business => ({
        ...firestoreBiz,
        id: firestoreBiz.id,
    });

    const convertSupplier = (firestoreSup: FirestoreSupplier & { id: string }): Supplier => ({
        ...firestoreSup,
        id: firestoreSup.id,
    });

    const convertNotification = (firestoreNotif: FirestoreNotification & { id: string }): NotificationItem => ({
        ...firestoreNotif,
        id: firestoreNotif.id,
        timestamp: firestoreNotif.createdAt && typeof firestoreNotif.createdAt.toDate === 'function'
            ? firestoreNotif.createdAt.toDate().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
            : new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        createdAt: firestoreNotif.createdAt,
        targetRoles: firestoreNotif.targetRoles as UserRole[],
    });

    const convertUser = (firestoreUser: FirestoreUser & { id: string }): User => ({
        ...firestoreUser,
        id: firestoreUser.id,
        avatar: firestoreUser.avatar || '',
    });

    // Subscribe to requisitions
    useEffect(() => {
        if (!currentUser) {
            setRequisitions(prev => prev.length === 0 ? prev : []);
            setLoadingRequisitions(false);
            return;
        }

        // REMOVED: setLoadingRequisitions(true); - Fix for revert issue

        let unsubscribe: Unsubscribe;

        try {
            const processReqs = (firestoreReqs: (FirestoreRequisition & { id: string })[]) => {
                setRequisitions(firestoreReqs.map(convertRequisition));
                setLoadingRequisitions(false);
            };

            // Pass the additional multi-BU list
            unsubscribe = RequisitionService.subscribeToRequisitions(
                currentUser.role,
                currentUser.businessId,
                currentUser.businessUnitIds || [],
                processReqs as any
            );

        } catch (err: any) {
            setError(err.message);
            setLoadingRequisitions(false);
        }

        return () => {
            if (unsubscribe) unsubscribe();
        };
    }, [currentUser]);

    // Subscribe to businesses — filtered by user's assigned BUs
    useEffect(() => {
        // REMOVED: setLoadingBusinesses(true);

        // Determine which BUs the current user is allowed to see
        const visibleBuIds = getUserVisibleBuIds(currentUser ?? null);

        const handleBizData = (firestoreBizs: (FirestoreBusiness & { id: string })[]) => {
            let filtered = firestoreBizs;
            // visibleBuIds === null means global role → show all
            // visibleBuIds is an array → client-side filter by doc.id
            if (visibleBuIds !== null) {
                filtered = firestoreBizs.filter(b => visibleBuIds.includes(b.id));
            }
            setBusinesses(filtered.map(convertBusiness));
            setLoadingBusinesses(false);
        };

        // We still fetch all businesses and filter client-side because
        // Firestore 'documentId()' in queries are complex. The businesses
        // collection is small (typically < 50 docs), so this is efficient.
        const unsubscribe = FirestoreService.subscribeToCollection<FirestoreBusiness>(
            COLLECTIONS.BUSINESSES,
            handleBizData,
            [],
            (err) => {
                setError(err.message);
                setLoadingBusinesses(false);
            }
        );

        return () => unsubscribe();
    }, [currentUser]);

    // Subscribe to suppliers
    useEffect(() => {
        // REMOVED: setLoadingSuppliers(true);

        const unsubscribe = FirestoreService.subscribeToCollection<FirestoreSupplier>(
            COLLECTIONS.SUPPLIERS,
            (firestoreSups) => {
                setSuppliers(firestoreSups.map(convertSupplier));
                setLoadingSuppliers(false);
            },
            [],
            (err) => {
                setError(err.message);
                setLoadingSuppliers(false);
            }
        );

        return () => unsubscribe();
    }, []);

    // Subscribe to notifications
    useEffect(() => {
        if (!currentUser) {
            setNotifications(prev => prev.length === 0 ? prev : []);
            setLoadingNotifications(false);
            return;
        }

        // REMOVED: setLoadingNotifications(true);

        const handleUserNotifs = (firestoreNotifs: (FirestoreNotification & { id: string })[]) => {
            setUserNotifications(firestoreNotifs.map(convertNotification));
            setLoadingNotifications(false);
        };

        const handleError = (err: Error) => {
            setError(err.message);
            setLoadingNotifications(false);
        };

        // Subscribe to user-specific notifications only (Backend must resolve Roles to UIDs)
        const unsubUser = NotificationsService.subscribeToNotifications(currentUser.id, handleUserNotifs, handleError);

        return () => {
            unsubUser();
        };
    }, [currentUser]);

    // Merge and sort notifications
    useEffect(() => {
        // Just use userNotifications directly since we removed roleNotifications
        const sortedList = [...userNotifications].sort((a, b) => {
            // Sort by createdAt desc safely
            if (a.createdAt && b.createdAt) {
                return b.createdAt.toMillis() - a.createdAt.toMillis();
            }
            return 0;
        });

        setNotifications(sortedList);
    }, [userNotifications]);

    // Load all users
    useEffect(() => {
        const loadUsers = async () => {
            try {
                const firestoreUsers = await FirestoreService.getDocuments<FirestoreUser>(
                    COLLECTIONS.USERS
                );
                setAllUsers(firestoreUsers.map(convertUser));
            } catch (err: any) {
                console.error('Error loading users:', err);
            }
        };

        loadUsers();
    }, []);

    // Requisition operations
    const createRequisition = React.useCallback(async (data: Omit<Requisition, 'id' | 'dateCreated' | 'timestamp'>): Promise<string> => {
        try {
            const id = await RequisitionService.createRequisition(data as any);
            return id;
        } catch (err: any) {
            setError(err.message);
            throw err;
        }
    }, []);

    const updateRequisition = React.useCallback(async (id: string, data: Partial<Requisition>): Promise<void> => {
        try {
            await RequisitionService.updateRequisition(id, data as any);
        } catch (err: any) {
            setError(err.message);
            throw err;
        }
    }, []);

    const updateRequisitionStatus = React.useCallback(async (
        id: string,
        status: RequisitionStatus,
        comment?: string
    ): Promise<void> => {
        try {
            await RequisitionService.updateRequisition(id, { status, remarks: comment });
        } catch (err: any) {
            setError(err.message);
            throw err;
        }
    }, []);

    const deleteRequisition = React.useCallback(async (id: string): Promise<void> => {
        try {
            await RequisitionService.deleteRequisition(id);
        } catch (err: any) {
            setError(err.message);
            throw err;
        }
    }, []);

    // Supplier operations
    const createSupplier = React.useCallback(async (data: Omit<Supplier, 'id'>): Promise<void> => {
        try {
            await FirestoreService.createDocument<FirestoreSupplier>(
                COLLECTIONS.SUPPLIERS,
                data as any
            );
        } catch (err: any) {
            setError(err.message);
            throw err;
        }
    }, []);

    const updateSupplier = React.useCallback(async (id: string, data: Partial<Supplier>): Promise<void> => {
        try {
            await FirestoreService.updateDocument<FirestoreSupplier>(
                COLLECTIONS.SUPPLIERS,
                id,
                data as any
            );
        } catch (err: any) {
            setError(err.message);
            throw err;
        }
    }, []);

    const deleteSupplier = React.useCallback(async (id: string): Promise<void> => {
        try {
            await FirestoreService.deleteDocument(COLLECTIONS.SUPPLIERS, id);
        } catch (err: any) {
            setError(err.message);
            throw err;
        }
    }, []);

    // Business operations
    const getUsersByBusiness = React.useCallback(async (businessId: string): Promise<User[]> => {
        try {
            const firestoreUsers = await FirestoreService.getDocuments<FirestoreUser>(
                COLLECTIONS.USERS,
                [where('businessId', '==', businessId)]
            );
            return firestoreUsers.map(convertUser);
        } catch (err: any) {
            setError(err.message);
            throw err;
        }
    }, []);

    const value: DataContextType = React.useMemo(() => ({
        requisitions,
        businesses,
        suppliers,
        notifications,
        allUsers,
        loadingRequisitions,
        loadingBusinesses,
        loadingSuppliers,
        loadingNotifications,
        error,
        createRequisition,
        updateRequisition,
        updateRequisitionStatus,
        deleteRequisition,
        createSupplier,
        updateSupplier,
        deleteSupplier,
        getUsersByBusiness,
    }), [
        requisitions,
        businesses,
        suppliers,
        notifications,
        allUsers,
        loadingRequisitions,
        loadingBusinesses,
        loadingSuppliers,
        loadingNotifications,
        error,
        createRequisition,
        updateRequisition,
        updateRequisitionStatus,
        deleteRequisition,
        createSupplier,
        updateSupplier,
        deleteSupplier,
        getUsersByBusiness
    ]);

    return <DataContext.Provider value={value}>{children}</DataContext.Provider>;
};

/**
 * useUOM – Returns the system-hardcoded UOM list.
 *
 * UOMs are now a fixed, built-in list and CANNOT be modified by users.
 * The Firestore `uom/units` document is no longer read or written to.
 * The `updateUOMs` function is kept as a no-op for backwards compatibility
 * with any existing call-sites that still reference it.
 */
import { UOM_CODES } from '../constants/uom.constants';

export const useUOM = () => {
    return {
        /** The fixed, system-defined list of UOM code strings. */
        uomOptions: UOM_CODES,

        /**
         * @deprecated UOMs are now hardcoded and cannot be updated.
         * This is a no-op kept for backwards compatibility.
         */
        updateUOMs: async (_units: string[]): Promise<void> => {
            console.warn('[useUOM] updateUOMs is disabled – UOMs are now hardcoded.');
        },

        loading: false,
        error: null as string | null,
    };
};

import { doc, runTransaction, collection, query, where, getDocs } from 'firebase/firestore';
import { db } from '../../config/firebase';

/**
 * Counter types supported by the system
 */
export enum CounterType {
    PRF = 'prf',
    BURF = 'burf',
    LIQUIDATION = 'liquidation',
    PCF = 'pcf',
}

/**
 * Counter document structure in Firestore
 * Updated to match firestore.rules requirements (Issue #6)
 */
interface CounterDocument {
    value: number;
    prefix: string; // Required by firestore.rules
    lastUpdated: string;
}

/**
 * Service for managing auto-incrementing counters in Firestore
 * Uses transactions to ensure atomic increments and prevent race conditions
 */
export class CounterService {
    private static readonly COLLECTION_NAME = 'counters';

    // Prefix mappings for each counter type
    private static readonly PREFIXES: Record<CounterType, string> = {
        [CounterType.PRF]: 'PRF',
        [CounterType.BURF]: 'BURF',
        [CounterType.LIQUIDATION]: 'LIQ',
        [CounterType.PCF]: 'PCF',
    };

    /**
     * Get the next counter value and increment it atomically
     * @param counterType - Type of counter to increment
     * @returns The next counter value
     */
    static async getNextValue(counterType: CounterType): Promise<number> {
        const counterRef = doc(db, this.COLLECTION_NAME, counterType);
        const prefix = this.PREFIXES[counterType];

        try {
            const nextValue = await runTransaction(db, async (transaction) => {
                const counterDoc = await transaction.get(counterRef);

                let currentValue = 0;
                if (counterDoc.exists()) {
                    const data = counterDoc.data() as CounterDocument;
                    currentValue = data.value || 0;
                }

                const nextValue = currentValue + 1;

                // FIX: Use update() for existing docs, set() only for new docs
                // This matches Firestore rules which have separate create/update permissions
                if (counterDoc.exists()) {
                    transaction.update(counterRef, {
                        value: nextValue,
                        lastUpdated: new Date().toISOString(),
                    });
                } else {
                    transaction.set(counterRef, {
                        value: nextValue,
                        prefix: prefix,
                        lastUpdated: new Date().toISOString(),
                    });
                }

                return nextValue;
            });

            return nextValue;
        } catch (error) {
            console.error(`Error incrementing counter ${counterType}:`, error);
            throw new Error(`Failed to generate next ${counterType} ID`);
        }
    }

    /**
     * Get the next ID for any prefix (dynamic counter support)
     * Handles new/unknown prefixes by automatically creating the counter document starting at 1
     * @param prefix - The prefix string (e.g., 'PRF', 'BURF', 'PCF')
     * @returns Formatted ID string (e.g., 'PCF-00001')
     */
    static async getNextId(prefix: string): Promise<string> {
        // Normalize prefix to lowercase for document ID
        const counterDocId = prefix.toLowerCase();
        const counterRef = doc(db, this.COLLECTION_NAME, counterDocId);

        try {
            const nextValue = await runTransaction(db, async (transaction) => {
                const counterDoc = await transaction.get(counterRef);

                let currentValue = 0;
                if (counterDoc.exists()) {
                    const data = counterDoc.data() as CounterDocument;
                    currentValue = data.value || 0;
                }

                const nextVal = currentValue + 1;

                // Use update() for existing docs, set() for new docs (auto-initialize at 1)
                if (counterDoc.exists()) {
                    transaction.update(counterRef, {
                        value: nextVal,
                        lastUpdated: new Date().toISOString(),
                    });
                } else {
                    // Auto-create new counter document starting at 1
                    transaction.set(counterRef, {
                        value: nextVal,
                        prefix: prefix.toUpperCase(),
                        lastUpdated: new Date().toISOString(),
                    });
                }

                return nextVal;
            });

            // Format: PREFIX-00001 (5-digit padding for larger sequences)
            return `${prefix.toUpperCase()}-${nextValue.toString().padStart(5, '0')}`;
        } catch (error) {
            console.error(`Error generating next ID for ${prefix}:`, error);
            throw new Error(`Failed to generate next ${prefix} ID`);
        }
    }

    /**
     * Generate a formatted PRF ID (e.g., "PRF-0001")
     * @returns Formatted PRF ID string
     */
    static async generatePRFId(): Promise<string> {
        const nextValue = await this.getNextValue(CounterType.PRF);
        return this.formatPRFId(nextValue);
    }

    /**
     * Generate a formatted BURF ID (e.g., "BURF-0001")
     * @returns Formatted BURF ID string
     */
    static async generateBURFId(): Promise<string> {
        const nextValue = await this.getNextValue(CounterType.BURF);
        return this.formatBURFId(nextValue);
    }

    /**
     * Generate a formatted Liquidation ID (e.g., "LIQ-0001")
     * @returns Formatted Liquidation ID string
     */
    static async generateLiquidationId(): Promise<string> {
        const nextValue = await this.getNextValue(CounterType.LIQUIDATION);
        return this.formatLiquidationId(nextValue);
    }

    /**
     * Generate a batch-specific PRF ID for BURF-to-PRF conversions
     * Queries existing PRFs linked to this BURF and generates the next batch number
     * @param parentBurfId - The original BURF ID (e.g., "BURF-0033")
     * @returns Formatted batch ID (e.g., "BURF-0033-B1", "BURF-0033-B2")
     */
    static async generateBatchPrfId(parentBurfId: string): Promise<string> {
        try {
            // Query for existing PRFs that were created from this BURF
            // They will have prfDetails.requisitionId = parentBurfId OR id starts with parentBurfId-B
            const requisitionsRef = collection(db, 'requisitions');

            // Count existing batches by looking for IDs that start with parentBurfId-B
            const batchQuery = query(
                requisitionsRef,
                where('prfDetails.requisitionId', '==', parentBurfId)
            );

            const snapshot = await getDocs(batchQuery);
            const batchCount = snapshot.size;

            // Generate next batch number (B1, B2, B3, etc.)
            const nextBatchNumber = batchCount + 1;
            return `${parentBurfId}-B${nextBatchNumber}`;
        } catch (error) {
            console.error(`Error generating batch PRF ID for ${parentBurfId}:`, error);
            // Fallback: use timestamp-based suffix to avoid collisions
            const fallbackSuffix = Date.now().toString().slice(-4);
            return `${parentBurfId}-B${fallbackSuffix}`;
        }
    }

    /**
     * Format a number as a PRF ID
     * @param value - Counter value
     * @returns Formatted PRF ID (e.g., "PRF-0001")
     */
    private static formatPRFId(value: number): string {
        return `PRF-${value.toString().padStart(4, '0')}`;
    }

    /**
     * Format a number as a BURF ID
     * @param value - Counter value
     * @returns Formatted BURF ID (e.g., "BURF-0001")
     */
    private static formatBURFId(value: number): string {
        return `BURF-${value.toString().padStart(4, '0')}`;
    }

    /**
     * Format a number as a Liquidation ID
     * @param value - Counter value
     * @returns Formatted Liquidation ID (e.g., "LIQ-0001")
     */
    private static formatLiquidationId(value: number): string {
        return `LIQ-${value.toString().padStart(4, '0')}`;
    }

    /**
     * Get the current counter value without incrementing
     * @param counterType - Type of counter to check
     * @returns Current counter value, or 0 if not initialized
     */
    static async getCurrentValue(counterType: CounterType): Promise<number> {
        const counterRef = doc(db, this.COLLECTION_NAME, counterType);

        try {
            const counterDoc = await runTransaction(db, async (transaction) => {
                const doc = await transaction.get(counterRef);
                if (doc.exists()) {
                    const data = doc.data() as CounterDocument;
                    return data.value || 0;
                }
                return 0;
            });

            return counterDoc;
        } catch (error) {
            console.error(`Error reading counter ${counterType}:`, error);
            return 0;
        }
    }

    /**
     * Reset a counter to a specific value
     * @deprecated SECURITY FIX C3: This function is COMPLETELY DISABLED to prevent ID collisions.
     * Counter resets should ONLY be performed via Firebase Admin SDK by authorized personnel.
     * 
     * Rationale: Even in development, resetting counters can cause ID reuse which may
     * propagate to production through data exports/imports or shared staging environments.
     * 
     * @param _counterType - Type of counter to reset (unused - function disabled)
     * @param _value - New counter value (unused - function disabled)
     * @throws Always throws an error directing to Firebase Admin SDK
     */
    static async resetCounter(_counterType: CounterType, _value: number = 0): Promise<void> {
        // FIX C3: COMPLETELY DISABLED - was only checking PROD environment
        // Risk: Development data with reused IDs could leak to production
        // Solution: Always throw, directing users to proper admin procedures
        throw new Error(
            'Counter reset is permanently disabled in client code to prevent ID collisions. ' +
            'Use Firebase Admin SDK with proper authorization for counter management.'
        );
    }

}

